      // BAB 7: RUANG KANTOR & KEBUTUHAN SEHARI-HARI
      // ==========================================
      { id: 'n_r86', ch: 7, q: "가: 여기가 사무실입니까?\n나: __________________.", a: ["네, 사무실입니다", "아니요, 학생입니다", "네, 식당입니다", "저기입니다"], c: "네, 사무실입니다", ex: "Pertanyaannya adalah 'Apakah di sini ruang kantor?'. Jawaban yang paling logis dan mengiyakan adalah 'Ya, ini kantor' (네, 사무실입니다).", romaji: "" },
      { id: 'n_r87', ch: 7, q: "가: 화장실이 어디입니까?\n나: __________________.", a: ["화장실입니다", "저기입니다", "기숙사입니다", "여기입니다"], c: "저기입니다", ex: "Orang pertama bertanya 'Toiletnya di mana?'. Jawaban yang logis untuk menunjukkan arah/lokasi adalah 'Di sana' (저기입니다).", romaji: "" },
      { id: 'n_r88', ch: 7, q: "가: 이게 뭐예요?\n나: __________________.", a: ["열쇠예요", "사무실이에요", "시장이에요", "기숙사예요"], c: "열쇠예요", ex: "Pertanyaannya adalah 'Ini apa?' (menggunakan 이게 yang merujuk pada benda/barang). Jawaban yang tepat haruslah nama benda, yaitu 'Ini kunci' (열쇠예요).", romaji: "" },
      { id: 'n_r89', ch: 7, q: "가: 여기가 기숙사예요. 이건 기숙사 열쇠예요.\n나: __________________.", a: ["처음 뵙겠습니다", "아니요, 기숙사예요", "감사합니다", "저기입니다"], c: "감사합니다", ex: "Orang pertama memperkenalkan asrama dan memberikan kunci asrama. Respons alami ketika menerima sesuatu adalah mengucapkan 'Terima kasih' (감사합니다).", romaji: "" },
      { id: 'n_r90', ch: 7, q: "가: 저게 뭐예요?\n나: 가족사진이에요.\n질문: 나에게 무엇이 있습니까?", a: ["여권", "거울", "가족사진", "지갑"], c: "가족사진", ex: "Dialog menunjukkan orang pertama bertanya 'Itu apa?' dan orang kedua menjawab 'Foto keluarga' (가족사진).", romaji: "" },
      { id: 'n_r91', ch: 7, q: "식당______ 어디입니까?", a: ["이", "가", "은", "는"], c: "이", ex: "Kata '식당' (rumah makan) diakhiri dengan huruf konsonan (ㅇ). Oleh karena itu, partikel subjek yang tepat untuk mengikutinya adalah '이'.", romaji: "" },
      { id: 'n_r92', ch: 7, q: "기숙사______ 어디입니까?", a: ["이", "가", "을", "를"], c: "가", ex: "Kata '기숙사' (asrama) diakhiri dengan huruf vokal (ㅏ). Oleh karena itu, partikel penanda subjek yang tepat adalah '가'.", romaji: "" },
      { id: 'n_r93', ch: 7, q: "여기가 어디______?", a: ["에요", "이에요", "예요", "입니까"], c: "예요", ex: "Kalimat non-formal ini bertanya 'Di sini di mana?'. Kata '어디' berakhiran huruf vokal (ㅣ), sehingga akhiran predikat non-formal yang tepat adalah '예요'.", romaji: "" },
      { id: 'n_r94', ch: 7, q: "가방______?", a: ["예요", "이에요", "입니까", "이"], c: "이에요", ex: "Pertanyaannya berarti 'Apakah (ini) tas?'. Kata benda '가방' berakhiran huruf konsonan (ㅇ), maka akhiran kalimat non-formal yang melekat padanya adalah '이에요'.", romaji: "" },
      { id: 'n_r95', ch: 7, q: "저게 ______예요?", a: ["왜", "뭐", "장소", "나라"], c: "뭐", ex: "Kalimat ini bertujuan untuk bertanya 'Itu apa?'. Kata tanya singkat untuk benda dalam bahasa lisan Korea adalah '뭐' (singkatan dari 무엇).", romaji: "" },
      { id: 'n_r96', ch: 7, q: "가: 화장실이 어디입니까?\n나: ______입니다.", a: ["어느", "누구", "뭐", "저기"], c: "저기", ex: "Penanya bertanya letak toilet. Jawaban yang dibutuhkan harus menunjukkan keterangan tempat, yaitu '저기' (di sana).", romaji: "" },
      { id: 'n_r97', ch: 7, q: "______이/가 어디입니까?\n나: 기숙사입니다.", a: ["누구", "뭐", "여기", "이름"], c: "여기", ex: "Jawaban menyatakan '(Di sini) adalah asrama'. Maka pertanyaan yang logis menanyakan lokasi tempat si penanya berada, yaitu 'Di sini (여기가) di mana?'.", romaji: "" },
      { id: 'n_r98', ch: 7, q: "이건 제 ______입니다.", a: ["식당", "편의점", "여권", "회사"], c: "여권", ex: "Kata tunjuk '이건' (ini) merujuk pada sebuah barang/benda, bukan tempat. Di antara pilihan jawaban, hanya '여권' (paspor) yang merupakan benda.", romaji: "" },
      { id: 'n_r99', ch: 7, q: "가: 이게 뭐예요?\n나: 화장품______.", a: ["이", "이에요", "예요", "가"], c: "이에요", ex: "Kata benda '화장품' (kosmetik) berakhiran konsonan (ㅁ). Oleh karena itu, akhiran kalimat predikat non-formal yang harus dipakai adalah '이에요'.", romaji: "" },
      { id: 'n_r100', ch: 7, q: "가: 베개예요?\n나: 아니요, ______예요.", a: ["이불", "가방", "열쇠", "여권"], c: "열쇠", ex: "Benda yang benar harus berakhiran huruf vokal karena menggunakan akhiran '예요'. Di antara pilihan yang ada, hanya '열쇠' yang berakhiran vokal.", romaji: "" },

      // ==========================================
      // BAB 8: RUTINITAS HARIAN & WAKTU
      // ==========================================
      { id: 'n_r101', ch: 8, q: "가: 투안 씨, 지금 뭐 해요?\n나: __________________.", a: ["텔레비전을 봐요", "11시예요", "오후예요", "네, 운동해요"], c: "텔레비전을 봐요", ex: "Orang pertama (A) bertanya 'Tuan, sekarang sedang apa?'. Jawaban yang logis harus menyatakan suatu kegiatan/aktivitas, yaitu 'Menonton TV' (텔레비전을 봐요).", romaji: "" },
      { id: 'n_r102', ch: 8, q: "가: 몇 시에 점심을 먹어요?\n나: __________________.", a: ["커피를 마셔요", "12시 30분에 먹어요", "요리해요", "지금 먹어요"], c: "12시 30분에 먹어요", ex: "Orang pertama bertanya 'Jam berapa makan siang?'. Jawaban yang benar harus mengandung keterangan waktu (jam), yaitu 'Makan pada jam 12.30' (12시 30분에 먹어요).", romaji: "" },
      { id: 'n_r103', ch: 8, q: "투안: 지금 몇 시예요?\n리한: 11시예요.\n질문: 지금 몇 시입니까?", a: ["10시", "11시", "12시", "1시"], c: "11시", ex: "Tuan bertanya 'Sekarang jam berapa?'. Rihan menjawab 'Jam 11' (11시예요). Waktu saat ini adalah jam 11.", romaji: "" },
      { id: 'n_r104', ch: 8, q: "수루: 투안 씨는 뭐 해요?\n투안: 텔레비전을 봐요. 수루 씨는 뭐 해요?\n수루: 저는 지금 요리해요.\n질문: 수루 씨는 지금 무엇을 합니까?", a: ["텔레비전을 봐요", "요리해요", "자요", "회사에 가요"], c: "요리해요", ex: "In dalam dialog, Suru menjawab 'Saya sekarang sedang memasak' (저는 지금 요리해요). Pertanyaannya adalah apa yang sedang dilakukan Suru.", romaji: "" },
      { id: 'n_r105', ch: 8, q: "저는 지금 점심______ 먹어요.", a: ["이", "가", "을", "에"], c: "을", ex: "Kata '점심' (makan siang) adalah objek dari kata kerja makan (먹다). Karena diakhiri dengan huruf konsonan (ㅁ), maka partikel penanda objek yang tepat adalah '을'.", romaji: "" },
      { id: 'n_r106', ch: 8, q: "아침______ 운동해요.", a: ["에", "을", "를", "이"], c: "에", ex: "Kata '아침' (pagi) merupakan keterangan waktu. Partikel penanda waktu dalam bahasa Korea adalah '에'.", romaji: "" },
      { id: 'n_r107', ch: 8, q: "가: 언제 운동해요?\n나: 저녁______ 운동해요.", a: ["은", "가", "에", "를"], c: "에", ex: "Kata '저녁' (malam) adalah keterangan waktu yang menunjukkan kapan aktivitas itu terjadi, sehingga wajib dilekatkan dengan partikel penanda waktu '에'.", romaji: "" },
      { id: 'n_r108', ch: 8, q: "투안 씨는 커피를 ____________.", a: ["마시어요", "마셔요", "먹어요", "해요"], c: "마셔요", ex: "Kata dasar untuk 'minum' adalah 마시다. Kata kerja berakhiran vokal 'ㅣ' akan berubah menjadi '-어요' dan digabungkan menjadi '마셔요' (마시 + 어요 = 마셔요).", romaji: "" },
      { id: 'n_r109', ch: 8, q: "가: 지금 뭐 해요?\n나: 아침을 ____________.", a: ["봐요", "해요", "씻어요", "먹어요"], c: "먹어요", ex: "Pasangan kata kerja yang tepat untuk sarapan adalah 'makan' (먹다). Sesuai aturan tata bahasa, 먹다 + 어요 menjadi '먹어요'.", romaji: "" },
      { id: 'n_r110', ch: 8, q: "가: 지금 뭐 해요?\n나: 전화를 ____________.", a: ["마셔요", "해요", "자요", "일어나요"], c: "해요", ex: "Pasangan kata benda untuk 'telepon' (전화) agar menjadi kata kerja 'menelepon' adalah menggunakan '하다' (전화하다). Dalam bentuk kalimat sopan informal, 하다 berubah menjadi '해요'.", romaji: "" },
      { id: 'n_r111', ch: 8, q: "가: 지금 ____________ 시예요?\n나: 오후 두 시예요.", a: ["언제", "몇", "누구", "왜"], c: "몇", ex: "Penjawab merespons dengan 'Jam dua siang.' Maka orang pertama sedang menanyakan 'Jam berapa sekarang?'. Kata tanya yang tepat adalah '몇' (berapa).", romaji: "" },
      { id: 'n_r112', ch: 8, q: "가: ____________ 운동해요?\n나: 아침에 운동해요.", a: ["어디", "언제", "누구", "무엇"], c: "언제", ex: "Jawaban dari lawan bicara adalah keterangan waktu 'Pada pagi hari.' Kata tanya yang tepat untuk menanyakan waktu ('Kapan') dalam bahasa Korea adalah '언제'.", romaji: "" },
      { id: 'n_r113', ch: 8, q: "가: 몇 시에 자요?\n나: 11시에 ____________.", a: ["가요", "먹어요", "봐요", "자요"], c: "자요", ex: "Jawabannya harus mengulang kata kerja yang sama yaitu tidur (자다). 자다 + 아요 menjadi '자요'.", romaji: "" },
      { id: 'n_r114', ch: 8, q: "가: 이게 뭐예요?\n나: 텔레비전____________.", a: ["봐요", "해요", "이에요", "을"], c: "이에요", ex: "A bertanya 'Ini apa?' (menggunakan 있게). Jawabannya harus berupa nama benda mati yang diakhiri partikel nomina. 텔레비전 berakhiran konsonan sehingga diikuti partikel '이에요'.", romaji: "" },
      { id: 'n_r115', ch: 8, q: "12시 30분을 어떻게 읽습니까?", a: ["열 시 삼십 분", "열두 시 삼십 분", "한 시 이십 분", "두 시 오십 분"], c: "열두 시 삼십 분", ex: "Untuk jam menggunakan angka Korea asli (12 = 열두) dan untuk menit menggunakan angka Sino-Korea (30 = 삼십).", romaji: "" },

      // ==========================================
      // BAB 9: ANGGOTA KELUARGA & KARAKTER
      // ==========================================
      { id: 'n_r116', ch: 9, q: "가: 가족이 몇 명이에요?\n나: __________________.", a: ["세 명이에요", "베트남에 살아요", "여동생이 예뻐요", "한국에 가요"], c: "세 명이에요", ex: "Orang pertama bertanya 'Keluarganya ada berapa orang?'. Jawaban yang logis untuk merespons pertanyaan jumlah orang adalah 'Ada 3 orang' (세 명이에요).", romaji: "" },
      { id: 'n_r117', ch: 9, q: "가: 여동생은 남자 친구가 있어요?\n나: __________________.", a: ["네, 없어요", "아니요, 없어요", "스무 살이에요", "제 여동생이에요"], c: "아니요, 없어요", ex: "Jika jawabannya menyatakan 'tidak punya', maka harus diawali dengan kata sangkalan 'Tidak' (아니요) diikuti kata 'tidak punya' (없어요).", romaji: "" },
      { id: 'n_r118', ch: 9, q: "가: 투안 씨는 어디에 있어요?\n나: __________________.", a: ["세 명이에요", "형이 있어요", "집에 있어요", "똑똑해요"], c: "집에 있어요", ex: "Kata tanya '어디' menanyakan lokasi. Oleh karena itu, jawaban yang benar harus memberikan informasi tempat, yaitu 'Ada di rumah' (집에 있어요).", romaji: "" },
      { id: 'n_r119', ch: 9, q: "리한: 투안 씨는 가족이 몇 명이에요?\n투안: 어머니하고 형하고 저, 세 명이에요.\n질문: 투안 씨의 가족은 몇 명입니까?", a: ["두 명", "세 명", "네 명", "다섯 명"], c: "세 명", ex: "Tuan membalas dengan tegas bahwa keluarganya berjumlah tiga orang (세 명이에요), yang terdiri dari ibu, kakak laki-laki, dan dia sendiri.", romaji: "" },
      { id: 'n_r120', ch: 9, q: "저는 아버지______ 어머니가 있어요.", a: ["가", "에", "는", "하고"], c: "하고", ex: "Partikel yang digunakan untuk menghubungkan dua kata benda secara setara dengan arti 'dan' dalam konteks lisan adalah '하고'.", romaji: "" },
      { id: 'n_r121', ch: 9, q: "동생은 기숙사______ 살아요.", a: ["가", "에", "는", "하고"], c: "에", ex: "Kata '기숙사' (asrama) adalah kata benda penunjuk tempat. Partikel yang tepat untuk menunjukkan lokasi/tempat tinggal adalah '에' (di/pada).", romaji: "" },
      { id: 'n_r122', ch: 9, q: "가: 누나는 어디에 가요?\n나: 회사______ 가요.", a: ["에", "가", "은", "하고"], c: "에", ex: "Kata kerja perpindahan/arah seperti '가다' (pergi) wajib diikuti oleh partikel tujuan arah/tempat yaitu '에'.", romaji: "" },
      { id: 'n_r123', ch: 9, q: "내일 한 시______ 만나요.", a: ["가", "에", "는", "하고"], c: "에", ex: "Selain untuk tempat, partikel '에' juga ditempelkan pada kata benda penunjuk waktu, seperti jam satu (한 시).", romaji: "" },
      { id: 'n_r124', ch: 9, q: "아내______ 아들이 있어요.", a: ["에", "가", "하고", "는"], c: "하고", ex: "Dua kata benda '아내' (istri) and '아들' (anak laki-laki) dirangkai dengan partikel penghubung setara '하고' (dan).", romaji: "" },
      { id: 'n_r125', ch: 9, q: "제 동생은 ______. 수학을 잘해요.", a: ["똑똑해요", "뚱뚱해요", "친절해요", "얌전해요"], c: "똑똑해요", ex: "Konteks kalimat ini adalah memuji kemampuan adik yang pintar dalam bidang matematika (수학을 잘해요). Oleh karena itu, kata sifat yang paling tepat adalah pintar (똑똑해요).", romaji: "" },
      { id: 'n_r126', ch: 9, q: "여동생이 정말 예뻐요. 지금 몇 ______이에요?", a: ["살", "명", "에", "하고"], c: "살", ex: "Kata satuan yang wajib digunakan untuk menghitung umur/tahun usia seseorang dalam bahasa Korea adalah '살'.", romaji: "" },
      { id: 'n_r127', ch: 9, q: "제 친구는 농구 선수예요. 키가 ______.", a: ["작아요", "커요", "똑똑해요", "예뻐요"], c: "커요", ex: "Atlet basket identik dengan fisik yang tinggi. Frasa '키가 크다' (badannya tinggi) dalam bentuk formal-sopan berubah menjadi '키가 커요'.", romaji: "" },
      { id: 'n_r128', ch: 9, q: "리한 씨는 낮에 일해요. 밤에 공부해요. 아주 ______.", a: ["얌전해요", "활발해요", "부지런해요", "뚱뚱해요"], c: "부지런해요", ex: "Karakter seseorang yang terus produktif (bekerja siang dan belajar malam) disebut sebagai orang yang sangat rajin (부지런해요).", romaji: "" },
      { id: 'n_r129', ch: 9, q: "수피카 씨는 친절해요. 할아버지를 도와줘요.\n질문: 수피카 씨의 성격은 어떻습니까?", a: ["활발해요", "얌전해요", "똑똑해요", "친절해요"], c: "친절해요", ex: "Sifat (성격) Supika dijelaskan secara eksplisit di awal kalimat yaitu ramah atau baik hati (친절해요).", romaji: "" },
      { id: 'n_r130', ch: 9, q: "저는 조금 뚱뚱해요. 매일 ______을/를 해요.", a: ["수학", "영화", "운동", "요리"], c: "운동", ex: "Secara logis dan sesuai dengan materi teks, aktivitas yang dilakukan setiap hari untuk mengatasi kegemukan (뚱뚱해요) adalah berolahraga (운동).", romaji: "" },

      // ==========================================
      // BAB 10: AKTIVITAS MASA LAMPAU & HARI LIBUR
      // ==========================================
      { id: 'n_r131', ch: 10, q: "가: 수루 씨는 언제 한국에 왔어요?\n나: 올해 2월 10일에 한국에 ____________.", a: ["오세요", "왔어요", "와요", "올 거예요"], c: "왔어요", ex: "Karena pertanyaannya menggunakan bentuk lampau (왔어요) dan menanyakan kejadian di masa lalu, maka jawaban yang tepat juga harus menggunakan bentuk lampau 'Saya telah datang...' (왔어요).", romaji: "" },
      { id: 'n_r132', ch: 10, q: "가: 어제 뭐 했어요?\n나: 도서관에서 한국어를 ____________.", a: ["공부해요", "만났어요", "공부했어요", "마셨어요"], c: "공부했어요", ex: "Kegiatan logis di perpustakaan adalah belajar. Karena ditanya mengenai kejadian kemarin (어제), maka kata kerjanya harus menggunakan bentuk lampau 'telah belajar' (공부했어요).", romaji: "" },
      { id: 'n_r133', ch: 10, q: "가: 주말에 백화점에서 쇼핑했어요?\n나: 아니요, ____________에서 쇼핑했어요.", a: ["영화관", "기숙사", "시장", "노래방"], c: "시장", ex: "Berdasarkan opsi yang tersedia, tempat logis untuk berbelanja selain mal adalah pasar (시장).", romaji: "" },
      { id: 'n_r134', ch: 10, q: "가: 어디에서 운동을 했어요?\n나: ____________에서 했어요.", a: ["공원", "서점", "영화관", "커피숍"], c: "공원", ex: "Jawaban yang tepat haruslah nama tempat yang cocok untuk berolahraga. Di antara opsi yang ada, tempat yang benar adalah taman (공원).", romaji: "" },
      { id: 'n_r135', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n저는 어제 공원____________ 산책했어요.", a: ["에", "가", "이", "에서"], c: "에서", ex: "Kata '공원' (taman) diikuti dengan kata kerja aktivitas '산책하다' (berjalan-jalan). Partikel yang tepat untuk menunjukkan lokasi di mana suatu aktivitas berlangsung adalah '에서'.", romaji: "" },
      { id: 'n_r136', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n저는 3월 1일____________ 회사에 가요.", a: ["부터", "에서", "하고", "가"], c: "부터", ex: "Berdasarkan tata bahasa tentang tanggal masuk kerja, partikel yang menunjukkan waktu awalan/mulai adalah '부터' (mulai/dari).", romaji: "" },
      { id: 'n_r137', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n가: 투안 씨는 ____________ 저녁을 먹어요?\n나: 7시에 먹어요.", a: ["어디", "언제", "무슨", "누가"], c: "언제", ex: "Lawan bicara menjawab dengan keterangan waktu 'Makan pada jam 7.' Maka kata tanya untuk menanyakan waktu ('Kapan') adalah '언제'.", romaji: "" },
      { id: 'n_r138', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n어제 기숙사에서 음식을 ____________.", a: ["만들어요", "읽었어요", "만났어요", "만들었어요"], c: "만들어요", ex: "Ada keterangan waktu '어제' (kemarin), sehingga kata kerja '만들다' (membuat/memasak) harus dirubah menjadi bentuk lampau (만들었어요).", romaji: "" },
      { id: 'n_r139', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n동생____________ 같이 저녁을 먹어요.", a: ["가", "에", "하고", "에서"], c: "하고", ex: "Partikel yang digunakan bersama kata '같이' (bersama) untuk menyatakan kebersamaan dengan orang lain adalah '하고' (dengan).", romaji: "" },
      { id: 'n_r140', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n월요일부터 금요일까지 회사에서 일을 해요. ____________에는 집에서 쉬어요.", a: ["오후", "내일", "주중", "주말"], c: "주말", ex: "Hari Senin sampai Jumat disebut hari biasa (주중), sedangkan hari libur (Sabtu dan Minggu) disebut akhir pekan (주말).", romaji: "" },
      { id: 'n_r141', ch: 10, q: "가: 어제 뭐 했어요?\n나: 극장에서 영화를 ____________.", a: ["샀어요", "갔어요", "봤어요", "산책했어요"], c: "봤어요", ex: "Pasangan kata kerja yang tepat untuk '영화를' (film) dalam bentuk lampau adalah '봤어요' (telah menonton).", romaji: "" },
      { id: 'n_r142', ch: 10, q: "가: 서점에 갔어요?\n나: 네, 서점에 갔어요. 그리고 책을 ____________.", a: ["읽었어요", "샀어요", "만났어요", "마셨어요"], c: "샀어요", ex: "Aktivitas utama ketika mendatangi toko buku dan dilakukan segera setelah sampai adalah membeli buku (책을 샀어요).", romaji: "" },
      { id: 'n_r143', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n오늘이 5월 16일이에요. ____________은 17일이에요.", a: ["어제", "작년", "내일", "주말"], c: "내일", ex: "Hari ini adalah tanggal 16 Mei. Secara logis, hari yang bertepatan dengan tanggal 17 Mei (satu hari setelahnya) adalah besok (내일).", romaji: "" },
      { id: 'n_r144', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n저는 리한 씨____________ 한국어를 배워요.", a: ["에", "가", "하고", "에서"], c: "하고", ex: "Partikel '하고' menempel di belakang kata benda/nama orang yang bermakna 'dengan / bersama dengan' dalam aktivitas sosial.", romaji: "" },
      { id: 'n_r145', ch: 10, q: "빈칸에 들어갈 가장 알맞은 것을 고르십시오.\n어제 커피숍에서 커피를 ____________.", a: ["마셔요", "샀어요", "마셨어요", "봤어요"], c: "마셨어요", ex: "Terdapat kata '어제' (kemarin) yang mewajibkan kata kerja '마시다' (minum) dikonversi ke dalam grammar bentuk masa lalu (past tense) menjadi '마셨어요'.", romaji: "" }, { id: 'n_r146', ch: 11, q: "가: 뭘 드릴까요?\n나: __________________.", a: ["이천 원이에요", "사과 다섯 개 주세요", "봉투에 넣었어요", "교환해 주세요"], c: "사과 다섯 개 주세요", ex: "Pertanyaannya adalah 'Mau pesan apa?'. Jawaban yang paling tepat adalah menyebutkan pesanan, yaitu 'Tolong beri saya lima buah apel' (사과 다섯 개 주세요).", romaji: "" },
      { id: 'n_r147', ch: 11, q: "가: 이 사과 __________________?\n나: 이천 원이에요.", a: ["어디", "언제", "얼마", "누구"], c: "얼마", ex: "Orang kedua menjawab dengan harga, 'Dua ribu Won'. Maka kata tanya yang tepat untuk menanyakan harga/berapa adalah '얼마' (Berapa).", romaji: "" },
      { id: 'n_r148', ch: 11, q: "가: 이 운동화는 오만 오천 원이에요.\n나: 좀 비싸요. __________________.\n가: 알았어요. 오만 원 주세요.", a: ["넣어 주세요", "바꿔 주세요", "깎아 주세요", "포장해 주세요"], c: "깎아 주세요", ex: "Pelanggan mengatakan agak mahal (좀 비싸요) dan penjual menurunkan harga. Kalimat untuk meminta potongan harga/diskon adalah '깎아 주세요'.", romaji: "" },
      { id: 'n_r149', ch: 11, q: "가: 봉투에 __________________?\n나: 네, 넣어 주세요.", a: ["포장해 드릴까요", "환불해 드릴까요", "바꿔 드릴까요", "넣어 드릴까요"], c: "넣어 드릴까요", ex: "Orang kedua merespons dengan 'Ya, tolong masukkan' (네, 넣어 주세요). Maka orang pertama pasti menawarkan 'Apakah mau saya masukkan ke dalam plastik/kantong?'.", romaji: "" },
      { id: 'n_r150', ch: 11, q: "어제 시장에서 운동화를 샀어요. 그런데 조금 비싸서 값을 __________________.", a: ["줬어요", "깎았어요", "넣었어요", "바꿨어요"], c: "깎았어요", ex: "Kata kerja yang tepat disandingkan dengan harga (값) saat berbelanja barang mahal adalah menawarnya (깎다). Karena kemarin, maka bentuk lampau '깎았어요'.", romaji: "" },
      { id: 'n_r151', ch: 11, q: "사과, 오렌지, 우유는 세는 단위가 __________________입니다.", a: ["송이", "개", "병", "마리"], c: "개", ex: "Buah-buahan secara umum seperti apel dan jeruk dihitung menggunakan satuan '개' (buah/biji).", romaji: "" },
      { id: 'n_r152', ch: 11, q: "물, 맥주는 세는 단위가 __________________입니다.", a: ["통", "그릇", "잔", "병"], c: "병", ex: "Benda cair yang disimpan di dalam botol komersial seperti air mineral (물) dan bir (맥주) dihitung menggunakan kata satuan botol yaitu '병'.", romaji: "" },
      { id: 'n_r153', ch: 11, q: "포도, 바나나, 꽃은 세는 단위가 __________________입니다.", a: ["송이", "대", "명", "벌"], c: "송이", ex: "Benda yang tumbuh/dipetik bertangkai seperti buah anggur, pisang, dan bunga dihitung dengan satuan tangkai/tandan yaitu '송이'.", romaji: "" },
      { id: 'n_r154', ch: 11, q: "수박, 배추는 세는 단위가 __________________입니다.", a: ["권", "통", "장", "분"], c: "통", ex: "Buah atau sayuran yang berbentuk bulat besar utuh seperti semangka dan sawi putih dihitung dengan satuan '통'.", romaji: "" },
      { id: 'n_r155', ch: 11, q: "커피, 주스는 세는 단위가 __________________입니다.", a: ["잔", "마리", "대", "켤레"], c: "잔", ex: "Minuman yang dihidangkan di dalam cangkir atau gelas seperti kopi dan jus dihitung menggunakan satuan '잔'.", romaji: "" },
      { id: 'n_r156', ch: 11, q: "밥, 국, 반찬은 세는 단위가 __________________입니다.", a: ["개", "송이", "그릇", "통"], c: "그릇", ex: "Makanan di rumah makan seperti nasi, sup, dan lauk pauk dihidangkan dan dihitung menggunakan satuan mangkuk yaitu '그릇'.", romaji: "" },
      { id: 'n_r157', ch: 11, q: "정장, 한복은 세는 단위가 __________________입니다.", a: ["벌", "켤레", "대", "장"], c: "벌", ex: "Pakaian utuh seperti jas atau pakaian tradisional Korea dihitung menggunakan kata satuan potong/lembar pakaian yaitu '벌'.", romaji: "" },
      { id: 'n_r158', ch: 11, q: "운동화, 장갑, 양말은 세는 단위가 __________________입니다.", a: ["벌", "켤레", "마리", "명"], c: "켤레", ex: "Benda pelengkap tubuh yang dipakai sepasang (kanan-kiri) seperti sepatu olahraga, sarung tangan, dan kaus kaki dihitung dengan satuan '켤레'.", romaji: "" },
      { id: 'n_r159', ch: 11, q: "텔레비전, 냉장고, 자동차는 세는 단위가 __________________입니다.", a: ["명", "분", "대", "권"], c: "대", ex: "Mesin elektronik dan kendaraan seperti televisi, kulkas, dan mobil dihitung menggunakan kata satuan unit mesin/kendaraan yaitu '대'.", romaji: "" },
      { id: 'n_r160', ch: 11, q: "고양이, 강아지, 생선은 세는 단위가 __________________입니다.", a: ["마리", "권", "장", "켤레"], c: "마리", ex: "Hewan-hewan seperti kucing, anak anjing, dan ikan dihitung menggunakan kata satuan ekor hewan yaitu '마리'.", romaji: "" }, { id: 'n_r161', ch: 12, q: "가: 이 건물에 은행이 있어요?\n나: ________________________.", a: ["네, 지하 1층에 있어요", "아니요, 우체국이에요", "네, 은행에 가요", "위로 올라가세요"], c: "네, 지하 1층에 있어요", ex: "Jawaban yang tepat harus merespons ketersediaan bank dan letaknya, yaitu 'Ya, ada di lantai 1 bawah tanah' (네, 지하 1층에 있어요).", romaji: "" },
      { id: 'n_r162', ch: 12, q: "가: 우체국이 어디에 있어요?\n나: ________________________.", a: ["경찰서 뒤에 있어요", "편의점에 가요", "저쪽으로 내려가세요", "오른쪽으로 가세요"], c: "경찰서 뒤에 있어요", ex: "Karena menanyakan lokasi pasti, jawaban yang paling akurat adalah menyebutkan patokan tempatnya, yaitu 'Ada di belakang kantor polisi' (경찰서 뒤에 있어요).", romaji: "" },
      { id: 'n_r163', ch: 12, q: "가: 약국이 어디에 있어요?\n나: 2층에 있어요. ________________________.", a: ["아래로 내려가세요", "위로 올라가세요", "밖으로 나가세요", "안으로 들어가세요"], c: "위로 올라가세요", ex: "Instruksi arah yang logis untuk pergi ke lantai 2 (dari lantai bawah) adalah 'Naiklah ke atas' (위로 올라가세요).", romaji: "" },
      { id: 'n_r164', ch: 12, q: "가: 여기 자리 있어요?\n나: 네, ________________________.", a: ["기다리세요", "앉으세요", "나가세요", "내려가세요"], c: "앉으세요", ex: "Orang kedua menjawab 'Ya,' dan secara logis mempersilakan tamu tersebut untuk duduk dengan sopan 'Silakan duduk' (앉으세요).", romaji: "" },
      { id: 'n_r165', ch: 12, q: "가: 화장실이 어디에 있어요?\n나: 사무실 옆에 있어요. 오른쪽________ 가세요.", a: ["으로", "로", "에", "에서"], c: "으로", ex: "Kata '오른쪽' (kanan) berakhiran dengan huruf konsonan (ㄱ). Oleh karena itu, partikel penunjuk arah yang benar adalah '으로'.", romaji: "" },
      { id: 'n_r166', ch: 12, q: "컴퓨터가 사무실에 있어요. 사무실________ 가세요.", a: ["로", "으로", "에", "에서"], c: "로", ex: "Kata '사무실' (kantor) berakhiran dengan konsonan 'ㄹ' (rieul). Berdasarkan aturan tata bahasa, jika berakhiran 'ㄹ', partikel arah yang digunakan adalah '로'.", romaji: "" },
      { id: 'n_r167', ch: 12, q: "가: 이 건물에 편의점이 있어요?\n나: 네, 3층에 있어요. 3층________ 올라가세요.", a: ["으로", "로", "에", "이"], c: "으로", ex: "Kata '3층' (lantai 3) berakhiran dengan konsonan (ㅇ/ieung). Maka dari itu, partikel penunjuk arah yang harus dilekatkan adalah '으로'.", romaji: "" },
      { id: 'n_r168', ch: 12, q: "투안 씨, 빨리 ________________.", a: ["오세요", "가세요", "있으세요", "하세요"], c: "오세요", ex: "Konteks kalimat ini menyuruh Tuan untuk mendekat/datang dengan cepat. Kalimat perintah sopannya adalah 'Tuan, tolong cepat datang' (빨리 오세요).", romaji: "" },
      { id: 'n_r169', ch: 12, q: "가: 밖에서 기다려 주세요.\n나: 네, ________________.", a: ["알겠어요", "없어요", "앉으세요", "기다리세요"], c: "알겠어요", ex: "Orang pertama meminta tolong untuk menunggu di luar. Orang kedua harus memberikan konfirmasi pemahaman yaitu 'Saya mengerti' (알겠어요).", romaji: "" },
      { id: 'n_r170', ch: 12, q: "병원 ________________에 은행이 있어요.", a: ["건너편", "사이", "가운데", "안쪽"], c: "건너편", ex: "'건너편' berarti 'seberang', yang tata bahasanya cocok disambung dengan partikel '에'. Pilihan '사이' (di antara) membutuhkan lebih dari satu lokasi rujukan.", romaji: "" },
      { id: 'n_r171', ch: 12, q: "가: 우체국이 건물 밖에 있어요?\n나: 네, ________________ 나가세요.", a: ["안으로", "밖으로", "위로", "아래로"], c: "밖으로", ex: "Arah luar ditambah partikel tujuan menjadi '밖으로' (keluarlah ke arah luar).", romaji: "" },
      { id: 'n_r172', ch: 12, q: "가: 내일 고향에 ________________?\n나: 네, 내일 가요.", a: ["돌아가요", "올라가요", "내려가요", "들어가요"], c: "돌아가요", ex: "Kata kerja yang tepat untuk menyatakan 'kembali pulang' ke tempat asal adalah '돌아가다' (menjadi 돌아가요).", romaji: "" },
      { id: 'n_r173', ch: 12, q: "가: 이 근처에 약국이 있어요?\n나: 네, 저 사거리에서 왼쪽으로 가세요. ________________ 병원 옆에 약국이 있어요.", a: ["그래서", "그러면", "그러나", "그리고"], c: "그러면", ex: "Kata sambung yang tepat untuk menyatakan hasil dari instruksi 'beloklah ke kiri' tersebut adalah '그러면' (Kalau begitu/Dengan begitu).", romaji: "" },
      { id: 'n_r174', ch: 12, q: "1층으로 ________________. 그러면 식당이 있어요.", a: ["내려오세요", "올라가세요", "들어가세요", "나가세요"], c: "내려오세요", ex: "Karena lantai 1 berada di bawah posisi pembicara (di lantai atas), kata kerja yang digunakan adalah turunlah / '내려오세요' (datang turun).", romaji: "" },
      { id: 'n_r175', ch: 12, q: "길을 건널 때는 ________________을/를 이용하세요.", a: ["횡단보도", "신호등", "골목", "이정표"], c: "횡단보도", ex: "Fasilitas jalanan yang dikhususkan untuk menyeberang jalan adalah zebra cross atau tempat penyeberangan pejalan kaki (횡단보도).", romaji: "" }, { id: 'n_r176', ch: 13, q: "가: 우리 같이 영화 볼까요?\n나: ________________________.", a: ["좋아요. 같이 영화 봐요.", "미안해요. 시간이 있어요.", "네, 바빠요.", "아니요, 재미있어요."], c: "좋아요. 같이 영화 봐요.", ex: "Jawaban persetujuan yang logis untuk ajakan menonton film adalah 'Bagus. Ayo kita nonton film bersama' (좋아요. 같이 영화 봐요).", romaji: "" },
      { id: 'n_r177', ch: 13, q: "가: 우리 내일 어디에서 만날까요?\n나: ________________________.", a: ["7시에 만나요.", "회사 앞 어때요?", "코미디 영화를 봐요.", "내일 시간 괜찮아요."], c: "회사 앞 어때요?", ex: "Pertanyaannya adalah 'Besok kita sebaiknya bertemu di mana?' (어디에서). Maka jawabannya harus menyarankan lokasi (회사 앞 어때요?).", romaji: "" },
      { id: 'n_r178', ch: 13, q: "가: 내일 여섯 시쯤 만날까요?\n나: 여섯 시는 좀 빨라요. ________________________.", a: ["일곱 시에 괜찮아요?", "시청 앞 어때요?", "시간이 없어요.", "영화를 보고 싶어요."], c: "일곱 시에 괜찮아요?", ex: "Orang kedua menganggap jam 6 terlalu awal. Respons logis selanjutnya adalah menawarkan waktu pengganti, yaitu 'Bagaimana kalau jam 7?'.", romaji: "" },
      { id: 'n_r179', ch: 13, q: "투안: 수루 씨, 내일 시간 있어요?\n수루: 네, 시간 괜찮아요. 그런데 왜요?\n투안: 우리 같이 점심 먹을까요?\n수루: ________________________.", a: ["네, 시간이 없어요.", "아니요, 내일 바빠요.", "좋아요. 같이 점심 먹어요.", "내일은 일이 많아요."], c: "좋아요. 같이 점심 먹어요.", ex: "Jawaban Suru yang paling logis menerima ajakan makan siang setelah mengonfirmasi ada waktu luang adalah 'Boleh. Mari makan siang bersama'.", romaji: "" },
      { id: 'n_r180', ch: 13, q: "저는 오늘 아주 바빠요. 그래서 영화를 볼 시간이 ________________________.", a: ["없어요", "있어요", "많아요", "좋아요"], c: "없어요", ex: "Karena kalimat awal menyatakan sibuk (바빠요), secara logis 'tidak ada' waktu untuk menonton film (없어요).", romaji: "" },
      { id: 'n_r181', ch: 13, q: "가: 뭐 먹고 ________________________?\n나: 비빔밥을 먹고 싶어요.", a: ["싶어요", "볼까요", "만날까요", "할까요"], c: "싶어요", ex: "Tata bahasa untuk menyatakan keinginan adalah '-고 싶다'. Karena dijawab '먹고 싶어요', pertanyaannya harus sejalan: '먹고 싶어요?' (Ingin makan apa?).", romaji: "" },
      { id: 'n_r182', ch: 13, q: "가: 우리 내일 같이 ________________________?\n나: 좋아요. 같이 공부해요.", a: ["먹을까요", "공부할까요", "만날까요", "볼까요"], c: "공부할까요", ex: "Orang B menjawab setuju untuk belajar bersama (같이 공부해요). Berarti orang A menawarkan ajakan belajar (공부할까요?).", romaji: "" },
      { id: 'n_r183', ch: 13, q: "가: 오늘 저녁에 같이 시내에 ________________________?\n나: 좋아요. 같이 시내에 가요.", a: ["갈까요", "먹을까요", "볼까요", "할까요"], c: "갈까요", ex: "Orang B menjawab setuju untuk pergi ke pusat kota (시내에 가요). Oleh karena itu, tawaran dari A menggunakan kata kerja 'pergi' (갈까요?).", romaji: "" },
      { id: 'n_r184', ch: 13, q: "이 구두는 너무 작아요. 발이 ________________________.", a: ["편해요", "불편해요", "간단해요", "가까워요"], c: "불편해요", ex: "Jika sepatu terlalu kecil, maka kondisi yang dirasakan oleh kaki adalah 'tidak nyaman' (불편해요).", romaji: "" },
      { id: 'n_r185', ch: 13, q: "가: 회사에서 집까지 ________________________?\n나: 아니요, 버스로 1시간 걸려요.", a: ["가까워요", "같아요", "달라요", "빨라요"], c: "가까워요", ex: "B menyangkal dan berkata butuh 1 jam (jauh). Berarti A awalnya bertanya apakah jaraknya dekat (가까워요?).", romaji: "" },
      { id: 'n_r186', ch: 13, q: "가: 수루 씨는 무슨 영화를 좋아해요?\n나: ________________________.", a: ["코미디 영화를 보고 싶어요.", "시간이 괜찮아요.", "시청 앞에서 만나요.", "내일은 바빠요."], c: "코미디 영화를 보고 싶어요.", ex: "Jawaban yang paling masuk akal untuk pertanyaan 'suka film apa' adalah merespons dengan genre film (코미디 영화).", romaji: "" },
      { id: 'n_r187', ch: 13, q: "내일은 친구 생일이에요. 그래서 선물을 ________________________.", a: ["사고 싶어요", "먹고 싶어요", "보고 싶어요", "가고 싶어요"], c: "사고 싶어요", ex: "Karena besok ulang tahun teman, kata kerja yang sesuai untuk hadiah (선물) adalah 'ingin membeli' (사고 싶어요).", romaji: "" },
      { id: 'n_r188', ch: 13, q: "가: 내일 7시에 만날까요?\n나: 7시는 좀 ________________. 8시는 어때요?", a: ["빨라요", "달라요", "편해요", "간단해요"], c: "빨라요", ex: "Orang B meminta waktu diundur menjadi jam 8. Berarti jam 7 dirasa terlalu 'awal' atau 'cepat' (빨라요).", romaji: "" },
      { id: 'n_r189', ch: 13, q: "일이 너무 많아서 ________________.", a: ["한가해요", "바빠요", "재미있어요", "간단해요"], c: "바빠요", ex: "Jika memiliki banyak pekerjaan (일이 많다), maka kondisinya adalah sibuk (바빠요).", romaji: "" },
      { id: 'n_r190', ch: 13, q: "가: 한국어 공부가 ________________?\n나: 네, 아주 재미있어요.", a: ["재미없어요", "재미있어요", "복잡해요", "불편해요"], c: "재미있어요", ex: "Jika jawabannya diawali 'Ya' dan menyatakan menarik/menyenangkan (재미있어요), berarti pertanyaannya juga harus menggunakan kata '재미있어요?'.", romaji: "" }, { id: 'n_r191', ch: 14, q: "가: 어서 오세요. 몇 분이세요?\n나: ________________________.", a: ["비빔밥 먹을래요", "두 명이요", "여기 앉으세요", "김치찌개 주세요"], c: "두 명이요", ex: "Pelayan bertanya 'Untuk berapa orang?' (몇 분이세요?). Jawaban yang tepat harus menyebutkan jumlah orang, yaitu 'Dua orang' (두 명이요).", romaji: "" },
      { id: 'n_r192', ch: 14, q: "가: ________________________?\n나: 저는 갈비탕 먹을래요.", a: ["자리 있어요", "몇 분이세요", "뭐 드릴까요", "맵지 않아요"], c: "뭐 드릴까요", ex: "Orang kedua menjawab pesanan makanannya. Frasa standar yang digunakan pelayan untuk menanyakan pesanan adalah 'Mau pesan apa?' (뭐 드릴까요?).", romaji: "" },
      { id: 'n_r193', ch: 14, q: "가: 떡볶이가 매워요?\n나: 아니요, ________________________.", a: ["안 매워요", "너무 매워요", "매울래요", "안 먹을래요"], c: "안 매워요", ex: "Jawaban diawali dengan penolakan 'Tidak' (아니요). Maka kata sifatnya harus dirubah ke bentuk negatif menggunakan '안', menjadi 'Tidak pedas' (안 매워요).", romaji: "" },
      { id: 'n_r194', ch: 14, q: "투안: 수루 씨는 불고기 좋아해요?\n수루: 네, 좋아해요. 투안 씨는요?\n투안: ________________________. 저는 비빔밥을 좋아해요.", a: ["저도 좋아해요", "전 안 좋아해요", "불고기를 먹을래요", "조금 매워요"], c: "전 안 좋아해요", ex: "Tuan menyatakan bahwa dia menyukai bibimbap. Secara logis, ia harus menolak menyukai bulgogi terlebih dahulu dengan berkata 'Saya tidak suka' (전 안 좋아해요).", romaji: "" },
      { id: 'n_r195', ch: 14, q: "가: 저녁에 어디에 갈래요?\n나: 저는 시내에 ________________________.", a: ["갈래요", "먹을래요", "볼래요", "놀래요"], c: "갈래요", ex: "Sesuai pola tanya jawab grammar -(으)ㄹ래요, penjawab harus mengulang kata kerja yang ditanyakan yaitu pergi 'Saya mau pergi ke pusat kota' (시내에 갈래요).", romaji: "" },
      { id: 'n_r196', ch: 14, q: "가: 주말에 우리 같이 ________________________?\n나: 좋아요. 같이 놀아요.", a: ["쉴래요", "놀래요", "먹을래요", "갈래요"], c: "놀래요", ex: "B membalas ajakan dengan persetujuan 'Ayo kita main bersama' (같이 놀아요). Kata kerja bermain (놀다) digabung dengan -(으)ㄹ래요 menjadi '놀래요?'.", romaji: "" },
      { id: 'n_r197', ch: 14, q: "가: 어제 운동했어요?\n나: 아니요, 운동 ________________________.", a: ["없어요", "안 먹었어요", "안 했어요", "안 해요"], c: "안 했어요", ex: "Untuk kata kerja 명사+하다 (운동하다) di masa lampau, kata negatif '안' diletakkan di tengah sebelum 하다, menjadi '운동 안 했어요'.", romaji: "" },
      { id: 'n_r198', ch: 14, q: "식당에 사람이 많습니다. ________________________가/이 없습니다.", a: ["메뉴", "식당", "자리", "반찬"], c: "자리", ex: "Jika restoran penuh dengan orang, maka yang secara logis tidak ada atau kehabisan adalah 'tempat duduk' atau 'kursi' (자리).", romaji: "" },
      { id: 'n_r199', ch: 14, q: "찌개가 조금 ________________________. 하지만 맛있어요.", a: ["달아요", "달래요", "맵다", "매워요"], c: "매워요", ex: "Kata dasar pedas adalah '맵다'. Karena merupakan 'ㅂ' tidak beraturan (ㅂ 불규칙), ketika bertemu akhiran -어요 ia berubah menjadi '매워요'.", romaji: "" },
      { id: 'n_r200', ch: 14, q: "음식이 너무 ________________________. 소금을 더 넣고 싶어요.", a: ["싱거워요", "매워요", "짜요", "시어요"], c: "싱거워요", ex: "Jika sebuah masakan membutuhkan tambahan garam (소금), berarti rasanya hambar. Hambar (싱겁다) berubah menjadi '싱거워요' akibat ㅂ tidak beraturan.", romaji: "" },
      { id: 'n_r201', ch: 14, q: "가: 아침 먹었어요?\n나: 아니요, ________________________.", a: ["안 먹어요", "안 먹을래요", "안 먹었어요", "맛없어요"], c: "안 먹었어요", ex: "A bertanya dengan tata bahasa lampau (먹었어요). B harus menggunakan bentuk negatif masa lampau untuk menjawabnya, yaitu 'Belum/tidak makannya' (안 먹었어요).", romaji: "" },
      { id: 'n_r202', ch: 14, q: "가: 내일 뭐 할래요?\n나: 저는 집에서 ________________________.", a: ["안 쉴래요", "쉴래요", "쉬어요", "쉬었어요"], c: "쉴래요", ex: "A bertanya niatan menggunakan -(으)ㄹ래요. Orang B menjawab niatannya untuk beristirahat dengan tata bahasa yang sama, yaitu '쉴래요' (ingin/mau istirahat).", romaji: "" },
      { id: 'n_r203', ch: 14, q: "여기 된장찌개하고 밥 한 ________________________ 주세요.", a: ["그릇", "접시", "인분", "공기"], c: "공기", ex: "Satuan hitung khusus untuk nasi (밥) di restoran Korea adalah '공기' (mangkuk nasi).", romaji: "" },
      { id: 'n_r204', ch: 14, q: "가: 투안 씨, 이 오렌지가 달아요?\n나: 아니요, 안 달아요. 너무 ________________________.", a: ["짜요", "싱거워요", "시어요", "매워요"], c: "시어요", ex: "Rasa buah jeruk yang tidak manis pastilah asam. Kosakata untuk asam adalah 시다, yang dalam bentuk sopannya menjadi '시어요'.", romaji: "" },
      { id: 'n_r205', ch: 14, q: "가: 불고기 3________________________ 주세요.\n나: 네, 알겠습니다.", a: ["공기", "인분", "접시", "그릇"], c: "인분", ex: "Satuan hitung yang dipakai saat memesan menu daging utama (seperti Bulgogi, Samgyeopsal) dalam bahasa Korea adalah porsi, yaitu '인분'.", romaji: "" }, { id: 'n_r206', ch: 15, q: "가: 비가 계속 오네요. 투안 씨, 우산 있어요?\n나: ________________________.", a: ["네, 안 그치네요.", "아니요, 없어요.", "이따가 집에 가요.", "네, 날씨가 맑아요."], c: "아니요, 없어요.", ex: "Jawaban yang paling tepat untuk mengonfirmasi ketiadaan benda yang ditanyakan (payung) adalah 'Tidak, saya tidak punya' (아니요, 없어요).", romaji: "" },
      { id: 'n_r207', ch: 15, q: "가: 오늘 참 덥네요.\n나: ________________________.", a: ["네, 눈이 오네요.", "맞아요. 너무 더워요.", "아니요, 비가 와요.", "네, 정말 시원하네요."], c: "맞아요. 너무 더워요.", ex: "Orang kedua yang setuju dengan keadaan cuaca sangat panas tersebut akan menjawab, 'Benar. Terlalu panas.' (맞아요. 너무 더워요).", romaji: "" },
      { id: 'n_r208', ch: 15, q: "가: 투안 씨는 무슨 계절을 좋아해요?\n나: ________________________.", a: ["비가 많이 와요.", "저는 겨울을 좋아해요.", "날씨가 아주 춥네요.", "오늘 참 시원하네요."], c: "저는 겨울을 좋아해요.", ex: "Karena ditanya 'musim apa' (무슨 계절), maka harus dijawab dengan nama musim yang disukai, yaitu 'Saya suka musim dingin' (저는 겨울을 좋아해요).", romaji: "" },
      { id: 'n_r209', ch: 15, q: "수루: 오늘 기분이 어때요?\n투안: ________________________.", a: ["가을을 가장 좋아해요.", "비가 그치네요.", "눈이 와서 기분이 좋아요.", "날씨가 참 나쁘네요."], c: "눈이 와서 기분이 좋아요.", ex: "Suru bertanya 'Bagaimana perasaanmu hari ini?'. Jawaban yang logis adalah menjelaskan kondisi perasaan dan alasannya (눈이 와서 기분이 좋아요).", romaji: "" },
      { id: 'n_r210', ch: 15, q: "베트남에는 겨울이 없어요. 그래서 눈이 ________________________.", a: ["많이 와요", "너무 추워요", "기분이 좋아요", "안 와요"], c: "안 와요", ex: "Jika suatu negara tidak ada musim dingin, maka secara logis saljunya pasti 'tidak turun' (안 와요).", romaji: "" },
      { id: 'n_r211', ch: 15, q: "가: 지금 날씨가 어때요?\n나: 비가 ________________________. 우산이 필요해요.", a: ["와요", "그쳐요", "맑아요", "따뜻해요"], c: "와요", ex: "Payung dibutuhkan ketika cuacanya sedang turun hujan. Kosakata turun hujan adalah 비가 오다, yang diubah menjadi '와요'.", romaji: "" },
      { id: 'n_r212', ch: 15, q: "날씨가 ________________________ 기분이 좋아요.", a: ["시원해서", "시원하네요", "피곤해서", "외로워서"], c: "시원해서", ex: "Tata bahasa untuk menyatakan alasan (karena) di tengah kalimat adalah '-아서/어서'. '시원하다' digabung dengan '-어서' menjadi '시원해서' (Karena sejuk).", romaji: "" },
      { id: 'n_r213', ch: 15, q: "가: 왜 우울해요?\n나: 비가 ________________________ 기분이 우울해요.", a: ["오네요", "와서", "그치네요", "맑아서"], c: "와서", ex: "Untuk memberikan alasan menggunakan '-아서/어서', kata '비가 오다' (turun hujan) ditambah '-아서' menjadi '비가 와서' (Karena hujan turun).", romaji: "" },
      { id: 'n_r214', ch: 15, q: "가: 어제 왜 병원에 갔어요?\n나: 배가 ________________________ 병원에 갔어요.", a: ["아파서", "아프네요", "춥네요", "추워서"], c: "아파서", ex: "Pergi ke rumah sakit pasti karena sakit. Kata '아프다' (sakit) dirangkai dengan tata bahasa alasan '-아서' menjadi '아파서' (karena sakit).", romaji: "" },
      { id: 'n_r215', ch: 15, q: "요즘 회사에 일이 아주 많습니다. 일을 많이 ________________________ 매일 피곤합니다.", a: ["하네요", "해서", "좋아서", "좋네요"], c: "해서", ex: "Tata bahasa alasan '-아서/어서' jika digabung dengan kata kerja berakhiran '하다' akan berubah menjadi '해서' (일을 많이 해서 / Karena banyak bekerja).", romaji: "" },
      { id: 'n_r216', ch: 15, q: "가: 모니카 씨는 한국 음식을 참 잘 ________________________.\n나: 그래요? 감사합니다.", a: ["만드네요", "만나서", "만들어서", "만나네요"], c: "만드네요", ex: "Tata bahasa kekaguman/keterkejutan adalah '-네요'. Membuat (만들다) jika bertemu '-네요' maka huruf 'ㄹ' akan hilang menjadi '만드네요'.", romaji: "" },
      { id: 'n_r217', ch: 15, q: "가: 오늘 날씨가 정말 ________________________.\n나: 네, 맞아요. 빨리 집에 가서 쉬고 싶어요. 너무 추워요.", a: ["시원하네요", "춥네요", "따뜻하네요", "덥네요"], c: "춥네요", ex: "B setuju ingin cepat pulang karena 'sangat dingin'. Oleh karena itu, A pasti mengagumi betapa dinginnya cuaca hari itu, yaitu '춥네요'.", romaji: "" },
      { id: 'n_r218', ch: 15, q: "어제 밤에 잠을 못 ________________________ 오늘 너무 졸려요.", a: ["자네요", "와서", "자서", "오네요"], c: "자서", ex: "Kata kerja tidur adalah '자다'. Sebagai alasan dari akibat (mengantuk), maka dipasang dengan tata bahasa sebab '-아서' menjadi '자서'.", romaji: "" },
      { id: 'n_r219', ch: 15, q: "가: 시험을 잘 ________________________?\n나: 네, 시험을 잘 쳐서 기분이 아주 좋아요.", a: ["쳤네요", "쳐서", "쳤어요", "치네요"], c: "쳤어요", ex: "B menjawab pertanyaan dengan past tense ('telah mengerjakan'). Maka A pasti bertanya menggunakan bentuk masa lampau: '시험을 잘 쳤어요?'.", romaji: "" },
      { id: 'n_r220', ch: 15, q: "친구한테서 편지를 ________________________ 정말 기뻐요.", a: ["받아서", "받네요", "봐서", "보네요"], c: "받아서", ex: "Menerima (받다) menjadi alasan atas perasaan gembira (기쁘다). '받다' ditambah akhiran alasan '-아서' menjadi '받아서' (Karena menerima).", romaji: "" }, { id: 'n_r221', ch: 16, q: "가: 수루 씨는 취미가 뭐예요?\n나: ________________________.", a: ["시간이 없어요.", "제 취미는 독서예요.", "낚시하러 가요.", "등산 동호회예요."], c: "제 취미는 독서예요.", ex: "Pertanyaannya 'Hobinya apa?' (취미가 뭐예요?). Jawaban yang paling tepat adalah menyebutkan hobi, yaitu 'Hobi saya adalah membaca buku' (제 취미는 독서예요).", romaji: "" },
      { id: 'n_r222', ch: 16, q: "가: ________________________?\n나: 낚시하러 자주 가요.", a: ["오늘 날씨가 어때요", "시간이 있을 때 뭐 해요", "무슨 운동을 좋아해요", "취미가 뭐예요"], c: "시간이 있을 때 뭐 해요", ex: "Pertanyaan yang cocok untuk respons rutinitas 'sering pergi memancing' ini adalah 'Apa yang kamu lakukan saat ada waktu luang?' (시간이 있을 때 뭐 해요?).", romaji: "" },
      { id: 'n_r223', ch: 16, q: "가: 축구를 가장 좋아해요.\n나: 그래요? 그러면 내일 저하고 같이 축구하러 ________________________?", a: ["갈래요", "올래요", "할래요", "칠래요"], c: "갈래요", ex: "Tata bahasa ajakan pergi untuk suatu tujuan adalah -(으)러 가다, ditambah ajakan -(으)ㄹ래요 menjadi '갈래요?' (Maukah pergi...?).", romaji: "" },
      { id: 'n_r224', ch: 16, q: "가: 리한 씨는 주말에 보통 뭐 해요?\n나: 전 운동을 좋아해서 주로 ________________________.", a: ["음악을 들어요", "사진을 찍어요", "운동해요", "독서해요"], c: "운동해요", ex: "Kata yang logis untuk melengkapi kalimat 'Saya suka olahraga, jadi biasanya saya ________' adalah 'berolahraga' (운동해요).", romaji: "" },
      { id: 'n_r225', ch: 16, q: "날씨가 ________ 등산해요.", a: ["좋을 때", "좋을 가요", "좋아서", "좋네요"], c: "좋을 때", ex: "Untuk menyatakan 'ketika' atau 'saat', kita menggunakan '-(으)ㄹ 때'. Kata sifat '좋다' menjadi '좋을 때' (Saat bagus).", romaji: "" },
      { id: 'n_r226', ch: 16, q: "비가 ________ 집에서 책을 읽어요.", a: ["올 때", "와서", "올러", "오네요"], c: "올 때", ex: "Tata bahasa untuk 'ketika/saat' adalah '-(으)ㄹ 때'. Kata kerja '오다' (turun) menjadi '올 때' (Ketika turun).", romaji: "" },
      { id: 'n_r227', ch: 16, q: "가: 운동을 매일 해요?\n나: 아니요, 시간이 ________ 해요.", a: ["있을 때", "없을 때", "있어서", "없어서"], c: "있을 때", ex: "Jawaban yang logis adalah olahraga 'Ketika ada/memiliki waktu'. Tata bahasa yang tepat adalah '있을 때'.", romaji: "" },
      { id: 'n_r228', ch: 16, q: "가: 그 사람을 언제 만났어요?\n나: 제주도를 ________ 만났어요.", a: ["여행하러", "여행할 때", "여행해서", "여행할래요"], c: "여행할 때", ex: "Jawabannya harus menjelaskan waktu kejadian (kapan bertemunya). Menggunakan '여행하다' ditambah '-(으)ㄹ 때' menjadi '여행할 때' (Ketika berwisata).", romaji: "" },
      { id: 'n_r229', ch: 16, q: "스트레스가 많을 때 음악을 ________. 그러면 기분이 좋아져요.", a: ["듣으러", "들을 때", "들어요", "듣어요"], c: "들어요", ex: "Bentuk kebiasaan/sekarang dari kata kerja mendengarkan (듣다) adalah '-어요'. Karena irregular 'ㄷ', ia berubah menjadi '들어요'.", romaji: "" },
      { id: 'n_r230', ch: 16, q: "가: 주말에 친구하고 같이 어디 가요?\n나: 운동________ 가요.", a: ["할 때", "해서", "하러", "하네요"], c: "하러", ex: "Tata bahasa untuk tujuan adalah '-(으)러 가다'. Kata '운동하다' menjadi '운동하러' (Untuk berolahraga).", romaji: "" },
      { id: 'n_r231', ch: 16, q: "가: 시간 있을 때 뭐 해요?\n나: 저는 사진 ________ 자주 가요.", a: ["찍을 때", "찍어서", "찍으러", "찍을래요"], c: "찍으러", ex: "Kata kerja '찍다' (memotret) dipadukan dengan tata bahasa tujuan pergi '-(으)러 가다' menjadi '찍으러' (pergi untuk mengambil foto).", romaji: "" },
      { id: 'n_r232', ch: 16, q: "제 취미는 자전거 타기예요. 그래서 주말마다 공원에 자전거를 ________ 가요.", a: ["탈 때", "타러", "치러", "하러"], c: "타러", ex: "Kata kerja pasangan untuk sepeda adalah '타다' (naik/mengendarai). Digabung dengan tata bahasa tujuan menjadi '타러' (pergi untuk naik sepeda).", romaji: "" },
      { id: 'n_r233', ch: 16, q: "친구하고 같이 배드민턴을 ________ 체육관에 가요.", a: ["치러", "타러", "하러", "칠 때"], c: "치러", ex: "Kata kerja yang sesuai untuk olahraga menggunakan raket (badminton) adalah '치다' (memukul). Digabung tata bahasa tujuan menjadi '치러' (pergi untuk bermain).", romaji: "" },
      { id: 'n_r234', ch: 16, q: "가: 여권을 만들려면 사진이 필요해요.\n나: 그래요? 그럼 주말에 사진관에 사진을 ________ 갈까요?", a: ["볼", "찍을", "찍으러", "보러"], c: "찍으러", ex: "Kata kerja yang tepat untuk foto adalah 찍다 (mengambil/memotret). Dipadukan dengan tata bahasa tujuan menjadi '찍으러' (pergi untuk mengambil).", romaji: "" },
      { id: 'n_r235', ch: 16, q: "저는 제 취미를 정말 좋아해요. 그래서 시간이 있을 때 ________ 낚시를 하러 가요.", a: ["가끔", "항상", "별로", "안"], c: "항상", ex: "Kata keterangan frekuensi yang tepat jika seseorang 'sangat menyukai' suatu hal dan melakukannya tiap ada waktu adalah '항상' (selalu).", romaji: "" }, { id: 'n_r236', ch: 17, q: "가: 리한 씨는 제주도에 가 봤어요?\n나: ________________________.", a: ["네, 가 봤어요.", "아니요, 갈 거예요.", "네, 숙소를 예약했어요.", "특히 바다가 아름다웠어요."], c: "네, 가 봤어요.", ex: "Orang pertama bertanya pengalaman menggunakan tata bahasa '-아/어 보다'. Respons persetujuan yang tepat adalah 'Ya, saya pernah pergi.' (네, 가 봤어요).", romaji: "" },
      { id: 'n_r237', ch: 17, q: "가: 제주도가 어땠어요? 좋았어요?\n나: ________________________.", a: ["내일 출발할 거예요.", "네, 정말 좋았어요. 경치가 아름다웠어요.", "비행기 표를 샀어요.", "민박에서 묵을 거예요."], c: "네, 정말 좋았어요. 경치가 아름다웠어요.", ex: "Jawaban yang logis harus merespons kesan wisata tersebut, yaitu 'Ya, sangat bagus. Pemandangannya indah.'", romaji: "" },
      { id: 'n_r238', ch: 17, q: "두 사람은 지금 무엇에 대해 이야기하고 있습니까?\n가: 비행기 표는 샀어요?\n나: 네, 숙소도 벌써 다 예약했어요. 짐만 싸면 돼요.", a: ["여행 경험", "여행 준비", "관광지 소개", "호텔 요금"], c: "여행 준비", ex: "Orang pertama bertanya tiket pesawat, orang kedua menjawab sudah pesan penginapan dan tinggal berkemas. Mereka sedang mendiskusikan 'Persiapan wisata' (여행 준비).", romaji: "" },
      { id: 'n_r239', ch: 17, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 호텔, 펜션, 민박, 여관, 콘도 ]", a: ["숙박 시설", "교통수단", "관광지", "여행 활동"], c: "숙박 시설", ex: "Hotel, Pension (Bungalo), Minbak (Homestay), Yeogwan (Losmen), dan Condo adalah macam-macam 'Fasilitas Penginapan' (숙박 시설).", romaji: "" },
      { id: 'n_r240', ch: 17, q: "제주도는 경치가 정말 아름답습니다. __________________ 사람들이 아주 친절합니다.", a: ["그러나", "그래서", "그리고", "그러면"], c: "그리고", ex: "Kalimat ini menyebutkan dua nilai plus Pulau Jeju. Kata sambung penambahan yang tepat untuk menggabungkannya adalah 그리고 (Dan).", romaji: "" },
      { id: 'n_r241', ch: 17, q: "저는 다음 달에 고향에 갈 거예요. __________________ 어제 비행기 표를 샀어요.", a: ["그래서", "하지만", "그리고", "그러나"], c: "그래서", ex: "Tindakan membeli tiket adalah akibat/hasil dari rencana pulang kampung. Kata sambungnya adalah 그래서 (Oleh karena itu/Jadi).", romaji: "" },
      { id: 'n_r242', ch: 17, q: "콘도는 직접 음식을 만들어서 먹을 수 있습니다. __________________ 호텔에서는 요리를 할 수 없습니다.", a: ["그러면", "그리고", "그래서", "하지만"], c: "하지만", ex: "Kalimat pertama menyatakan kelebihan kondominium, sedangkan kalimat kedua menyatakan kekurangan hotel (tidak bisa masak). Ada pertentangan, jadi menggunakan 하지만 (Namun).", romaji: "" },
      { id: 'n_r243', ch: 17, q: "'-아/어 보다'를 맞게 사용한 문장은 무엇입니까?", a: ["한국에서 여행을 많이 해 봤어요.", "내일 김치를 먹어 봤어요.", "숙소를 예약해 볼 거예요.", "어제 비행기 표를 사 봤습니다."], c: "한국에서 여행을 많이 해 봤어요.", ex: "Tata bahasa '-아/어 보다' digunakan untuk pengalaman (pernah). Pilihan A (Saya pernah banyak berwisata di Korea) adalah penggunaan yang paling baku dan benar.", romaji: "" },
      { id: 'n_r244', ch: 17, q: "'-(으)ㄹ 거예요'를 틀리게 사용한 문장은 무엇입니까?", a: ["오늘 저녁에 불고기를 먹을 거예요.", "이번 주말에 친구를 만날 거예요.", "휴가 때 제주도로 출발할을 거예요.", "숙소에서 짐을 풀 거예요."], c: "휴가 때 제주도로 출발할을 거예요.", ex: "Kata 출발하다 berakhiran vokal, jadi seharusnya ditambahkan '-ㄹ 거예요' menjadi '출발할 거예요'. Tulisan '출발할을 거예요' pada opsi C salah gramatikal.", romaji: "" },
      { id: 'n_r245', ch: 17, q: "가: ________________________?\n나: 친구를 만나러 부산에 갈 거예요.", a: ["언제 출발했어요?", "이번 연휴에 뭐 할 거예요?", "부산이 어땠어요?", "누구하고 같이 가요?"], c: "이번 연휴에 뭐 할 거예요?", ex: "Orang kedua menjawab rencana masa depannya. Maka pertanyaan yang tepat harus menanyakan rencananya: 'Liburan panjang kali ini akan melakukan apa?'", romaji: "" },
      { id: 'n_r246', ch: 17, q: "가: 휴가 때 어디에서 잘 거예요?\n나: 가족적인 분위기가 좋아서 ________________________.", a: ["박물관을 관람할 거예요.", "비행기 표를 샀어요.", "펜션에서 묵을 거예요.", "동해 일주를 할 거예요."], c: "펜션에서 묵을 거예요.", ex: "Akomodasi yang bernuansa kekeluargaan (가족적인 분위기) dan merupakan tempat menginap adalah 펜션 (Bungalo).", romaji: "" },
      { id: 'n_r247', ch: 17, q: "저는 고향에 바다가 없습니다. 그래서 이번 휴가 때 바다에 가서 수영을 _______________.", a: ["해 볼 거예요", "해 봤어요", "갈 거예요", "할 거예요"], c: "해 볼 거예요", ex: "Karena dia belum pernah, gabungan tata bahasa coba/pengalaman (-아/어 보다) dan masa depan (-(으)ㄹ 거예요) digunakan menjadi '해 볼 거예요' (akan mencoba berenang).", romaji: "" },
      { id: 'n_r248', ch: 17, q: "이 호텔은 _______________ 참 좋습니다. 침대도 크고 텔레비전도 큽니다.", a: ["경치가", "사람들이", "시설이", "비용이"], c: "시설이", ex: "Ranjang dan TV adalah bagian dari sarana/fasilitas bangunan. Kosakata fasilitas adalah 시설.", romaji: "" },
      { id: 'n_r249', ch: 17, q: "여행지에서 돌아오기 전에 친구들에게 줄 _______________ 샀습니다.", a: ["온천을", "기념품을", "비행기를", "동굴을"], c: "기념품을", ex: "Barang yang dibeli untuk diberikan kepada teman sepulang liburan adalah Cenderamata / Oleh-oleh (기념품).", romaji: "" },
      { id: 'n_r250', ch: 17, q: "어제 제주도에 도착했습니다. 호텔에 가서 가장 먼저 가방을 열고 _______________.", a: ["짐을 쌌습니다", "짐을 풀었습니다", "표를 샀습니다", "출발했습니다"], c: "짐을 풀었습니다", ex: "Tindakan setelah membuka tas di hotel adalah membongkar barang bawaan (짐을 풀다). Karena kejadiannya kemarin, digunakan bentuk lampau: 짐을 풀었습니다.", romaji: "" }, { id: 'n_r251', ch: 18, q: "가: 투안 씨는 여기까지 어떻게 왔어요?\n나: 저는 회사가 가까워서 걸어왔어요.", a: ["대중교통 이용 방법", "교통수단", "출근 시간", "교통카드 충전"], c: "교통수단", ex: "Membicarakan cara datang (naik apa) merujuk pada 'Sarana transportasi'.", romaji: "" },
      { id: 'n_r252', ch: 18, q: "다음 단어들은 무엇과 관계가 있습니까? [ 마을버스, 시내버스, 시외버스, 고속버스 ]", a: ["기차", "배", "비행기", "버스"], c: "버스", ex: "Semua variasi tersebut adalah jenis Bus.", romaji: "" },
      { id: 'n_r253', ch: 18, q: "가: 시청에 어떻게 가요?\n나: 버스나 지하철을 타고 가세요.", a: ["시청에 어떻게 가요", "얼마나 걸려요", "뭐가 더 빨라요", "몇 번 버스를 타고 가요"], c: "시청에 어떻게 가요", ex: "Jawaban memberikan instruksi cara pergi ke tempat, jadi pertanyaannya 'Bagaimana cara pergi ke Balai Kota?'.", romaji: "" },
      { id: 'n_r254', ch: 18, q: "가: 회사에서 여기까지 시간이 얼마나 걸려요?\n나: 보통 30분 정도 걸려요.", a: ["1번이나 2번 버스를 타요", "버스나 지하철을 타고 와요", "보통 30분 정도 걸려요", "회사가 가까워서 걸어왔어요"], c: "보통 30분 정도 걸려요", ex: "Menjawab durasi waktu '얼마나 걸려요' dengan '30 menit'.", romaji: "" },
      { id: 'n_r255', ch: 18, q: "오늘은 월요일입니다. 출근 시간입니다. 그래서 길이 많이 막힙니다.", a: ["하지만", "그래서", "그리고", "그러면"], c: "그래서", ex: "Senin pagi adalah jam sibuk, maka akibatnya macet. Kata sambung sebab-akibat: 그래서.", romaji: "" },
      { id: 'n_r256', ch: 18, q: "평소에는 버스가 빠릅니다. 하지만 출퇴근 시간에는 지하철이 더 빠릅니다.", a: ["그래서", "그러면", "하지만", "그리고"], c: "하지만", ex: "Ada pertentangan kondisi antara hari biasa dan jam sibuk, maka pakai '하지만'.", romaji: "" },
      { id: 'n_r257', ch: 18, q: "'-아/어 보다'를 맞게 사용한 문장은?", a: ["저는 아침에 빵이나 김밥을 먹어요.", "금요일나 토요일에 만날까요?", "수박이나 딸기나를 좋아해요.", "버스이나 택시를 타고 가세요."], c: "저는 아침에 빵이나 김밥을 먹어요.", ex: "Pilihan A benar karena '빵' (konsonan) ditambah '이나' menjadi '빵이나'.", romaji: "" },
      { id: 'n_r258', ch: 18, q: "'에서 ~ 까지'를 바르게 사용한 문장은?", a: ["집에서 회사까지 걸어왔어요.", "집까지 회사에서 걸어갔어요.", "서울에서 부산에서 KTX를 탔어요.", "공항까지 호텔까지 택시를 탑니다."], c: "집에서 회사까지 걸어왔어요.", ex: "Pola [Titik A]에서 [Titik B]까지 digunakan untuk menunjukkan jarak.", romaji: "" },
      { id: 'n_r259', ch: 18, q: "가: 교통카드는 어디에서 사요?\n나: 교통카드는 지하철역이나 편의점에서 살 수 있어요.", a: ["교통카드를 어떻게 충전해요", "지하철역이 어디에 있어요", "교통카드는 지하철역이나 편의점에서 살 수 있어요", "편의점에서 무엇을 팔아요"], c: "교통카드는 지하철역이나 편의점에서 살 수 있어요", ex: "Menjawab tempat pembelian kartu transportasi.", romaji: "" },
      { id: 'n_r260', ch: 18, q: "가: 집에서 회사까지 어떻게 가요?\n나: 저는 비행기나 배를 타고 가요.", a: ["이나", "나", "에서", "까지"], c: "나", ex: "'비행기' berakhiran vokal, jadi ditambah '나'.", romaji: "" },
      { id: 'n_r261', ch: 18, q: "가: 공항에서 호텔까지 거리가 얼마나 돼요?\n나: 택시로 40분 정도 걸려요.", a: ["이나 / 나", "에서 / 까지", "까지 / 에서", "에 / 이나"], c: "에서 / 까지", ex: "Titik awal (bandara) dan tujuan (hotel) menggunakan '에서' dan '까지'.", romaji: "" },
      { id: 'n_r262', ch: 18, q: "저는 오늘 회사가 가까워서 집에서 걸어왔어요.", a: ["걸어왔어요", "타고 왔어요", "환승했어요", "차가 막혔어요"], c: "걸어왔어요", ex: "Karena dekat, tindakan yang paling logis adalah 'berjalan kaki datang' (걸어왔어요).", romaji: "" },
      { id: 'n_r263', ch: 18, q: "가: 지금 버스를 타고 갈까요?\n나: 아니요, 출퇴근 시간에는 차가 많이 막혀요. 지하철을 타세요.", a: ["빨라요", "막혀요", "내려요", "지나요"], c: "막혀요", ex: "Alasan utama menghindari bus saat jam sibuk adalah karena jalanan 'macet' (막혀요).", romaji: "" },
      { id: 'n_r264', ch: 18, q: "지하철역에서 교통카드 충전기를 찾으세요. 그리고 카드를 올려 놓으세요.", a: ["정류장", "매점", "충전기", "현금"], c: "충전기", ex: "Alat untuk meletakkan kartu dan mengisi ulang saldo adalah mesin top-up (충전기).", romaji: "" },
      { id: 'n_r265', ch: 18, q: "가: 아침 먹었어요?\n나: 아니요, 안 먹었어요.", a: ["안 먹어요", "안 먹을래요", "안 먹었어요", "맛없어요"], c: "안 먹었어요", ex: "Karena pertanyaan (먹었어요) bentuk lampau, maka harus dijawab dengan bentuk negatif lampau (안 먹었어요).", romaji: "" },{ id: 'n_r266', ch: 19, q: "가: 오늘 날씨가 참 춥지요?\n나: ________________________.", a: ["아니요, 눈이 와요.", "네, 날씨가 맑아요.", "네, 정말 춥네요.", "아니요, 비가 와요."], c: "네, 정말 춥네요.", ex: "Penanya meminta penegasan menggunakan akhiran '-지요?' (춥지요? / Dingin, kan?). Jawaban konfirmasi persetujuan yang tepat adalah 'Ya, benar-benar dingin' (네, 정말 춥네요).", romaji: "" },
{ id: 'n_r267', ch: 19, q: "가: 인터넷 쇼핑이 어때요?\n나: ________________________.", a: ["값이 싸고 편리해요.", "어렵고 비싸서 안 해요.", "시장에서 옷을 샀어요.", "백화점이 더 싸요."], c: "값이 싸고 편리해요.", ex: "Pertanyaan menanyakan opini seputar belanja online. Sesuai materi teks, keunggulannya digabungkan dengan grammar '-고' menjadi 'Harganya murah dan praktis' (값이 싸고 편리해요).", romaji: "" },
{ id: 'n_r268', ch: 19, q: "다음 사람은 무엇에 대해 이야기하고 있습니까?\n\"제 아이디는 'tuan'입니다. 비밀번호는 '1234'입니다.\"", a: ["전화번호", "인터넷 로그인", "화상 채팅", "날씨"], c: "인터넷 로그인", ex: "Kombinasi data berupa 'ID' and '비밀번호' (Kata sandi) adalah syarat utama yang digunakan untuk proses otentikasi masuk ke akun web (인터넷 로그인).", romaji: "" },
{ id: 'n_r269', ch: 19, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 112, 119, 1345, 114 ]", a: ["이메일 주소", "비밀번호", "휴대전화 배터리", "생활 전화번호"], c: "생활 전화번호", ex: "112 (Polisi), 119 (Kebakaran/Medis), 1345 (Imigrasi), dan 114 (Informasi) disebut sebagai nomor darurat/penting penunjang kehidupan sehari-hari (생활 전화번호).", romaji: "" },
{ id: 'n_r270', ch: 19, q: "인터넷 쇼핑은 물건 값이 쌉니다. ______________ 쇼핑도 아주 편리합니다.", a: ["그러나", "그리고", "하지만", "그러면"], c: "그리고", ex: "Kalimat pertama memberikan informasi keuntungan (harga murah) dan kalimat kedua menambah keuntungan lain (praktis). Konjungsi yang berfungsi menambahkan data setara adalah '그리고' (Dan).", romaji: "" },
{ id: 'n_r271', ch: 19, q: "외국인 등록 번호가 없습니다. ______________ 한국 웹사이트에 회원 가입이 안 됩니다.", a: ["그래서", "그리고", "하지만", "그러나"], c: "그래서", ex: "Gagal mendaftar keanggotaan web merupakan dampak/akibat dari tidak adanya kartu registrasi. Konjungsi sebab-akibat yang bermakna 'Oleh karena itu/Jadi' adalah '그래서'.", romaji: "" },
{ id: 'n_r272', ch: 19, q: "'-지요'를 맞게 사용한 문장은 무엇입니까?", a: ["투안 씨가 베트남 사람지요?", "지금 바쁘다지요?", "오늘 회사에 가지요?", "그 식당이 맛있어지요?"], c: "오늘 회사에 가지요?", ex: "Grammar '-지요' langsung ditempelkan pada akar kata kerja/sifat setelah membuang '다'. '가다' menjadi '가지요' (Pergi, kan?). Pilihan A salah, seharusnya '사람이지요'.", romaji: "" },
{ id: 'n_r273', ch: 19, q: "'-고'를 바르게 사용한 문장은 무엇입니까?", a: ["저는 밥을 먹어고 동생은 빵을 먹어요.", "오늘은 비가 오고 바람이 불어요.", "식당이 맛없고서 안 가요.", "옷이 싸다고 예뻐요."], c: "오늘은 비가 오고 바람이 불어요.", ex: "Grammar penghubung '-고' melekat pada akar kata dasar tanpa perubahan vokal. '오다' menjadi '오고' (Turun hujan dan angin bertiup). Pilihan A salah, seharusnya '먹고'.", romaji: "" },
{ id: 'n_r274', ch: 19, q: "가: 모르는 전화번호가 있으면 114에 전화해서 물어보세요.\n나: 아, 그래요? ________________________.", a: ["114가 뭐예요?", "알려 주셔서 감사합니다.", "회원 가입을 하세요.", "전화를 끊어 주세요."], c: "알려 주셔서 감사합니다.", ex: "A memberikan solusi navigasi nomor telepon. Respons kesopanan umum setelah diberikan informasi/bantuan pengetahuan dari orang lain adalah 'Terima kasih telah memberi tahu' (알려 주셔서 감사합니다).", romaji: "" },
{ id: 'n_r275', ch: 19, q: "가: 김 과장님 좀 바꿔 주세요.\n나: ________________________.", a: ["네, 잠깐만 기다리세요.", "전화를 잘못 거셨어요.", "통화가 끝났어요.", "문자를 확인하세요."], c: "네, 잠깐만 기다리세요.", ex: "A meminta panggilan dialihkan ke Manajer Kim. Jawaban resepsionis/penerima telepon yang paling standar adalah meminta penelpon menunggu: 'Ya, mohon tunggu sebentar' (네, 잠깐만 기다리세요).", romaji: "" },
{ id: 'n_r276', ch: 19, q: "가: 오늘이 수루 씨 생일_______?\n나: 네, 맞아요. 어떻게 알았어요?", a: ["고", "지요", "이고", "이지요"], c: "이지요", ex: "A ingin memastikan kebenaran info mengenai hari ulang tahun Suru. Karena kata benda '생일' diakhiri huruf konsonan (ㄹ), maka grammar penegasan akhiran nomina yang tepat adalah '이지요?'.", romaji: "" },
{ id: 'n_r277', ch: 19, q: "우리 회사는 출퇴근 시간이 정확하_______ 월급도 많이 줍니다.", a: ["지요", "고", "이고", "습니다"], c: "고", ex: "Menggabungkan dua klausa yang setara mengenai kelebihan perusahaan (Waktu tepat [dan] gaji banyak). Kata dasar '정확하다' digabung dengan '-고' menjadi '정확하고'.", romaji: "" },
{ id: 'n_r278', ch: 19, q: "가: 여보세요, 거기 병원이지요?\n나: 아니요, ___________________. 여기는 약국이에요.", a: ["전화를 잘못 거셨어요", "전화를 바꿔 주세요", "통화 중이십니다", "휴대전화를 끄셨어요"], c: "전화를 잘못 거셨어요", ex: "Penanya mengira menelepon rumah sakit, tetapi salah nomor ke apotek. Kalimat sopan untuk menginfokan lawan bicara salah menghubungi nomor adalah '전화를 잘못 거셨어요' (Anda salah sambung).", romaji: "" },
{ id: 'n_r279', ch: 19, q: "작업장에 갑자기 불이 났을 때는 빨리 _______에 전화를 해야 합니다.", a: ["112", "114", "119", "1345"], c: "119", ex: "Layanan darurat terpadu nasional di Korea Selatan untuk penanganan bencana kebakaran (불) serta evakuasi ambulans medis adalah nomor 119.", romaji: "" },
{ id: 'n_r280', ch: 19, q: "가: 여보세요. 리한 씨 휴대전화지요?\n나: 네, 그런데요. ___________________.\n가: 저는 투안이에요. 리한 씨 좀 바꿔 주세요.", a: ["실례지만 누구세요?", "지금 통화 중이십니다.", "문자를 남겨 주세요.", "전화를 끊지 마세요."], c: "실례지만 누구세요?", ex: "Rihan menerima panggilan dari orang yang langsung meminta konfirmasi namanya tanpa mengenalkan diri. Pertanyaan konfirmasi identitas penelpon yang sopan adalah '실례지만 누구세요?' (Maaf, ini dengan siapa?).", romaji: "" },{ id: 'n_r281', ch: 20, q: "두 사람은 무엇에 대해 이야기하고 있습니까?\n가: 방이 너무 더럽네요.\n나: 네, 제가 지금 빗자루로 쓸게요.", a: ["요리 방법", "쓰레기 분리수거", "방 청소", "빨래하기"], c: "방 청소", ex: "A berkata kamar sangat kotor, B menjawab akan menyapunya dengan sapu. Mereka membicarakan 'Membersihkan kamar' (방 청소).", romaji: "" },
{ id: 'n_r282', ch: 20, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 종이류, 빈병류, 플라스틱류 ]", a: ["대형 쓰레기", "음식물 쓰레기", "재활용 쓰레기", "일반 쓰레기"], c: "재활용 쓰레기", ex: "Kertas (종이), botol kosong (빈병), dan plastik (플라스틱) adalah bahan yang bisa didaur ulang (재활용 쓰레기).", romaji: "" },
{ id: 'n_r283', ch: 20, q: "가: 작업장 청소를 해야 하는데 누가 할래요?\n나: ________________________.", a: ["제가 지금 할게요.", "투안 씨가 할게요.", "작업장이 깨끗해요.", "청소기를 돌렸어요."], c: "제가 지금 할게요.", ex: "Tata bahasa '-(으)ㄹ게요' menyatakan kesediaan/janji dari pembicara. Subjeknya wajib orang pertama 'Saya' (제가 지금 할게요).", romaji: "" },
{ id: 'n_r284', ch: 20, q: "가: 투안 씨, 빨래를 다 했어요?\n나: 네, 빨래가 끝났어요. 지금 베란다에 ________________________.", a: ["널게요.", "걷을게요.", "갤게요.", "다릴게요."], c: "널게요.", ex: "Tindakan logis setelah selesai mencuci baju dan membawanya ke luar (balkon/beranda) adalah 'Menjemurnya' (널게요).", romaji: "" },
{ id: 'n_r285', ch: 20, q: "저는 요리하는 것을 별로 안 좋아합니다. ______________ 설거지하는 것은 괜찮습니다.", a: ["그래서", "그리고", "하지만", "그러면"], c: "하지만", ex: "Terdapat pertentangan antara tidak suka memasak dan tidak keberatan mencuci piring. Kata sambung yang tepat adalah '하지만' (Tetapi).", romaji: "" },
{ id: 'n_r286', ch: 20, q: "주말에 친구들이 우리 집에 놀러 옵니다. ______________ 저는 오늘 시장에서 장을 볼 겁니다.", a: ["그러나", "그래서", "하지만", "그리고"], c: "그래서", ex: "Berbelanja adalah akibat (persiapan) dari kedatangan teman di akhir pekan. Kata sambung sebab-akibat adalah '그래서' (Oleh karena itu).", romaji: "" },
{ id: 'n_r287', ch: 20, q: "'-(으)ㄹ게요'를 바르게 사용한 문장은 무엇입니까?", a: ["내일은 지각하지 않을게요.", "수루 씨가 창문을 닦을게요.", "어제 제가 방을 정리할게요.", "날씨가 비가 올게요."], c: "내일은 지각하지 않을게요.", ex: "Tata bahasa '-(으)ㄹ게요' hanya boleh dipakai untuk SUBJEK ORANG PERTAMA (Saya/Kami) untuk rencana masa depan. A adalah satu-satunya kalimat yang memenuhi syarat.", romaji: "" },
{ id: 'n_r288', ch: 20, q: "'-는 것'을 틀리게 사용한 문장은 무엇입니까?", a: ["저는 옷을 다리는 것이 재미있어요.", "리한 씨는 요리하는 것을 싫어해요.", "창문을 닦는 것을 아주 힘들어요.", "제 취미는 음식을 만드는 것입니다."], c: "창문을 닦는 것을 아주 힘들어요.", ex: "Pada opsi C, karena menjelaskan sifat (힘들다 - sulit), maka 'mengelap jendela' berkedudukan sebagai SUBJEK, seharusnya menggunakan partikel '이/가' (닦는 것이).", romaji: "" },
{ id: 'n_r289', ch: 20, q: "가: 쓰레기봉투는 어디에서 사야 해요?\n나: ________________________.", a: ["정해진 장소에 버려야 해요.", "가까운 슈퍼마켓에서 살 수 있어요.", "물기를 빼고 버릴게요.", "쓰레기를 분리해서 버리세요."], c: "가까운 슈퍼마켓에서 살 수 있어요.", ex: "A menanyakan lokasi pembelian kantong sampah. Jawaban yang tepat menunjukkan lokasi: 'Bisa dibeli di supermarket terdekat'.", romaji: "" },
{ id: 'n_r290', ch: 20, q: "가: 투안 씨, 회의실이 너무 지저분하네요.\n나: 죄송합니다. 제가 지금 바로 ____________________.", a: ["치울게요", "치우는 것이에요", "치웠어요", "안 치울래요"], c: "치울게요", ex: "A menegur ruang kotor. B minta maaf dan berjanji akan segera membereskannya. Janji untuk diri sendiri adalah menggunakan '-(으)ㄹ게요' (치울게요).", romaji: "" },
{ id: 'n_r291', ch: 20, q: "한국에서는 일반 쓰레기와 음식물 쓰레기를 같은 봉투에 담아서 버리면 안 됩니다. 반드시 _______________ 버려야 합니다.", a: ["몰래", "함께", "따로", "일찍"], c: "따로", ex: "Lawan dari membuang bersama-sama dalam satu kantong (같은 봉투) adalah membuang secara 'Terpisah' (따로).", romaji: "" },
{ id: 'n_r292', ch: 20, q: "가방이나 책상 같은 대형 쓰레기를 버릴 때는 주민자치센터에서 _______________을/를 사서 붙여야 합니다.", a: ["영수증", "스티커", "우표", "세제"], c: "스티커", ex: "Benda yang dibeli di balai warga dan harus ditempel pada sampah besar (대형 쓰레기) sebelum dibuang adalah Stiker (스티커).", romaji: "" },
{ id: 'n_r293', ch: 20, q: "가: 저녁 먹고 나서 누가 설거지할래요?\n나: 제가 음식을 ____________________.", a: ["만들어서 설거지를 할게요", "만들었으니까 설거지를 해 주세요", "만드는 것이 너무 어려워요", "만들고 설거지를 할게요"], c: "만들었으니까 설거지를 해 주세요", ex: "Mencari kesepakatan pembagian tugas. Alasan paling logis: 'Karena saya yang sudah memasak (membuat makanan), tolong Anda yang cuci piring ya'.", romaji: "" },
{ id: 'n_r294', ch: 20, q: "다 쓴 건전지나 형광등은 일반 쓰레기통에 버리지 말고 _______________ 수거함에 넣어야 합니다.", a: ["전용", "헌 옷", "음식물", "무료"], c: "전용", ex: "Batu baterai atau lampu neon dibuang ke kotak pengumpulan 'khusus' (전용).", romaji: "" },
{ id: 'n_r295', ch: 20, q: "가: 밖을 보니까 비가 너무 많이 와요!\n나: 어머, 옥상에 널어놓은 빨래를 빨리 ____________________!", a: ["걷어야겠어요", "널어야겠어요", "빨아야겠어요", "개야겠어요"], c: "걷어야겠어요", ex: "Tindakan logis dan refleks saat tiba-tiba hujan agar jemuran di atap tidak basah adalah segera mengangkat jemuran (걷어야겠어요).", romaji: "" },// ==========================================
// BAB 21: BAGAIMANA KALAU SAYA BANTU MENATA MEJANYA?
// ==========================================
{ id: 'n_r296', ch: 21, q: "가: 제가 선물을 준비할까요?\n나: 네, 수미 씨가 선물을 _________________.", a: ["사세요", "샀어요", "어겼어요", "치우세요"], c: "사세요", ex: "Jawaban setuju untuk menyiapkan hadiah (membeli) dalam bentuk perintah sopan adalah '사세요' (Silakan beli/siapkan).", romaji: "" },
{ id: 'n_r297', ch: 21, q: "가: 투안 씨, 시간이 있으면 이것 좀 가르쳐 줄 수 있어요?\n나: 지금은 좀 _________________ 잠시만 기다려 주세요.", a: ["바쁜데", "바쁘고", "바쁘지만", "바빠서"], c: "바쁜데", ex: "Tata bahasa '-는데' digunakan untuk menyatakan situasi/latar belakang sebelum memberikan instruksi (saya sibuk, jadi harap tunggu).", romaji: "" },
{ id: 'n_r298', ch: 21, q: "무엇에 대해 이야기하고 있습니까?\n\"결혼을 하거나 이사를 한 후에 친구들을 집에 초대하고 음식을 장만합니다.\"", a: ["집들이", "회사 생활", "영화 예매", "한국어 공부"], c: "집들이", ex: "Syukuran mengundang teman setelah pindah rumah disebut 집들이 (Syukuran pindah rumah).", romaji: "" },
{ id: 'n_r299', ch: 21, q: "Apa hubungan kata berikut?\n[ 시간 지키기, 미리 전화하기, 늦게 도착하지 않기 ]", a: ["선물", "약속", "식당", "청소"], c: "약속", ex: "Semua adalah etika yang berhubungan erat dengan janji (약속).", romaji: "" },
{ id: 'n_r300', ch: 21, q: "세제는 좋은 일이 많이 생기고 부자가 되라는 의미가 있습니다. _________________ 휴지는 일이 잘 풀리라는 의미가 있습니다.", a: ["그래서", "그리고", "하지만", "그러면"], c: "그리고", ex: "Kedua kalimat menambahkan informasi positif yang setara. Maka kata sambung yang tepat adalah '그리고' (Dan).", romaji: "" },
{ id: 'n_r301', ch: 21, q: "내일 오후 3시에 사무실을 방문하고 싶습니다. _________________ 내일 3시에는 다른 약속이 있습니다.", a: ["그리고", "그래서", "하지만", "그러면"], c: "하지만", ex: "Keinginan berkunjung bertentangan dengan fakta sudah ada janji lain. Maka kata sambungnya adalah '하지만' (Akan tetapi).", romaji: "" },
{ id: 'n_r302', ch: 21, q: "'-(으)ㄹ까요'를 바르게 사용한 문장은?", a: ["제가 창문을 닫을까요?", "제가 선물을 준비할을까요?", "제가 상을 차릴을까요?", "제가 마중 나갈을까요?"], c: "제가 창문을 닫을까요?", ex: "Kata kerja konsonan '닫다' menjadi '닫을까요'. Sisanya salah imbuhan.", romaji: "" },
{ id: 'n_r303', ch: 21, q: "'-는데/-(으)ㄴ데'를 바르게 사용한 문장은?", a: ["지금 바쁘다는데 잠시만 기다려 주세요.", "오늘 날씨가 좋은데 우리 놀러 갈까요?", "내일 약속이 없는은데 만날 수 있어요?", "밖이 춥은데 옷을 따뜻하게 입으세요."], c: "오늘 날씨가 좋은데 우리 놀러 갈까요?", ex: "Kata sifat '좋다' menjadi '좋은데'. Pilihan lain salah imbuhan.", romaji: "" },
{ id: 'n_r304', ch: 21, q: "가: 상 차리는 것을 좀 도와줄까요?\n나: ________________________.", a: ["아니에요. 다 됐어요.", "네, 금방 찾았어요.", "아니요. 제가 약속을 어겼어요.", "네, 집들이 선물이에요."], c: "아니에요. 다 됐어요.", ex: "Respons sopan menolak tawaran bantuan karena pekerjaan sudah selesai adalah '아니에요. 다 됐어요'.", romaji: "" },
{ id: 'n_r305', ch: 21, q: "반장님, 저희 집 집들이에 _________________ 주셔서 정말 감사합니다.", a: ["방문해", "초대해", "약속해", "어겨"], c: "초대해", ex: "Terima kasih karena sudah mengundang (초대해 주셔서 감사합니다).", romaji: "" },
{ id: 'n_r306', ch: 21, q: "한국 사람들은 보통 다른 사람의 집을 _________________ 때 선물을 가지고 갑니다.", a: ["방문할", "마중할", "배웅할", "잃어버릴"], c: "방문할", ex: "Ketika berkunjung (방문할) ke rumah orang lain, orang Korea membawa hadiah.", romaji: "" },
{ id: 'n_r307', ch: 21, q: "약속에 늦거나 지키지 못할 때는 미리 전화를 _________________.", a: ["받아야 합니다", "해야 합니다", "끊어야 합니다", "바꿔야 합니다"], c: "해야 합니다", ex: "Jika terlambat, kita harus melakukan panggilan telepon (전화를 해야 합니다).", romaji: "" },
{ id: 'n_r308', ch: 21, q: "가: 집 찾기가 어렵지 않았어요?\n나: _________________. 금방 찾았어요.", a: ["네, 어려웠어요", "아니에요", "고마워요", "미안해요"], c: "아니에요", ex: "Karena B berhasil menemukan rumah dengan cepat (금방 찾았어요), maka jawabannya menyangkal kesulitan (아니에요).", romaji: "" },
{ id: 'n_r309', ch: 21, q: "가: 저녁 먹고 나서 누가 설거지할래요?\n나: 제가 음식을 ____________________.", a: ["만들어서 설거지를 할게요", "만들었으니까 설거지를 해 주세요", "만드는 것이 너무 어려워요", "만들고 설거지를 할게요"], c: "만들었으니까 설거지를 해 주세요", ex: "Kesepakatan: Karena saya sudah memasak, Anda tolong cuci piring (만들었으니까... 해 주세요).", romaji: "" },
{ id: 'n_r310', ch: 21, q: "가: 여보세요. 거기 병원이지요?\n나: 아니요, ___________________. 여기는 약국이에요.", a: ["전화를 잘못 거셨어요", "전화를 바꿔 주세요", "통화 중이십니다", "휴대전화를 끄셨어요"], c: "전화를 잘못 거셨어요", ex: "Kalimat standar untuk memberitahu lawan bicara salah nomor adalah '전화를 잘못 거셨어요'.", romaji: "" },{ id: 'n_r311', ch: 22, q: "두 사람은 무엇에 대해 이야기하고 있습니까?\n가: 방이 너무 더럽네요.\n나: 네, 제가 지금 빗자루로 쓸게요.", a: ["요리 방법", "쓰레기 분리수거", "방 청소", "빨래하기"], c: "방 청소", ex: "Membicarakan 'Membersihkan kamar' (방 청소).", romaji: "" },
{ id: 'n_r312', ch: 22, q: "Apa hubungan kata berikut?\n[ 종이류, 빈병류, 플라스틱류 ]", a: ["대형 쓰레기", "음식물 쓰레기", "재활용 쓰레기", "일반 쓰레기"], c: "재활용 쓰레기", ex: "Kertas, botol, plastik adalah bahan daur ulang (재활용 쓰레기).", romaji: "" },
{ id: 'n_r313', ch: 22, q: "가: 버스 정류장에서 담배를 피워도 돼요?\n나: 아니요, 버스 정류장은 금연 구역이니까 ________________________.", a: ["담배를 피우면 안 돼요", "담배를 사면 안 돼요", "밖에서 피워도 돼요", "담배를 버리면 안 돼요"], c: "담배를 피우면 안 돼요", ex: "Larangan merokok di area bebas rokok: 'Tidak boleh merokok' (담배를 피우면 안 돼요).", romaji: "" },
{ id: 'n_r314', ch: 22, q: "가: 여기에서 차를 세워도 돼요?\n나: 저기 주차 금지 표지판이 ________________________.", a: ["있으니까 주차하면 안 돼요", "없으니까 차를 세우면 안 돼요", "있으니까 빨리 주차하세요", "없으니까 주차장에 가세요"], c: "있으니까 주차하면 안 돼요", ex: "Alasan dilarang parkir adalah rambu (있으니까 주차하면 안 돼요).", romaji: "" },
{ id: 'n_r315', ch: 22, q: "저는 어제 늦잠을 _________________ 회사에 지각했어요.", a: ["자다가", "자니까", "자면", "자도"], c: "자다가", ex: "Kejadian kurang baik saat melakukan sesuatu menggunakan '-다가' (자다가).", romaji: "" },
{ id: 'n_r316', ch: 22, q: "비빔밥은 _________________ 불고기를 먹읍시다.", a: ["매워서", "매우니까", "맵다가", "매우면"], c: "매우니까", ex: "Karena kalimat belakang ajakan (-읍시다), maka pakai '-(으)니까'.", romaji: "" },
{ id: 'n_r317', ch: 22, q: "'-(으)면 안 되다'를 바르게 사용한 문장은?", a: ["극장 안에서 전화를 하면 안 돼요.", "미술관에서 사진을 찍면 안 돼요.", "잔디밭에 들어가면 안이 돼요.", "길에 침을 뱉으면 안을 돼요."], c: "극장 안에서 전화를 하면 안 돼요.", ex: "Aturan grammar '-면 안 되다'.", romaji: "" },
{ id: 'n_r318', ch: 22, q: "'-(으)니까'를 틀리게 사용한 문장은?", a: ["날씨가 좋으니까 밖으로 나갈까요?", "지금 차가 막히니까 지하철을 타세요.", "내일은 주말이니까 같이 영화를 봅시다.", "배가 너무 아프니까 병원에 갔어요."], c: "배가 너무 아프니까 병원에 갔어요.", ex: "Fakta lampau lebih tepat pakai '-아서/어서'.", romaji: "" },
{ id: 'n_r319', ch: 22, q: "가: 모니카 씨, 여기에서 길을 건너면 안 돼요.\n나: 차도 _________________ 뭐 어때요? 빨리 건너가요.", a: ["없는데", "많으니까", "막히는데", "세우니까"], c: "없는데", ex: "Situasi tidak ada mobil (차도 없는데).", romaji: "" },
{ id: 'n_r320', ch: 22, q: "사람들이 지하철을 타려고 줄을 서 있습니다. 이때 _________________ 안 됩니다. 뒤로 가서 줄을 서야 합니다.", a: ["침을 뱉으면", "새치기를 하면", "담배를 피우면", "자리를 차지하면"], c: "새치기를 하면", ex: "Larangan menyela antrean (새치기를 하면).", romaji: "" },
{ id: 'n_r321', ch: 22, q: "지하철이나 버스의 _________________은/는 할아버지, 할머니, 임산부를 위한 자리입니다.", a: ["비상구", "화장실", "에스컬레이터", "노약자석"], c: "노약자석", ex: "Tempat duduk prioritas adalah 노약자석.", romaji: "" },
{ id: 'n_r322', ch: 22, q: "미술관 안에서는 그림을 눈으로만 봐야 합니다. 그림에 손을 _________________ 안 됩니다.", a: ["대도", "대면", "대니까", "대다가"], c: "대면", ex: "Larangan menyentuh (손을 대면 안 됩니다).", romaji: "" },
{ id: 'n_r323', ch: 22, q: "가: 저기요, 극장 안으로 음식물을 가지고 들어가면 안 됩니다.\n나: 아, 몰랐어요. _________________.", a: ["안으로 들어갈게요", "사진을 찍을게요", "죄송합니다. 밖에 버릴게요", "금연 구역이니까 밖에서 피울게요"], c: "죄송합니다. 밖에 버릴게요", ex: "Respons sopan saat ditegur.", romaji: "" },
{ id: 'n_r324', ch: 22, q: "에스컬레이터에서는 넘어질 수 있으니까 _________________ 안 됩니다. 손잡이를 꼭 잡고 타세요.", a: ["떠들면", "뛰어다닌", "자리를 차지하면", "다리를 벌리면"], c: "뛰어다니면", ex: "Larangan berlari-lari di eskalator (뛰어다니면).", romaji: "" },
{ id: 'n_r325', ch: 22, q: "가: 투안 씨도 앞으로 조심하세요. 얼마 전에 제 친구도 _________________ 다쳤어요.\n나: 정말요? 저는 횡단보도가 멀어서 그냥 길을 건넜는데….", a: ["안전하게 건너다가", "횡단보도로 가다가", "무단 횡단을 하다가", "차를 세우다가"], c: "무단 횡단을 하다가", ex: "Penyebab cedera adalah menyeberang sembarangan (무단 횡단을 하다가).", romaji: "" },{ id: 'n_r326', ch: 23, q: "다음 단어들은 무엇과 관계가 있습니까? [ 밥그릇을 들고 먹다, 밥에 숟가락을 꽂다, 소리를 크게 내다 ]", a: ["식사 예절 (하면 안 되는 행동)", "지하철 예절", "인사 예절", "물건을 주는 예절"], c: "식사 예절 (하면 안 되는 행동)", ex: "Mengangkat mangkuk saat makan, menancapkan sendok ke nasi, dan mengeluarkan suara keras semuanya berhubungan dengan pelanggaran 'Etika Makan'.", romaji: "" },
{ id: 'n_r327', ch: 23, q: "다음 단어들은 무엇과 관계가 있습니까? [ 편찮으시다, 돌아가시다, 연세, 성함, 댁 ]", a: ["공공장소", "집들이 선물", "어휘 높임 (높임말)", "교통수단"], c: "어휘 높임 (높임말)", ex: "편찮으시다 (sakit), 돌아가시다 (meninggal), 연세 (umur), 성함 (nama), 댁 (rumah) adalah kelompok kata khusus yang digunakan untuk menghormati orang yang lebih tua.", romaji: "" },
{ id: 'n_r328', ch: 23, q: "가: 할아버지, _________________이/가 어떻게 되세요? 나: 올해 일흔다섯 살이에요.", a: ["성함", "연세", "댁", "생신"], c: "연세", ex: "Karena jawabannya adalah angka umur, kata tanya yang tepat dan sopan untuk menanyakan umur adalah '연세'.", romaji: "" },
{ id: 'n_r329', ch: 23, q: "가: 사장님 지금 안에 _________________? 나: 아니요, 조금 전에 밖으로 나가셨어요.", a: ["있으세요", "계세요", "자세요", "주무세요"], c: "계세요", ex: "Bentuk hormat dari kata '있다' (ada/tinggal) adalah '계시다'. Ditambah akhiran -아요/어요 menjadi '계세요?'.", romaji: "" },
{ id: 'n_r330', ch: 23, q: "한국에서는 어른에게 높임말을 써야 합니다. _________________ 어른 앞에서는 예의를 잘 지켜야 합니다.", a: ["하지만", "그래서", "그리고", "그러나"], c: "그리고", ex: "Kedua kalimat ini menambahkan informasi yang setara. Kata sambung penambahan adalah '그리고' (Dan).", romaji: "" },
{ id: 'n_r331', ch: 23, q: "베트남에서는 밥그릇을 들고 밥을 먹습니다. _________________ 한국에서는 식탁에 밥그릇을 놓고 먹어야 합니다.", a: ["하지만", "그래서", "그리고", "그러면"], c: "하지만", ex: "Terdapat pertentangan budaya antara Vietnam dan Korea. Kata sambung pertentangan adalah '하지만'.", romaji: "" },
{ id: 'n_r332', ch: 23, q: "'-(으)시-'를 맞게 사용한 문장은 무엇입니까?", a: ["할아버지는 매일 아침 신문을 읽으세요.", "아버지는 지금 거실에서 잡수세요.", "사장님은 고향에 살으세요.", "어머니는 오늘 많이 바쁘으세요."], c: "할아버지는 매일 아침 신문을 읽으세요.", ex: "A: 읽다 (konsonan) + 으시 + 어요 = 읽으세요 (Benar).", romaji: "" },
{ id: 'n_r333', ch: 23, q: "'-아야/어야 되다(하다)'를 바르게 사용한 문장은 무엇입니까?", a: ["지하철에서는 자리를 양보해야 해요.", "어른께는 두 손으로 물건을 드려아야 해요.", "집 안에는 신발을 벗고 들어가어야 해요.", "밥을 먹을 때는 조용히 먹어야 해요."], c: "지하철에서는 자리를 양보해야 해요.", ex: "양보하다 (하다) -> 해야 해요 (Benar).", romaji: "" },
{ id: 'n_r334', ch: 23, q: "가: 한국에서 어른께 물건을 드릴 때 어떻게 해야 돼요? 나: 물건을 ____________________.", a: ["한 손으로 주면 안 돼요", "두 손으로 드려야 돼요", "허리를 숙여야 돼요", "고개를 돌려야 돼요"], c: "두 손으로 드려야 돼요", ex: "Jawaban yang paling tepat dan menggunakan tata bahasa kewajiban adalah 'Harus memberikannya dengan dua tangan'.", romaji: "" },
{ id: 'n_r335', ch: 23, q: "식사할 때 밥에 숟가락을 꽂으면 안 됩니다. 그리고 밥을 먹을 때 소리를 크게 ____________________.", a: ["내야 됩니다", "내지 마세요", "낼 수 없습니다", "내고 싶어요"], c: "내지 마세요", ex: "Bentuk larangan ajakan/perintah di kalimat kedua sesuai dengan dialog bab 23 adalah '내지 마세요' (jangan keluarkan).", romaji: "" },
{ id: 'n_r336', ch: 23, q: "한국 사람의 집에 갈 때 무엇을 조심해야 돼요? 반드시 신발을 _________________ 들어가야 해요.", a: ["신고", "벗고", "사고", "버리고"], c: "벗고", ex: "Kata kerja melepas sepatu adalah 신발을 벗다. Menjadi 벗고.", romaji: "" },
{ id: 'n_r337', ch: 23, q: "어른과 함께 술을 마실 때는 조심해야 합니다. 어른 앞에서는 _________________ 술을 마셔야 합니다.", a: ["고개를 돌리고", "다리를 꼬고", "허리를 숙이고", "두 손으로"], c: "고개를 돌리고", ex: "Etika minum di depan orang tua adalah 고개를 돌리다 (memalingkan wajah).", romaji: "" },
{ id: 'n_r338', ch: 23, q: "가: 투안 씨의 부모님은 고향에 살아요? 나: 네, 고향에 _________________.", a: ["사세요", "계세요", "살으세요", "살아요"], c: "사세요", ex: "Subjeknya adalah 부모님, kata '살다' harus diubah ke bentuk hormat. 살다 -> 사시 + 어요 = 사세요.", romaji: "" },
{ id: 'n_r339', ch: 23, q: "가: 가족이 어떻게 돼요? 나: 어머니하고 동생, 저 3명이에요. 아버지는 3년 전에 _________________.", a: ["돌아가셨어요", "주무셨어요", "편찮으셨어요", "계셨어요"], c: "돌아가셨어요", ex: "Bentuk hormat dari meninggal dunia (죽다) adalah 돌아가시다. Lampau menjadi 돌아가셨어요.", romaji: "" },
{ id: 'n_r340', ch: 23, q: "가: 한국에서 밥을 먹을 때 밥그릇을 들고 먹어도 돼요? 나: 아니요, _________________. 식탁 위에 놓고 먹어야 돼요.", a: ["들고 먹으면 안 돼요", "놓고 먹지 마세요", "조용히 먹어야 돼요", "숟가락을 꽂으면 안 돼요"], c: "들고 먹으면 안 돼요", ex: "Melarang tindakan angkat mangkuk adalah '들고 먹으면 안 돼요'.", romaji: "" },{ id: 'n_r341', ch: 24, q: "다음 단어들은 무엇과 관계가 있습니까? [ 한국어 과정, 컴퓨터 교육 과정, 태권도 교육 과정 ]", a: ["직업", "교육 과목", "기차 시간표", "청소 도구"], c: "교육 과목", ex: "Program-program tersebut adalah jenis mata pelajaran atau program pendidikan (교육 과목).", romaji: "" },
{ id: 'n_r342', ch: 24, q: "다음 단어들은 무엇과 관계가 있습니까? [ 개강, 종강, 수업 시간 ]", a: ["집들이 선물", "공공장소 규칙", "교육 일정", "자격증 종류"], c: "교육 일정", ex: "Mulai kelas, akhir kelas, dan waktu pelajaran berkaitan dengan jadwal pendidikan (교육 일정).", romaji: "" },
{ id: 'n_r343', ch: 24, q: "가: 인디카 씨, 어제 저녁에 뭐 했어요? 나: 친구하고 밥을 _________________ 이야기했어요.", a: ["먹다가", "먹으니까", "먹으면서", "먹기 쉬워서"], c: "먹으면서", ex: "Dua kejadian bersamaan menggunakan '-(으)면서'. Makan (먹다) menjadi 먹으면서.", romaji: "" },
{ id: 'n_r344', ch: 24, q: "가: 한국어 공부를 하고 싶은데 어떤 책이 좋아요? 나: 이 책을 보세요. 이 책은 재미있어서 _________________.", a: ["공부하기 어려워요", "공부하면서 들어요", "학원에 다녀야 해요", "공부하기 쉬워요"], c: "공부하기 쉬워요", ex: "Menyatakan kemudahan melakukan sesuatu menggunakan tata bahasa -기 쉽다.", romaji: "" },
{ id: 'n_r345', ch: 24, q: "저는 매일 아침부터 저녁까지 회사에서 일을 합니다. _________________ 일이 끝나면 한국어를 배우러 학원에 갑니다.", a: ["그리고", "하지만", "그러나", "그러면"], c: "그리고", ex: "Kalimat kedua adalah tambahan rutinitas yang setara, maka menggunakan kata sambung '그리고'.", romaji: "" },
{ id: 'n_r346', ch: 24, q: "'-(으)면서'를 바르게 사용한 문장은 무엇입니까?", a: ["저는 영화를 보면서 빵을 먹어요.", "한국 노래를 듣면서 한국어를 공부해요.", "길을 걷으면서 담배를 피우지 마세요.", "사전을 찾으면서고 공부해요."], c: "저는 영화를 보면서 빵을 먹어요.", ex: "Vokal/konsonan 'ㄹ' memakai '-면서', konsonan lain '-으면서'.", romaji: "" },
{ id: 'n_r347', ch: 24, q: "'-기 쉽다/어렵다'를 바르게 사용한 문장은 무엇입니까?", a: ["지금 하는 일은 비슷해서 이해하기 쉬워요.", "이 옷은 단추가 많아서 입기이 불편해요.", "토요일에는 일을 해야 돼서 학원에 다니기이 어려워요.", "이곳은 가게가 많아서 쇼핑하기가 쉽지 않아요."], c: "지금 하는 일은 비슷해서 이해하기 쉬워요.", ex: "Mengubah kata kerja jadi benda '-기' lalu ditambah kata sifat.", romaji: "" },
{ id: 'n_r348', ch: 24, q: "가: 모니카 씨는 어떻게 공부해요? 나: 저는 모르는 단어는 _________________ 공부해요.", a: ["사전을 찾으면서", "학원에 다니면서", "예습하기 어려워서", "자격증을 따기 쉬워서"], c: "사전을 찾으면서", ex: "Belajar sambil mencari kata di kamus adalah '사전을 찾으면서'.", romaji: "" },
{ id: 'n_r349', ch: 24, q: "가: 수피카 씨는 학원에 다녀요? 나: 아니요. 저는 영화 보는 것을 좋아해서 한국 영화를 _________________ 공부해요.", a: ["보면서", "듣기 쉬워서", "복습하면서", "만들면서"], c: "보면서", ex: "Kata kerja untuk menonton film adalah 보다. Menjadi 보면서 (sambil menonton).", romaji: "" },
{ id: 'n_r350', ch: 24, q: "가: 한국어 수업을 듣고 싶은데 언제 시작해요? 나: 다음 주 월요일에 시작해요. 다음 주 월요일이 _________________이에요.", a: ["종강", "과정", "개강", "과목"], c: "개강", ex: "Hari dimulainya sebuah kelas/semester disebut '개강' (gaegang).", romaji: "" },
{ id: 'n_r351', ch: 24, q: "자동차를 수리하는 공장에서 일하고 싶어서 _________________ 자격증을 따려고 합니다.", a: ["요리사", "정비사", "미용사", "상담사"], c: "정비사", ex: "Profesi yang mereparasi mobil adalah Teknisi/Montir (정비사).", romaji: "" },
{ id: 'n_r352', ch: 24, q: "가: 외국인센터의 한국어 수업료는 얼마예요? 돈을 내야 돼요? 나: 아니요, 돈을 내지 않아도 돼요. _________________예요.", a: ["유료", "벌금", "무료", "비싸"], c: "무료", ex: "Kata untuk 'gratis' atau tidak dipungut biaya adalah '무료' (muryo).", romaji: "" },
{ id: 'n_r353', ch: 24, q: "가: 아, 그래요? 자동차 정비 교육은 어떻게 신청해요? 나: _________________에서 신청하면 돼요.", a: ["홈페이지", "운동장", "경찰서", "영화관"], c: "홈페이지", ex: "Cara mendaftar pelatihan biasanya melalui website atau homepage.", romaji: "" },
{ id: 'n_r354', ch: 24, q: "가: 투안 씨, 어디 갔다 와요? 나: 나중에 고향에 돌아가서 일을 구할 때 도움이 될 것 같아서 _________________을/를 받고 왔어요.", a: ["영화", "자동차 정비 교육", "집들이 선물", "한국어 책"], c: "자동차 정비 교육", ex: "Kegiatan yang berguna untuk mencari kerja di kampung halaman adalah pelatihan montir mobil.", romaji: "" },
{ id: 'n_r355', ch: 24, q: "가: 한국어 수업이 끝난 후에 어떻게 공부해요? 나: 오늘 배운 것을 집에 가서 다시 _________________.", a: ["예습해요", "신청해요", "복습해요", "개강해요"], c: "복습해요", ex: "Mengulang kembali pelajaran yang sudah diajarkan adalah '복습하다'.", romaji: "" },// ======================== Papan NORMAL (15 soal) ========================

{ id: 'n_r355', ch: 25, q: "가: 수진 씨는 언제 교회에 가요?\n나: _________________ 가요.", a: ["일요일마다", "일요일부터", "일요일이나", "일요일까지"], c: "일요일마다", ex: "Penanya bertanya kapan Sujin pergi ke gereja. Tata bahasa untuk menyatakan rutinitas waktu adalah '마다' (Setiap). 'Saya pergi [setiap hari Minggu].' Menjadi 일요일마다 가요.", romaji: "" },
{ id: 'n_r356', ch: 25, q: "가: 아버지가 좀 편찮으세요.\n나: 빨리 _________________ 좋겠어요.", a: ["아팠으면", "좋아지셨으면", "돌아가셨으면", "다치셨으면"], c: "좋아지셨으면", ex: "A berkata bahwa ayahnya sedang sakit. B memberikan simpati dan harapan menggunakan tata bahasa '-았/었으면 좋겠다' (Semoga/Berharap). Harapan yang baik untuk orang sakit adalah 'Semoga cepat membaik (sembuh)' atau 빨리 좋아지셨으면 좋겠어요.", romaji: "" },
{ id: 'n_r357', ch: 25, q: "다음 사람들은 무엇과 관계가 있습니까?\n[ 스님, 신부님, 목사님, 이맘 ]", a: ["종교인 (성직자)", "종교 행사", "종교 책", "종교 건물"], c: "종교인 (성직자)", ex: "Biksu, Pastor, Pendeta, dan Imam semuanya adalah sebutan untuk para 'Pemuka Agama / Tokoh Agama' (종교인 / 성직자). B berarti Festival, C Buku, D Bangunan.", romaji: "" },
{ id: 'n_r358', ch: 25, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 성경, 불경, 코란 ]", a: ["종교 책 (경전)", "종교 건물", "종교인", "종교 활동"], c: "종교 책 (경전)", ex: "Alkitab (성경), Tripitaka (불경), dan Alquran (코란) semuanya adalah nama-nama 'Kitab Suci / Buku Agama' (종교 책 / 경전).", romaji: "" },
{ id: 'n_r359', ch: 25, q: "부모님이 불교 신자입니다. _________________ 저도 어릴 때는 절에 다녔습니다.", a: ["그러나", "그래서", "하지만", "그러면"], c: "그래서", ex: "Kalimat pertama: 'Orang tua saya adalah penganut Buddha.' Kalimat kedua: 'Saya pun saat kecil beribadah ke kuil.' Karena kalimat pertama adalah alasan/sebab (karena orang tua Buddha), maka akibatnya anak ikut ke kuil. Kata sambung sebab-akibat yang tepat adalah '그래서' (Jadi/Oleh karena itu).", romaji: "" },
{ id: 'n_r360', ch: 25, q: "어릴 때는 절에 다녔어요. _________________ 요즘은 바빠서 잘 안 가요.", a: ["그래서", "그런데 (하지만)", "그러면", "그리고"], c: "그런데 (하지만)", ex: "Kalimat pertama mengatakan dulu sering pergi ke kuil. Kalimat kedua mengatakan sekarang jarang pergi. Karena terdapat pertentangan (dulu pergi vs sekarang tidak), kata sambung yang tepat adalah '그런데 / 하지만' (Tetapi / Namun).", romaji: "" },
{ id: 'n_r361', ch: 25, q: "'마다'를 바르게 사용한 문장은 무엇입니까?", a: ["저는 주말마다 공원에서 자전거를 타요.", "내일마다 비가 많이 와서 우산이 필요해요.", "어제마다 도서관에서 한국어를 공부했어요.", "지금마다 커피를 한 잔 마셨으면 좋겠어요."], c: "저는 주말마다 공원에서 자전거를 타요.", ex: "'마다' (Setiap) dilekatkan pada kata benda yang menyatakan waktu/periode yang berulang.\nA: 주말마다 (Setiap akhir pekan) - Benar.\nB: 내일마다 (Setiap besok) - Salah secara logika, seharusnya 매일 (setiap hari).\nC & D: 어제마다, 지금마다 - Salah secara logika gramatikal.", romaji: "" },
{ id: 'n_r362', ch: 25, q: "'-았/었으면 좋겠다'를 바르게 사용한 문장은 무엇입니까?", a: ["주말에는 날씨가 좋았으면 좋겠어요.", "계속 비가 오었으면 좋겠어요.", "빨리 고향에 돌아가았으면 좋겠어요.", "우리 가족이 항상 건강하았으면 좋겠어요."], c: "주말에는 날씨가 좋았으면 좋겠어요.", ex: "Aturan '-았/었으면 좋겠다': Vokal ㅏ, ㅗ pakai 았. Vokal lain pakai 었. 하다 menjadi 했.\nA: 좋다 -> 좋았으면 좋겠어요 (Benar).\nB: 오다 -> 왔으면 좋겠어요 (Bukan 오었으면).\nC: 돌아가다 -> 돌아갔으면 좋겠어요 (Bukan 가았으면).\nD: 건강하다 -> 건강했으면 좋겠어요 (Bukan 하았으면).", romaji: "" },
{ id: 'n_r363', ch: 25, q: "가: 150번 버스가 자주 와요?\n나: 네, 5분_________________ 와요.", a: ["쯤", "마다", "에", "까지"], c: "마다", ex: "A bertanya apakah bus sering datang. B menjawab, 'Ya, datang [setiap] 5 menit.' Kata untuk 'setiap' yang menunjukkan siklus berulang adalah '마다'. Menjadi 5분마다 와요.", romaji: "" },
{ id: 'n_r364', ch: 25, q: "석가탄신일이 가까워지면 불교 신자들은 집이나 절에서 _________________을/를 만들어서 나무에 매답니다.", a: ["달걀", "트리", "등", "카드"], c: "등", ex: "'Menjelang Hari Kelahiran Buddha (석가탄신일), penganut Buddha membuat [Lampion] dan menggantungkannya di pohon.' Lampion/Lentera dalam bahasa Korea adalah '등' (deung).", romaji: "" },
{ id: 'n_r365', ch: 25, q: "천주교나 기독교 신자들은 부활절에 예쁜 그림을 그린 _________________을/를 서로 나누어 먹습니다.", a: ["달걀", "고기", "비빔밥", "등"], c: "달걀", ex: "'Pada hari Paskah (부활절), penganut Katolik dan Kristen saling membagikan dan memakan [Telur] yang telah digambar dengan cantik.' Telur adalah '달걀' (dalgyal).", romaji: "" },
{ id: 'n_r366', ch: 25, q: "12월이 되면 사람들은 크리스마스트리를 만들고 _________________을/를 주고받습니다.", a: ["코란", "카드", "불경", "달걀"], c: "카드", ex: "'Memasuki bulan Desember, orang-orang membuat pohon natal dan saling memberi dan menerima [Kartu].' Pada hari Natal orang bertukar kartu ucapan (카드).", romaji: "" },
{ id: 'n_r367', ch: 25, q: "라마단은 한 달 동안 해가 떠 있는 낮 시간에는 음식과 물을 먹지 못합니다. 이 기간에는 _________________을/를 해야 합니다.", a: ["절제", "폭식", "여행", "수영"], c: "절제", ex: "'Selama bulan Ramadan, di siang hari saat matahari bersinar tidak boleh makan dan minum. Pada masa ini, kita harus melakukan [Pengendalian diri / Puasa / Berpantang].' Menahan hawa nafsu dan makan dalam teks disebut '절제' (jeolje - mengendalikan diri/berpantang).", romaji: "" },
{ id: 'n_r368', ch: 25, q: "가: 아딧 씨, 오늘 이슬람 사원에 웬일이에요?\n나: 시간이 있을 _________________ 와서 기도해요.", a: ["때마다", "것마다", "수마다", "곳마다"], c: "때마다", ex: "A bertanya ada urusan apa ke masjid. B menjawab: '[Setiap kali] ada waktu, saya datang dan berdoa.' Bentuk grammar 'Setiap (kali/waktu)' yang dilekatkan dengan kata keterangan waktu (을 때) adalah '-(으)ㄹ 때마다' (Setiap saat/Setiap kali).", romaji: "" },
{ id: 'n_r369', ch: 25, q: "가: 리리 씨는 종교가 있어요?\n나: 네, 저는 _________________ 신자예요. 주말마다 성당에 가서 미사를 드려요.", a: ["이슬람교", "기독교", "천주교", "불교"], c: "천주교", ex: "A bertanya apa agama Riri. B berkata bahwa ia setiap akhir pekan pergi ke Gereja Katolik (성당) dan melakukan Misa (미사). Maka sudah pasti ia adalah penganut 'Katolik' (천주교).", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r370', ch: 26, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 소화제, 해열제, 진통제, 감기약 ]", a: ["병원 이름", "가정 비상약", "신체 부위", "아픈 증상"], c: "가정 비상약", ex: "Obat pencernaan (소화제), Obat penurun panas (해열제), Obat pereda nyeri (진통제), dan Obat flu (감기약) semuanya adalah jenis-jenis obat atau 'Obat-obatan Darurat Keluarga/P3K' (가정 비상약).", romaji: "" },
{ id: 'n_r371', ch: 26, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 기침을 하다, 콧물이 나다, 열이 나다 ]", a: ["소화 불량", "다리가 부러지다", "감기 증상", "배탈이 나다"], c: "감기 증상", ex: "Batuk (기침을 하다), Pilek (콧물이 나다), dan Demam (열이 나다) adalah sekumpulan 'Gejala Flu/Masuk Angin' (감기 증상).", romaji: "" },
{ id: 'n_r372', ch: 26, q: "가: 이 약은 어떻게 먹어야 돼요?\n나: 밥을 _________________ 이 약을 드세요.", a: ["먹은 후에", "먹기 전에", "먹으면서", "먹지 마세요"], c: "먹은 후에", ex: "A bertanya cara meminum obat. Sesuai judul dan tata bahasa Bab 26, instruksi umum apoteker adalah 'Minumlah obat ini [Setelah] makan nasi.' Tata bahasa 'Setelah' yang dilekatkan pada kata kerja '먹다' adalah '먹은 후에'.", romaji: "" },
{ id: 'n_r373', ch: 26, q: "가: 발목을 삐었어요. 어떻게 해야 돼요?\n나: 파스를 붙이세요. 그리고 오늘은 많이 _________________.", a: ["걷지 마세요", "걸은 후에 오세요", "걸어야 돼요", "걷고 싶어요"], c: "걷지 마세요", ex: "A keseleo pergelangan kaki. B menyarankan memakai koyo dan melarangnya banyak berjalan. Tata bahasa larangan adalah '-지 마세요'. Berjalan (걷다) menjadi 걷지 마세요 (Jangan berjalan).", romaji: "" },
{ id: 'n_r374', ch: 26, q: "늦은 밤에 갑자기 배가 너무 아팠습니다. _________________ 약국이 문을 닫아서 편의점에서 약을 샀습니다.", a: ["그래서", "그런데", "그리고", "그러면"], c: "그런데", ex: "Kalimat pertama: 'Larut malam tiba-tiba perut saya sangat sakit.' Kalimat kedua: 'Apotek tutup, jadi saya beli obat di minimarket.' Terdapat pertentangan situasi antara butuh obat dan apotek yang tutup. Kata sambung yang tepat adalah '그런데' (Tetapi/Namun).", romaji: "" },
{ id: 'n_r375', ch: 26, q: "아침에 빵하고 우유를 먹었습니다. _________________ 우유 맛이 좀 이상했습니다. 그래서 배가 아픕니다.", a: ["그러면", "그래서", "그런데", "그리고"], c: "그런데", ex: "'Pagi tadi saya makan roti dan susu. [Tetapi] rasa susunya agak aneh. Oleh karena itu perut saya sakit.' Karena ada informasi yang bertentangan atau menambahkan latar belakang masalah dari kalimat sebelumnya, '그런데' adalah jawaban yang tepat.", romaji: "" },
{ id: 'n_r376', ch: 26, q: "'-(으)ㄴ 후에'를 바르게 사용한 문장은 무엇입니까?", a: ["약을 먹은 후에 푹 쉬세요.", "영화를 본은 후에 쇼핑을 합시다.", "음식을 만들은 후에 같이 먹어요.", "운동을 하은 후에 샤워를 해요."], c: "약을 먹은 후에 푹 쉬세요.", ex: "Aturan '-(으)ㄴ 후에':\nA: 먹다 (konsonan) -> 먹은 후에 (Benar: Beristirahatlah dengan cukup setelah minum obat).\nB: 보다 (vokal) -> 본 후에 (Salah penulisan 본은).\nC: 만들다 (konsonan ㄹ) -> ㄹ hilang -> 만든 후에 (Salah penulisan 만들은).\nD: 하다 (vokal) -> 한 후에 (Salah penulisan 하은).", romaji: "" },
{ id: 'n_r377', ch: 26, q: "'-지 마세요'를 바르게 사용한 문장은 무엇입니까?", a: ["열이 나니까 밖에 나가하지 마세요.", "오늘은 유제품을 먹지 마세요.", "다리가 아프니까 걷르지 마세요.", "손을 데었으니까 요리를 하으지 마세요."], c: "오늘은 유제품을 먹지 마세요.", ex: "Aturan '-지 마세요' dilekatkan langsung pada akar kata kerja tanpa mengubah bentuknya.\nA: 나가다 -> 나가지 마세요 (Salah penambahan 하).\nB: 먹다 -> 먹지 마세요 (Benar: Hari ini jangan makan produk olahan susu).\nC: 걷다 -> 걷지 마세요 (Salah penulisan 걷르지).\nD: 하다 -> 하지 마세요 (Salah penulisan 하으지).", romaji: "" },
{ id: 'n_r378', ch: 26, q: "가: 모니카 씨, 어디가 불편하세요?\n나: 오늘 아침부터 배가 아프고 _________________ 해요.", a: ["설사를", "파스를", "붕대를", "안약을"], c: "설사를", ex: "Sesuai dialog 2 di Bab 26. Apoteker bertanya keluhan Monika. Monika menjawab perutnya sakit sejak pagi dan mengalami [Diare]. 'Diare' adalah '설사' (seolsa). Pasangannya 설사를 하다.", romaji: "" },
{ id: 'n_r379', ch: 26, q: "요리를 하다가 뜨거운 냄비에 손을 _________________. 그래서 약국에서 연고를 사서 발랐습니다.", a: ["베었습니다", "데었습니다", "삐었습니다", "부러졌습니다"], c: "데었습니다", ex: "'Saat memasak, tangan saya [terbakar/terkena panas] panci yang panas. Jadi saya beli salep di apotek dan mengoleskannya.' Tangan terkena luka bakar/panas adalah 손을 데다. Bentuk lampaunya 데었습니다.", romaji: "" },
{ id: 'n_r380', ch: 26, q: "공휴일에는 보통 약국이 문을 닫습니다. 약국이 문을 닫았으면 _________________에서도 감기약이나 진통제를 살 수 있습니다.", a: ["경찰서", "우체국", "편의점", "미용실"], c: "편의점", ex: "'Pada hari libur nasional biasanya apotek tutup. Jika apotek tutup, kita bisa membeli obat flu atau pereda nyeri di [Minimarket].' Sesuai bagian Informasi bab ini, jawabannya adalah 편의점 (Minimarket).", romaji: "" },
{ id: 'n_r381', ch: 26, q: "종이를 자르다가 칼에 손을 _________________. 그래서 구급함에서 밴드를 찾아서 붙였습니다.", a: ["베었습니다", "데었습니다", "토했습니다", "삐었습니다"], c: "베었습니다", ex: "'Saat memotong kertas, tangan saya [tersayat] pisau. Jadi saya mencari plester di kotak p3k dan menempelkannya.' Tangan tersayat benda tajam adalah 손을 베다. Lampaunya 베었습니다.", romaji: "" },
{ id: 'n_r382', ch: 26, q: "가: 바루 씨, 어떻게 오셨어요?\n나: _________________ 아파서 왔어요.", a: ["연고가", "소독약이", "머리가", "영양제가"], c: "머리가", ex: "Apoteker bertanya, 'Ada keperluan apa datang ke mari?'. Baru menjawab bahwa ada bagian tubuhnya yang sakit. Dari pilihan yang ada, hanya '머리' (Kepala) yang merupakan bagian tubuh. 연고 (salep), 소독약 (antiseptik), 영양제 (suplemen) adalah obat.", romaji: "" },
{ id: 'n_r383', ch: 26, q: "가: 소화가 안 되고 계속 토해요.\n나: 이 약을 드세요. 그리고 오늘은 밥을 _________________.", a: ["먹은 후에 오세요", "먹지 마세요", "먹고 싶어요", "먹어야 돼요"], c: "먹지 마세요", ex: "A mengeluh pencernaannya terganggu dan muntah terus. B (Apoteker) memberikan obat dan melarang A untuk makan hari ini agar perutnya istirahat. Tata bahasa larangan adalah '-지 마세요'. Menjadi 밥을 먹지 마세요.", romaji: "" },
{ id: 'n_r384', ch: 26, q: "스트레스를 받거나 잠을 잘 못 자면 _________________이/가 생길 수 있습니다. 그래서 쌓인 스트레스는 꼭 풀어야 합니다.", a: ["복통 (배탈)", "두통 (머리 아픔)", "치통 (이 아픔)", "안통 (눈 아픔)"], c: "두통 (머리 아픔)", ex: "Soal dari bagian perluasan (확장 연습). 'Jika stres atau tidak bisa tidur, bisa muncul [Sakit kepala / 두통]. Jadi stres yang menumpuk harus dilepaskan.' Sakit kepala (머리가 아프다) dalam istilah medis Sino-Korea adalah 두통 (Dutong).", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r385', ch: 27, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 내과, 정형외과, 치과, 이비인후과 ]", a: ["병원", "은행", "식당", "우체국"], c: "병원", ex: "Penyakit dalam (내과), Ortopedi (정형외과), Gigi (치과), dan THT (이비인후과) semuanya adalah bagian atau klinik yang ada di 'Rumah Sakit' (병원).", romaji: "" },
{ id: 'n_r386', ch: 27, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 주사를 맞다, 파스를 붙이다, 붕대를 감다 ]", a: ["집안일", "취미 활동", "치료 (의료 서비스)", "약속 시간"], c: "치료 (의료 서비스)", ex: "Disuntik, Menempelkan koyo, dan Membalut perban adalah sekumpulan tindakan medis atau 'Pengobatan' (치료 / 의료 서비스).", romaji: "" },
{ id: 'n_r387', ch: 27, q: "빈칸에 알맞은 문법을 고르십시오.\n얼굴에 뭐가 ________________ 피부과에 가 보세요.", a: ["나면", "나니까", "나서", "나지만"], c: "나면", ex: "'Jika ada sesuatu yang [muncul] di wajah, cobalah pergi ke poli kulit.' Kalimat ini memberikan syarat dan saran. Tata bahasa untuk 'Jika/Kalau' adalah '-(으)면'. Muncul (나다) + 면 = 나면.", romaji: "" },
{ id: 'n_r388', ch: 27, q: "가: 사무실이 춥네요.\n나: ________________ 문을 닫을까요?", a: ["춥으면", "추우면", "춥어서", "추우니까"], c: "추우면", ex: "A bilang kantornya dingin. B membalas: '[Jika dingin] bagaimana kalau saya tutup pintunya?'. Kata '춥다' (dingin) adalah irregular 'ㅂ'. Ketika bertemu '-(으)면', 'ㅂ' berubah menjadi '우'. Maka 춥다 -> 추우면.", romaji: "" },
{ id: 'n_r389', ch: 27, q: "가: 어떻게 ________________?\n나: 감기에 걸려서 왔습니다.", a: ["왔어요", "오셨습니까", "와요", "옵니까"], c: "오셨습니까", ex: "A (biasanya staf rumah sakit) bertanya dengan sangat sopan kepada pasien, 'Ada yang bisa saya bantu? / Bagaimana Anda bisa datang kemari?'. Bentuk formal sopan dari 오시다 (datang - honorifik) ditambah akhiran -ㅂ/습니까 adalah 오셨습니까?", romaji: "" },
{ id: 'n_r390', ch: 27, q: "'-(으)면'을 바르게 사용한 문장은 무엇입니까?", a: ["이 책을 읽으면 한국어를 잘할 수 있습니다.", "여기에 살으면 회사에 가기 편합니다.", "음식이 맵으면 저에게 말씀하세요.", "날씨가 덥으면 에어컨을 켜세요."], c: "이 책을 읽으면 한국어를 잘할 수 있습니다.", ex: "Aturan '-(으)면':\nA: 읽다 (konsonan) -> 읽으면 (Benar: Jika membaca buku ini...).\nB: 살다 (konsonan ㄹ) -> 살면 (Bukan 살으면).\nC: 맵다 (irregular ㅂ) -> 매우면 (Bukan 맵으면).\nD: 덥다 (irregular ㅂ) -> 더우면 (Bukan 덥으면).", romaji: "" },
{ id: 'n_r391', ch: 27, q: "'-ㅂ/습니다'를 바르게 사용한 문장은 무엇입니까?", a: ["저는 인도네시아에서 왔습니다.", "한국 음식을 잘 만듭으니다.", "지금 병원에서 약을 먹습입니다.", "제 친구는 매일 운동을 하습니다."], c: "저는 인도네시아에서 왔습니다.", ex: "Aturan akhiran formal sopan '-ㅂ/습니다':\nA: 오다 -> 왔 + 습니다 = 왔습니다 (Benar).\nB: 만들다 (ㄹ hilang) -> 만듭니다 (Salah tulis).\nC: 먹다 -> 먹습니다 (Salah tulis 먹습입니다).\nD: 하다 -> 합니다 (Salah tulis 하습니다).", romaji: "" },
{ id: 'n_r392', ch: 27, q: "가: 투안 씨, 걷는 게 왜 그래요?\n나: 발목이 좀 ________________.", a: ["아파요", "다쳐요", "나아요", "부러져요"], c: "아파요", ex: "Sesuai percakapan 1 bab 27. Rihan bertanya kenapa cara jalan Tuan seperti itu. Tuan menjawab: 'Pergelangan kaki saya sedikit [sakit].' Sakit adalah 아파요.", romaji: "" },
{ id: 'n_r393', ch: 27, q: "의사: 어디 봅시다. 여기를 ________________ 어떻습니까?\n환자: 아, 너무 아파요.", a: ["누르면", "바르면", "감으면", "맞으면"], c: "누르면", ex: "Sesuai percakapan 2. Dokter memeriksa kaki Tuan dan bertanya: 'Coba saya lihat. Jika bagian ini saya [tekan], bagaimana rasanya?'. Menekan adalah 누르다. Ditambah tata bahasa jika, menjadi 누르면.", romaji: "" },
{ id: 'n_r394', ch: 27, q: "아이가 어제부터 계속 기침을 하고 열이 많이 나요. 아이가 아프면 ________________에 가 보세요.", a: ["치과", "정형외과", "소아과", "산부인과"], c: "소아과", ex: "'Anak itu dari kemarin terus batuk dan demam tinggi. Jika anak sakit, cobalah pergi ke [Klinik/Poli Anak].' Poli anak dalam bahasa Korea adalah 소아과 (soagwa).", romaji: "" },
{ id: 'n_r395', ch: 27, q: "요즘 컴퓨터를 너무 많이 해서 눈이 피곤하고 아파요. 눈이 아프면 ________________에 가야 합니다.", a: ["안과", "피부과", "내과", "이비인후과"], c: "안과", ex: "'Akhir-akhir ini terlalu banyak main komputer jadi mata lelah dan sakit. Jika mata sakit, harus pergi ke [Poli Mata].' Poli mata adalah 안과 (anggwa).", romaji: "" },
{ id: 'n_r396', ch: 27, q: "배가 아프고 계속 설사를 하면 어느 병원에 가야 합니까?\n________________에 가야 합니다.", a: ["치과", "산부인과", "내과", "정형외과"], c: "내과", ex: "'Jika perut sakit dan terus diare, harus pergi ke rumah sakit mana? Harus pergi ke [Poli Penyakit Dalam].' Sakit perut dan diare ditangani oleh dokter penyakit dalam (내과).", romaji: "" },
{ id: 'n_r397', ch: 27, q: "가: 발목을 삐었네요. 먹는 약과 파스를 ________________ 해 드리겠습니다.\n나: 네, 감사합니다.", a: ["처방", "수술", "소독", "안마"], c: "처방", ex: "Dokter mendiagnosis: 'Pergelangan kaki Anda terkilir. Saya akan [buatkan resep obat] untuk obat minum dan koyo.' Meresepkan obat adalah 처방하다. Menjadi 처방 해 드리겠습니다.", romaji: "" },
{ id: 'n_r398', ch: 27, q: "의사: 어떻게 오셨습니까?\n환자: 어제 계단에서 ________________ 발목을 다쳤어요.", a: ["자서", "넘어져서", "울어서", "일어나서"], c: "넘어져서", ex: "Dokter bertanya ada keluhan apa. Pasien (Tuan) menjawab: 'Kemarin saya [terjatuh] dari tangga jadi pergelangan kaki saya cedera.' Terjatuh adalah 넘어지다, digabung alasan menjadi 넘어져서.", romaji: "" },
{ id: 'n_r399', ch: 27, q: "발목을 삐었을 때는 많이 걷지 말고 앉아서 쉬어야 합니다. ________________ 찜질을 해 주는 것이 좋습니다.", a: ["그러나", "하지만", "그리고", "그래서"], c: "그리고", ex: "Kalimat pertama: 'Saat pergelangan kaki terkilir, jangan banyak berjalan dan harus istirahat duduk.' Kalimat kedua: '[Kemudian/Dan] sebaiknya kompres kaki Anda.' Karena kalimat kedua menambahkan instruksi pengobatan tambahan, kata sambung yang tepat adalah '그리고' (Kemudian/Dan).", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r400', ch: 28, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 송금, 입금, 출금, 환전 ]", a: ["은행 시설", "우체국 업무", "은행 업무", "비상약 종류"], c: "은행 업무", ex: "Mengirim uang (송금), menyetor uang (입금), menarik uang (출금), dan menukar uang (환전) semuanya adalah jenis-jenis 'Urusan Bank / Perbankan' (은행 업무).", romaji: "" },
{ id: 'n_r401', ch: 28, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 신분증, 신청서, 서명, 통장 ]", a: ["체크카드 만들기", "통장 만들기", "현금인출기 사용하기", "대출하기"], c: "통장 만들기", ex: "Membawa kartu identitas (신분증), mengisi formulir (신청서), memberikan tanda tangan (서명), adalah langkah-langkah yang diperlukan untuk 'Membuat Buku Tabungan' (통장 만들기).", romaji: "" },
{ id: 'n_r402', ch: 28, q: "가: 왜 한국에 왔어요?\n나: _________________ 왔어요.", a: ["일하고", "일하려고", "일하러", "일하면"], c: "일하려고", ex: "A bertanya, 'Kenapa Anda datang ke Korea?'. B menjawab tujuannya adalah 'Saya datang [untuk bekerja].' Tata bahasa untuk mengekspresikan tujuan/niat adalah '-(으)려고'. 일하다 + 려고 = 일하려고 왔어요.", romaji: "" },
{ id: 'n_r403', ch: 28, q: "가: 모니카 씨, 왜 그렇게 채소를 많이 샀어요?\n나: 오늘 저녁에 친구들이 와서 불고기를 _________________ 샀어요.", a: ["만들면서", "만드려고", "만들려고", "만들면"], c: "만들려고", ex: "A bertanya, 'Monika, mengapa beli sayur banyak sekali?'. B menjawab, 'Teman-teman akan datang malam ini, jadi saya membelinya [untuk membuat] bulgogi.' Tata bahasa 'untuk' pada kata dasar berakhiran konsonan 'ㄹ' (만들다) langsung ditambahkan '-려고'. Menjadi 만들려고.", romaji: "" },
{ id: 'n_r404', ch: 28, q: "'-(으)려고'를 바르게 사용한 문장은 무엇입니까?\nA. 한국어를 공부하으려고 학원에 갑니다.\nB. 백화점에 옷을 사려고 왔어요.\nC. 은행에서 돈을 찾으러고 합니다.\nD. 책을 읽려고 도서관에 갔습니다.", a: ["한국어를 공부하으려고 학원에 갑니다.", "백화점에 옷을 사려고 왔어요.", "은행에서 돈을 찾으러고 합니다.", "책을 읽려고 도서관에 갔습니다."], c: "백화점에 옷을 사려고 왔어요.", ex: "Aturan '-(으)려고':\nA: 하다 (vokal) -> 하려고 (bukan 하으려고).\nB: 사다 (vokal) -> 사려고 (Benar: Saya datang ke mal untuk membeli baju).\nC: 찾다 (konsonan) -> 찾으려고 (bukan 찾으러고).\nD: 읽다 (konsonan) -> 읽으려고 (bukan 읽려고).", romaji: "" },
{ id: 'n_r405', ch: 28, q: "가: 고향으로 송금하고 싶은데 어떻게 해야 돼요?\n나: 여기 _________________ 됩니다.", a: ["신청서를 쓰면", "신청서를 쓰시면", "신청서를 쓰려고", "신청서를 써서"], c: "신청서를 쓰시면", ex: "A bertanya bagaimana cara mengirim uang ke kampung. B menjawab dengan instruksi: 'Anda [tinggal/cukup mengisi] formulir ini.' Tata bahasa untuk kecukupan adalah '-(으)면 되다'. Kata sopan 쓰다 -> 쓰시다 + 면 되다 = 쓰시면 됩니다.", romaji: "" },
{ id: 'n_r406', ch: 28, q: "'-(으)면 되다'를 바르게 사용한 문장은 무엇입니까?\nA. 이 약은 하루에 두 번 먹으면 돼요.\nB. 시간이 없으면 택시를 타으면 돼요.\nC. 내일 아침에 일찍 일어남면 돼요.\nD. 외국인 등록증을 만들으려면 돼요.", a: ["이 약은 하루에 두 번 먹으면 돼요.", "시간이 없으면 택시를 타으면 돼요.", "내일 아침에 일찍 일어남면 돼요.", "외국인 등록증을 만들으려면 돼요."], c: "이 약은 하루에 두 번 먹으면 돼요.", ex: "Aturan '-(으)면 되다':\nA: 먹다 (konsonan) -> 먹으면 돼요 (Benar: Obat ini cukup diminum 2 kali sehari).\nB: 타다 (vokal) -> 타면 돼요 (bukan 타으면).\nC: 일어나다 (vokal) -> 일어나면 돼요 (bukan 일어남면).\nD: 만들다 -> 만들면 돼요 (bukan 만들으려면 돼요).", romaji: "" },
{ id: 'n_r407', ch: 28, q: "가: 어떻게 오셨습니까?\n나: 한국 돈을 달러로 _________________ 왔어요.", a: ["환전하려고", "입금하려고", "대출하려고", "가입하려고"], c: "환전하려고", ex: "Teller bertanya, 'Ada yang bisa saya bantu?'. Jawaban yang logis untuk 'Uang Korea (won) ke Dolar' adalah 'menukar uang' (환전하다). Tata bahasa yang tepat adalah 'Saya datang [untuk menukar uang]' yaitu 환전하려고 왔어요.", romaji: "" },
{ id: 'n_r408', ch: 28, q: "은행에서 돈을 다른 사람에게 보내고 싶으면 _________________을/를 하세요.", a: ["환전", "대출", "가입", "송금"], c: "송금", ex: "'Jika Anda ingin [mengirim uang/mentransfer uang] ke orang lain di bank, lakukanlah [송금].' Songgeum berarti mengirim uang.", romaji: "" },
{ id: 'n_r409', ch: 28, q: "통장을 만들려면 여권이나 _________________이/가 필요합니다.", a: ["신용카드", "현금인출기", "신분증", "주소"], c: "신분증", ex: "'Jika ingin membuat buku tabungan, Anda memerlukan paspor atau [Kartu identitas / 신분증].' Bank membutuhkan tanda pengenal (신분증) untuk membuka rekening.", romaji: "" },
{ id: 'n_r410', ch: 28, q: "은행에 가서 신청서를 씁니다. _________________ 서명을 합니다.", a: ["하지만", "그리고", "그래서", "그러면"], c: "그리고", ex: "Kalimat pertama: 'Pergi ke bank dan menulis/mengisi formulir.' Kalimat kedua: '[Dan/Kemudian] memberikan tanda tangan.' Karena kalimat kedua adalah urutan/tindakan selanjutnya yang setara, kata sambung yang tepat adalah '그리고'.", romaji: "" },
{ id: 'n_r411', ch: 28, q: "고향에 돈을 보내고 싶습니다. _________________ 은행에 갑니다.", a: ["그래서", "그런데", "그리고", "그러나"], c: "그래서", ex: "Kalimat pertama (Sebab/Alasan): 'Saya ingin mengirim uang ke kampung halaman.' Kalimat kedua (Akibat/Tindakan): 'Saya pergi ke bank.' Kata sambung penanda sebab-akibat yang tepat adalah '그래서' (Oleh karena itu / Jadi).", romaji: "" },
{ id: 'n_r412', ch: 28, q: "가: 몽골로 송금하려고 하는데 어떻게 해야 돼요?\n나: 통장이 있으면 _________________을/를 이용하세요. 송금 수수료도 더 적게 나와요.", a: ["체크카드", "신분증", "여권", "현금인출기"], c: "현금인출기", ex: "Sesuai dialog 2 Bab 28. 'Jika ada buku tabungan gunakanlah [Mesin ATM / 현금인출기]. Biaya pengirimannya lebih sedikit'.", romaji: "" },
{ id: 'n_r413', ch: 28, q: "가: 오늘은 일요일인데 고향으로 송금할 수 있어요?\n나: 네. 우리 동네 은행은 일하는 외국인들이 많아서 일요일에도 _________________.", a: ["문을 닫아요", "문을 열어요", "약을 사요", "영화를 봐요"], c: "문을 열어요", ex: "Berdasarkan skrip Listening EPS-TOPIK. A bertanya apakah hari Minggu bisa transfer uang. B menjawab: 'Ya, karena di lingkungan kami banyak pekerja asing, pada hari Minggu pun bank [Buka / 문을 열어요]'.", romaji: "" },
{ id: 'n_r414', ch: 28, q: "기계에 통장을 넣고 송금 버튼을 _________________ 됩니다.", a: ["누르려고", "누르러", "누르면", "누르면서"], c: "누르면", ex: "'Masukkan buku tabungan ke mesin dan Anda [tinggal memencet] tombol pengiriman.' Tata bahasa instruksi mudah/cukup adalah '-(으)면 되다'. Memencet adalah 누르다 + 면 = 누르면.", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r415', ch: 29, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 우표를 붙이다, 주소를 쓰다, 저울에 올려놓다, 무게를 재다 ]", a: ["은행 업무", "병원 치료", "우체국 이용", "지하철 이용"], c: "우체국 이용", ex: "Menempelkan prangko, menulis alamat, meletakkan di atas timbangan, dan menimbang berat adalah aktivitas-aktivitas yang berhubungan dengan 'Penggunaan Kantor Pos' (우체국 이용).", romaji: "" },
{ id: 'n_r416', ch: 29, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 국제 특급, 등기 우편, 일반 우편, 배편, 항공편 ]", a: ["휴가 종류", "우편 배달 방법 (서비스)", "교육 프로그램", "포장 종류"], c: "우편 배달 방법 (서비스)", ex: "EMS, Pos Tercatat, Pos Biasa, Jalur Laut, dan Jalur Udara semuanya adalah 'Metode / Layanan Pengiriman Pos' (우편 배달 방법 / 서비스).", romaji: "" },
{ id: 'n_r417', ch: 29, q: "가: 어떻게 오셨습니까?\n나: 인도네시아로 엽서를 _________________ 왔어요.", a: ["보내면", "보내려고", "보내면서", "보낸 후에"], c: "보내려고", ex: "A bertanya ada keperluan apa. B menjawab niat/tujuannya: 'Saya datang [untuk mengirim] kartu pos ke Indonesia.' Tata bahasa untuk niat/tujuan adalah '-(으)려고'. Menjadi 보내려고.", romaji: "" },
{ id: 'n_r418', ch: 29, q: "가: 베트남까지 _________________ 걸려요?\n나: 국제 특급은 3, 4일 걸립니다.", a: ["언제", "얼마나", "누구", "왜"], c: "얼마나", ex: "Sesuai percakapan 2 dan Latihan. A bertanya tentang durasi waktu pengiriman ke Vietnam. Kata tanya untuk 'Berapa lama' adalah '얼마나' (eolmana). Menjadi 얼마나 걸려요?", romaji: "" },
{ id: 'n_r419', ch: 29, q: "'-(으)로'를 바르게 사용한 문장은 무엇입니까?\nA. 내일 아침에 서울으로 출발합니다.\nB. 저는 인도네시아으로 편지를 보냅니다.\nC. 베트남로 소포를 보낼 겁니다.\nD. 오른쪽으로 돌아가십시오.", a: ["내일 아침에 서울으로 출발합니다.", "저는 인도네시아으로 편지를 보냅니다.", "베트남로 소포를 보낼 겁니다.", "오른쪽으로 돌아가십시오."], c: "오른쪽으로 돌아가십시오.", ex: "Aturan '-(으)로' (ke arah / dengan cara):\nA: 서울 (konsonan ㄹ) -> 서울로 (bukan 서울으로).\nB: 인도네시아 (vokal) -> 인도네시아로 (bukan 인도네시아으로).\nC: 베트남 (konsonan ㅁ) -> 베트남으로 (bukan 베트남로).\nD: 오른쪽 (konsonan ㄱ) -> 오른쪽으로 (Benar: Berputarlah ke arah kanan).", romaji: "" },
{ id: 'n_r420', ch: 29, q: "'-(으)십시오'를 바르게 사용한 문장은 무엇입니까?\nA. 편지를 저울 위에 올려놓으십시오.\nB. 이 종이에 주소를 쓰으십시오.\nC. 내일까지 이것을 만들으십시오.\nD. 한국에서 오래 살으십시오.", a: ["편지를 저울 위에 올려놓으십시오.", "이 종이에 주소를 쓰으십시오.", "내일까지 이것을 만들으십시오.", "한국에서 오래 살으십시오."], c: "편지를 저울 위에 올려놓으십시오.", ex: "Aturan '-(으)십시오' (Bentuk perintah formal/sopan):\nA: 올려놓다 (konsonan) -> 올려놓으십시오 (Benar: Letakkan surat di atas timbangan).\nB: 쓰다 (vokal) -> 쓰십시오 (bukan 쓰으십시오).\nC: 만들다 (ㄹ hilang) -> 만드십시오 (bukan 만들으십시오).\nD: 살다 (ㄹ hilang) -> 사십시오 (bukan 살으십시오).", romaji: "" },
{ id: 'n_r421', ch: 29, q: "엽서를 보내고 싶으면 우체국에 가서 엽서에 _________________을/를 붙이십시오.", a: ["우표", "저울", "소포", "여권"], c: "우표", ex: "'Jika ingin mengirim kartu pos, pergilah ke kantor pos dan tempelkan [Prangko] pada kartu pos tersebut.' Benda yang ditempelkan (붙이다) adalah 우표.", romaji: "" },
{ id: 'n_r422', ch: 29, q: "우체국 직원: 엽서를 여기에 올려놓으세요. 그런데 받는 사람의 _________________이/가 없네요. 쓰세요.\n모니카: 아, 네. 알겠습니다.", a: ["이메일", "우편번호", "통장", "택배"], c: "우편번호", ex: "Sesuai percakapan 1 Bab 29. Pegawai pos berkata: 'Letakkan kartu pos di sini. Tetapi, [Kode pos] penerima masih belum ada, ya. Silakan tulis.' Jawabannya adalah 우편번호 (Kode pos).", romaji: "" },
{ id: 'n_r423', ch: 29, q: "가: 호찌민까지 얼마나 걸릴까요?\n나: _________________은/는 한두 달 정도 걸리고 _________________은/는 열흘에서 2주 정도 걸립니다.", a: ["등기 우편 / 일반 우편", "항공편 / 배편", "배편 / 항공편", "택배 / 소포"], c: "배편 / 항공편", ex: "Sesuai percakapan 2. Pegawai pos menjelaskan: '[Jalur laut/kapal] memakan waktu 1-2 bulan, dan [Jalur udara/pesawat] memakan waktu 10 hari sampai 2 minggu.' Karena 1-2 bulan lebih lama, itu pasti 배편 (kapal). Yang lebih cepat (10-14 hari) adalah 항공편 (pesawat). Urutannya 배편 / 항공편.", romaji: "" },
{ id: 'n_r424', ch: 29, q: "소포를 보낼 때 급하면 _________________으로/로 보내십시오. 요금은 비싸지만 제일 빠릅니다.", a: ["일반 우편", "배편", "국제 특급 (EMS)", "보통 우편"], c: "국제 특급 (EMS)", ex: "'Saat mengirim paket, jika terburu-buru (급하면) kirimlah dengan [Pos Kilat Internasional / EMS]. Biayanya mahal tapi paling cepat.'", romaji: "" },
{ id: 'n_r425', ch: 29, q: "항공편으로 소포를 보내고 싶습니다. _________________ 요금이 너무 비싸서 배편으로 보냈습니다.", a: ["그래서", "하지만", "그리고", "그러면"], c: "하지만", ex: "Kalimat pertama: 'Saya ingin mengirim paket dengan pesawat.' Kalimat kedua: 'Biayanya sangat mahal sehingga saya mengirim dengan kapal.' Terdapat pertentangan antara keinginan awal dan kenyataan (karena mahal). Kata sambung yang tepat adalah '하지만 / 그런데' (Akan tetapi / Namun).", romaji: "" },
{ id: 'n_r426', ch: 29, q: "소포를 보내려면 먼저 상자에 물건을 넣고 포장하십시오. _________________ 우체국에 가서 저울에 올려놓으십시오.", a: ["그러나", "하지만", "그리고", "왜냐하면"], c: "그리고", ex: "Kalimat pertama adalah instruksi pertama: 'Masukkan barang dan kemas.' Kalimat kedua adalah instruksi selanjutnya: '[Kemudian/Lalu] pergi ke kantor pos dan letakkan di timbangan.' Kata sambung untuk urutan/setara adalah '그리고'.", romaji: "" },
{ id: 'n_r427', ch: 29, q: "가: 신용카드를 잃어버렸는데 어떻게 해야 돼요?\n나: 빨리 이 전화번호로 전화를 _________________.", a: ["거십시오", "걸으십시오", "거세요", "걸십시오"], c: "거십시오", ex: "'Saya kehilangan kartu kredit, harus bagaimana? / Cepat [meneleponlah] ke nomor ini.' Telepon adalah 전화(를) 걸다. Karena 걸다 berakhiran 'ㄹ', 'ㄹ' hilang saat bertemu -(으)십시오. Menjadi 거십시오. (Catatan: 거세요 juga bisa secara makna, tapi opsi formal yang diajarkan dalam bab ini adalah 거십시오).", romaji: "" },
{ id: 'n_r428', ch: 29, q: "가: 인도네시아로 카드를 _________________ 해요.\n나: 그럼 카드를 이 저울 위에 올려놓으십시오.", a: ["보내려고", "보낼 수", "보내면", "보내서"], c: "보내려고", ex: "Sesuai Latihan Aktivitas bab ini. 'Saya [berniat mengirim] kartu ke Indonesia. / Kalau begitu letakkan kartunya di atas timbangan ini.' Tata bahasa niat adalah '-(으)려고 하다'. Menjadi 보내려고 해요.", romaji: "" },
{ id: 'n_r429', ch: 29, q: "편지를 보내기 전에 봉투에 보내는 사람의 주소와 _________________ 사람의 주소를 모두 정확하게 써야 합니다.", a: ["파는", "받는", "찾는", "주는"], c: "받는", ex: "'Sebelum mengirim surat, di amplop harus ditulis dengan tepat alamat orang yang mengirim (보내는 사람) dan alamat orang yang [Menerima].' Orang yang menerima adalah 받는 사람.", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r430', ch: 30, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 태권도, 한국어, 안전, 컴퓨터 ]", a: ["진료 과목", "은행 업무", "교육 프로그램", "우편 서비스"], c: "교육 프로그램", ex: "Taekwondo, Bahasa Korea, Keamanan, dan Komputer adalah jenis-jenis 'Program Pelatihan/Pendidikan' (교육 프로그램) yang diajarkan di Pusat Bantuan.", romaji: "" },
{ id: 'n_r431', ch: 30, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 예약하다, 상담을 받다, 신청서를 쓰다 ]", a: ["병원 위치", "센터 이용 방법", "우체국 위치", "고향 가는 방법"], c: "센터 이용 방법", ex: "Melakukan reservasi, berkonsultasi, dan mengisi formulir adalah langkah-langkah atau 'Cara Menggunakan Pusat Bantuan' (센터 이용 방법).", romaji: "" },
{ id: 'n_r432', ch: 30, q: "가: 혹시 한국 음식을 _________________?\n나: 네. 불고기를 조금 만들 줄 알아요.", a: ["만들 수 없어요", "만들 수 있어요", "만들려면", "만들어서"], c: "만들 수 있어요", ex: "A bertanya tentang 'kemampuan' B membuat makanan Korea. B menjawab 'Ya, saya bisa'. Maka bentuk pertanyaan untuk menanyakan kemampuan adalah '-(으)ㄹ 수 있다/없다'. Menjadi 만들 수 있어요? (Apakah Anda bisa membuat...?).", romaji: "" },
{ id: 'n_r433', ch: 30, q: "가: 김치찌개를 _________________ 뭐가 필요해요?\n나: 김치하고 고기가 필요해요.", a: ["만들어서", "만들지만", "만들면", "만들려면"], c: "만들려면", ex: "A bertanya: '[Jika ingin membuat] sup kimchi, apa yang dibutuhkan?'. Tata bahasa untuk 'Jika ingin/bermaksud' adalah '-(으)려면'. Karena '만들다' berakhiran 'ㄹ', langsung ditambah '-려면' menjadi 만들려면.", romaji: "" },
{ id: 'n_r434', ch: 30, q: "'-(으)ㄹ 수 있다/없다'를 바르게 사용한 문장은 무엇입니까?\nA. 저는 매운 김치를 먹을 수 없어요.\nB. 시간이 없어서 갈 수이 없어요.\nC. 그 친구는 영어를 할을 수 있어요.\nD. 오늘은 바빠서 만날 수이 없어요.", a: ["저는 매운 김치를 먹을 수 없어요.", "시간이 없어서 갈 수이 없어요.", "그 친구는 영어를 할을 수 있어요.", "오늘은 바빠서 만날 수이 없어요."], c: "저는 매운 김치를 먹을 수 없어요.", ex: "Aturan '-(으)ㄹ 수 있다/없다':\nA: 먹다 -> 먹을 수 없어요 (Benar: Saya tidak bisa makan kimchi yang pedas).\nB: 가다 -> 갈 수 없어요 (Salah tulis 갈 수이).\nC: 하다 -> 할 수 있어요 (Salah tulis 할을 수).\nD: 만나다 -> 만날 수 없어요 (Salah tulis 만날 수이).", romaji: "" },
{ id: 'n_r435', ch: 30, q: "'-(으)려면'을 바르게 사용한 문장은 무엇입니까?\nA. 한국에서 살으려면 한국어를 배워야 합니다.\nB. 약을 받으려면 의사의 처방전이 필요합니다.\nC. 이 음악을 듣려면 어떻게 해야 합니까?\nD. 한국 음식을 만들으려면 고기가 필요합니다.", a: ["한국에서 살으려면 한국어를 배워야 합니다.", "약을 받으려면 의사의 처방전이 필요합니다.", "이 음악을 듣려면 어떻게 해야 합니까?", "한국 음식을 만들으려면 고기가 필요합니다."], c: "약을 받으려면 의사의 처방전이 필요합니다.", ex: "Aturan '-(으)려면':\nA: 살다 (konsonan ㄹ) -> 살려면 (bukan 살으려면).\nB: 받다 (konsonan) -> 받으려면 (Benar: Jika ingin menerima obat...).\nC: 듣다 (irregular ㄷ) -> 들으려면 (bukan 듣려면).\nD: 만들다 (konsonan ㄹ) -> 만들려면 (bukan 만들으려면).", romaji: "" },
{ id: 'n_r436', ch: 30, q: "가: 태권도를 전혀 _________________ 괜찮을까요?\n나: 그럼요. 센터에 오셔서 처음부터 배우시면 됩니다.", a: ["할 수 없는데", "할 수 있는데", "할려면", "해서"], c: "할 수 없는데", ex: "Sesuai percakapan 1 bab 30. Rihan bertanya: 'Saya [sama sekali tidak bisa] taekwondo, apakah tidak masalah?'. Karena ada kata '전혀' (sama sekali), kalimat harus berbentuk negatif. Menjadi 할 수 없는데.", romaji: "" },
{ id: 'n_r437', ch: 30, q: "가: 컴퓨터 교육을 _________________ 어디로 가야 해요?\n나: 1층으로 내려가세요.", a: ["신청할 수 없어서", "신청하려면", "신청하니까", "신청해서"], c: "신청하려면", ex: "Sesuai contoh di bagian tata bahasa 2. 'Jika ingin mendaftar (신청하려면) pendidikan komputer, harus pergi ke mana? / Turunlah ke lantai 1.'", romaji: "" },
{ id: 'n_r438', ch: 30, q: "한국어 교육을 신청하려면 먼저 이 _________________을/를 쓰고 잠깐만 기다리세요.", a: ["신청서", "우표", "영수증", "엽서"], c: "신청서", ex: "'Jika ingin mendaftar pendidikan bahasa Korea, pertama-tama isilah [Formulir pendaftaran / 신청서] ini dan tunggu sebentar.' Mendaftar program membutuhkan formulir.", romaji: "" },
{ id: 'n_r439', ch: 30, q: "센터에서 교육을 받으려면 먼저 방문해서 _________________ 카드를 만들어야 합니다.", a: ["신용", "이용자", "교통", "학생"], c: "이용자", ex: "Sesuai percakapan 2. 'Jika ingin menerima pelatihan di pusat bantuan, Anda harus datang dan membuat [Kartu pengguna/anggota] terlebih dahulu.' Kartu anggota center disebut 이용자 카드 (iyongja kadeu).", romaji: "" },
{ id: 'n_r440', ch: 30, q: "센터에서 상담을 받고 싶습니다. _________________ 먼저 전화를 해서 예약해야 합니다.", a: ["그래서", "하지만", "그러면", "그리고"], c: "그러면", ex: "Kalimat pertama: 'Saya ingin berkonsultasi di pusat.' Kalimat kedua: 'harus telepon dan reservasi dulu.' Karena kalimat kedua adalah syarat/tindakan yang harus dilakukan jika kalimat pertama (niat) terjadi, kata sambung yang tepat adalah '그러면' / '그러려면' (Jika begitu).", romaji: "" },
{ id: 'n_r441', ch: 30, q: "가: 내일 센터에서 하는 한국 문화 체험에 갈 거예요?\n나: 아니요, 저는 주말에 출근해야 돼서 _________________.", a: ["갈 수 없어요", "갈 수 있어요", "가려면 안 돼요", "가고 싶어요"], c: "갈 수 없어요", ex: "B mengatakan 'Tidak, saya harus bekerja di akhir pekan, jadi [Saya tidak bisa pergi].' Ketidakmampuan karena suatu alasan menggunakan '-(으)ㄹ 수 없다'. Menjadi 갈 수 없어요.", romaji: "" },
{ id: 'n_r442', ch: 30, q: "한국어와 컴퓨터는 무료로 배울 수 있습니다. 교육은 _________________이기 때문에 돈을 내지 않아도 됩니다.", a: ["유료", "무상 (무료)", "비싸기", "어렵기"], c: "무상 (무료)", ex: "Sesuai latihan tambahan bab 30. 'Pendidikan ini adalah [Gratis / 무상(musang)], oleh karena itu Anda tidak perlu membayar uang.'", romaji: "" },
{ id: 'n_r443', ch: 30, q: "가: 선생님, 외국인 등록증을 꼭 가지고 가야 해요?\n나: 네, 통장이나 이용자 카드를 _________________ 신분증이 꼭 필요해요.", a: ["만들어서", "만들 수 있어서", "만들려면", "만들지만"], c: "만들려면", ex: "A bertanya apakah wajib bawa ARC (KTP). B menjawab: 'Ya, [Jika ingin membuat] buku tabungan atau kartu anggota, kartu identitas pasti dibutuhkan.' Menggunakan tata bahasa niat/syarat '-(으)려면'.", romaji: "" },
{ id: 'n_r444', ch: 30, q: "가: 수루 씨, 주말에 뭐 할 거예요?\n나: 저는 친구하고 외국인력지원센터에 가서 _________________을/를 할 거예요. 쓰레기도 줍고 청소도 할 거예요.", a: ["컴퓨터 교육", "자원 봉사", "한방 진료", "태권도 교육"], c: "자원 봉사", ex: "B menjelaskan kegiatannya: 'Memungut sampah dan bersih-bersih.' Kegiatan sosial tanpa dibayar ini disebut [Kerja bakti / Relawan sosial / 자원 봉사].", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r445', ch: 31, q: "가: 한국은 여름에 비가 많이 와요?\n나: 네. 비가 많이 와서 _________________이/가 높아요.", a: ["기온", "습도", "영하", "인구"], c: "습도", ex: "A bertanya apakah Korea sering hujan di musim panas. B menjawab: 'Ya, karena sering hujan [Kelembapan]-nya tinggi.' Jika banyak hujan, maka kelembapan (습도) udara akan naik.", romaji: "" },
{ id: 'n_r446', ch: 31, q: "가: 가장 기온이 낮을 때는 몇 도까지 내려가요?\n나: 우리 고향의 _________________은/는 15도 정도예요.", a: ["영상", "영하", "최저기온", "최고기온"], c: "최저기온", ex: "A bertanya 'Saat suhu paling rendah turun sampai berapa derajat?'. B menjawab: '[Suhu terendah] kampung halaman kami sekitar 15 derajat.' Suhu paling rendah adalah 최저기온 (Choejeogion).", romaji: "" },
{ id: 'n_r447', ch: 31, q: "'-지만'을 바르게 사용한 문장은 무엇입니까?\nA. 오늘은 비가 오으지만 내일은 맑을 거예요.\nB. 제 고향은 덥지만 비가 안 와서 여행하기 좋아요.\nC. 이 음식은 맵으지만 아주 맛있어요.\nD. 수박은 달르지만 레몬은 셔요.", a: ["오늘은 비가 오으지만 내일은 맑을 거예요.", "제 고향은 덥지만 비가 안 와서 여행하기 좋아요.", "이 음식은 맵으지만 아주 맛있어요.", "수박은 달르지만 레몬은 셔요."], c: "제 고향은 덥지만 비가 안 와서 여행하기 좋아요.", ex: "Aturan '-지만' (Tetapi) ditempelkan langsung pada akar kata tanpa menambahkan '으'.\nA: 오다 -> 오지만 (Bukan 오으지만).\nB: 덥다 -> 덥지만 (Benar: Kampungku panas tetapi tidak hujan jadi bagus untuk wisata).\nC: 맵다 -> 맵지만 (Bukan 맵으지만).\nD: 달다 -> 달지만 (Bukan 달르지만).", romaji: "" },
{ id: 'n_r448', ch: 31, q: "명사 + '보다'를 바르게 사용한 문장은 무엇입니까?\nA. 버스보다 지하철이 더 빠릅니다.\nB. 저는 사과를 딸기보다를 좋아해요.\nC. 오늘은 날씨가 어제보다가 추워요.\nD. 내 고향은 서울보다에 작아요.", a: ["버스보다 지하철이 더 빠릅니다.", "저는 사과를 딸기보다를 좋아해요.", "오늘은 날씨가 어제보다가 추워요.", "내 고향은 서울보다에 작아요."], c: "버스보다 지하철이 더 빠릅니다.", ex: "Aturan '-보다' (Daripada) ditempelkan pada kata benda yang menjadi standar perbandingan, dan TIDAK BOLEH ditumpuk dengan partikel subjek/objek/tempat (가, 를, 에).\nA: 버스보다 (Benar: Kereta bawah tanah lebih cepat daripada bus).\nB: 딸기보다를 (Salah dobel partikel).\nC: 어제보다가 (Salah dobel partikel).\nD: 서울보다에 (Salah dobel partikel).", romaji: "" },
{ id: 'n_r449', ch: 31, q: "동생은 라면을 _________________ 저는 라면을 좋아하지 않아요.", a: ["좋아해서", "좋아하지만", "좋아하면", "좋아하려고"], c: "좋아하지만", ex: "'Adik suka mi instan [TETAPI] saya tidak suka mi instan.' Terdapat perbandingan/pertentangan (대조적 정보) antara adik dan saya, sehingga menggunakan '-지만' (Tetapi).", romaji: "" },
{ id: 'n_r450', ch: 31, q: "우리 고향은 서울_________________ 인구도 적고 조용해요.", a: ["마다", "처럼", "보다", "에게"], c: "보다", ex: "Sesuai percakapan 2. 'Kampung halaman saya [DARIPADA/DIBANDINGKAN] Seoul, penduduknya lebih sedikit dan tenang.' Kata untuk membandingkan dua benda adalah '보다' (boda).", romaji: "" },
{ id: 'n_r451', ch: 31, q: "가: 철민 씨, 밖을 보세요. 지금 눈이 와요. 우와 _________________.\n나: 바루 씨는 눈을 처음 봐요?", a: ["복잡해요", "건조해요", "신기해요", "시끄러워요"], c: "신기해요", ex: "Sesuai percakapan 1. Baru takjub melihat salju dan berkata: 'Wah, [MENGAGUMKAN/AJAIB]!' Kata yang tepat untuk fenomena asing yang luar biasa adalah '신기하다' (singihada).", romaji: "" },
{ id: 'n_r452', ch: 31, q: "가: 투안 씨 고향은 서울하고 비슷해요?\n나: 아니요. 서울보다 인구가 적어서 훨씬 _________________.", a: ["조용해요", "시끄러워요", "많아요", "복잡해요"], c: "조용해요", ex: "Sesuai skrip listening EPS bab 31. A bertanya apakah kampung Tuan mirip Seoul. B menjawab: 'Tidak. Karena penduduknya lebih sedikit daripada Seoul, jauh lebih [TENANG/SEPI].' Jawabannya adalah 조용해요 (Tenang).", romaji: "" },
{ id: 'n_r453', ch: 31, q: "서울은 교통이 _________________ 버스나 지하철을 타면 어디든지 갈 수 있습니다.", a: ["불편해서", "복잡해서", "편리해서", "맑아서"], c: "편리해서", ex: "Sesuai skrip listening EPS. 'Karena transportasi di Seoul [PRAKTIS/NYAMAN], kita bisa pergi ke mana saja jika naik bus atau subway.' Nyaman/praktis adalah 편리하다. Digabung alasan menjadi 편리해서.", romaji: "" },
{ id: 'n_r454', ch: 31, q: "어제는 비가 왔습니다. _________________ 오늘은 날씨가 맑습니다.", a: ["그래서", "그리고", "하지만", "그러면"], c: "하지만", ex: "Kalimat pertama: 'Kemarin turun hujan.' Kalimat kedua: '[Tetapi] hari ini cuacanya cerah.' Menunjukkan pertentangan fakta, maka kata sambung yang tepat adalah '하지만' atau '그런데'. Di grammar fokus bab ini, '하지만' sangat relevan (berkaitan dengan -지만).", romaji: "" },
{ id: 'n_r455', ch: 31, q: "택시 기사: 네, 알겠습니다. 그런데 어디에서 _________________?\n칸: 캄보디아에서 왔어요.", a: ["오셨어요", "왔어요", "갈 거예요", "가셨어요"], c: "오셨어요", ex: "Sesuai percakapan 2. Sopir taksi bertanya dengan bentuk hormat (formal sopan): 'Anda [berasal] dari mana?'. Bentuk sopan dari 왔어요 (datang/berasal) adalah 오셨어요 (osyeosseoyo).", romaji: "" },
{ id: 'n_r456', ch: 31, q: "리한 씨가 갑자기 오늘 고향으로 돌아간다고 해서 _________________ 놀랐어요.", a: ["조금", "많이", "별로", "깜짝"], c: "깜짝", ex: "Dari bagian kosakata. 'Saya [SANGAT TERKEJUT] karena Rihan tiba-tiba bilang mau pulang ke kampung halaman hari ini.' Frasa tetap untuk terkejut/kaget adalah '깜짝 놀라다' (kkamjjak nollada).", romaji: "" },
{ id: 'n_r457', ch: 31, q: "가: 오늘 최고기온은 몇 도예요?\n나: 낮에는 기온이 30도까지 _________________.", a: ["내려갈 거예요", "올라갈 거예요", "낮을 거예요", "시원할 거예요"], c: "올라갈 거예요", ex: "Sesuai skrip listening EPS no 4. A menanyakan suhu tertinggi. B menjawab: 'Pada siang hari suhunya akan [NAIK] hingga 30 derajat.' Suhu yang menuju titik tinggi menggunakan kata kerja '올라가다' (naik).", romaji: "" },
{ id: 'n_r458', ch: 31, q: "집에서 회사까지 30분 _________________ 걸려요.", a: ["정도", "보다", "처럼", "마다"], c: "정도", ex: "'Dari rumah ke perusahaan menempuh waktu [SEKITAR / KIRA-KIRA] 30 menit.' Kata untuk menyatakan perkiraan jumlah/waktu adalah '정도' (jeongdo) atau '쯤' (jjeum).", romaji: "" },
{ id: 'n_r459', ch: 31, q: "가: 겨울에는 비가 많이 와서 습해요. 여행을 _________________ 여름에 가세요.", a: ["하면", "하려면", "하면서", "한 후에"], c: "하려면", ex: "Sesuai percakapan 1. Baru menyarankan: 'Di musim dingin lembab karena sering hujan. [JIKA BERMAKSUD/INGIN] berwisata, pergilah di musim panas.' Tata bahasa 'jika berniat/ingin' adalah '-(으)려면'. Menjadi 하려면.", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r460', ch: 32, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 팥죽, 군고구마, 찐빵, 호떡 ]", a: ["여름 음식", "겨울 음식", "과일", "고기"], c: "겨울 음식", ex: "Bubur kacang merah (팥죽), ubi panggang (군고구마), bakpao (찐빵), dan pancake manis (호떡) semuanya adalah jenis-jenis 'Makanan Musim Dingin' (겨울 음식).", romaji: "" },
{ id: 'n_r461', ch: 32, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 끓이다, 삶다, 굽다, 볶다, 튀기다 ]", a: ["식사 예절", "조리 방법", "재료 이름", "식당 종류"], c: "조리 방법", ex: "Merebus berkuah, merebus, memanggang, menumis, dan menggoreng adalah 'Cara Memasak' (조리 방법).", romaji: "" },
{ id: 'n_r462', ch: 32, q: "가: 무슨 음식을 먹을까요?\n나: 오늘은 비가 오고 추우니까 _________________ 음식을 먹고 싶어요.", a: ["따뜻한", "따뜻해서", "찬", "차가운"], c: "따뜻한", ex: "A bertanya mau makan apa. B menjawab: 'Karena hari ini hujan dan dingin, saya ingin makan makanan [yang hangat].' Tata bahasa untuk kata sifat menerangkan kata benda (yang) adalah '-(으)ㄴ'. 따뜻하다 + ㄴ = 따뜻한.", romaji: "" },
{ id: 'n_r463', ch: 32, q: "가: 어디 아파요?\n나: 아까 _________________ 음식을 많이 먹어서 배탈이 났어요.", a: ["따뜻한", "더운", "긴", "찬"], c: "찬", ex: "Sesuai latihan tata bahasa 1. B menjawab: 'Tadi saya banyak makan makanan [yang dingin] jadi perut saya sakit.' Dingin adalah 차다. Ditempelkan akhiran '-(으)ㄴ' menjadi 찬 (yang dingin).", romaji: "" },
{ id: 'n_r464', ch: 32, q: "'-(으)ㄴ'을 바르게 사용한 단어는 무엇입니까?", a: ["길다 → 길은 바지", "크다 → 큰 가방", "작다 → 자은 모자", "맛있다 → 맛있는은 음식"], c: "크다 → 큰 가방", ex: "Aturan '-(으)ㄴ' (yang):\nA: 길다 (konsonan ㄹ) -> ㄹ hilang -> 긴 (Bukan 길은).\nB: 크다 (vokal) -> 큰 (Benar: Tas yang besar).\nC: 작다 (konsonan) -> 작은 (Bukan 자은).\nD: 맛있다 -> 맛있는 (Kata berakhiran 있다/없다 menggunakan -는, bukan 맛있는은).", romaji: "" },
{ id: 'n_r465', ch: 32, q: "'-아서/어서'를 바르게 사용한 문장은 무엇입니까?\nA. 양파를 볶아아서 냄비에 넣으세요.\nB. 백화점에 가아서 옷을 샀어요.\nC. 생선을 구워서 먹을 거예요.\nD. 물을 끓이어서 차를 마십니다.", a: ["양파를 볶아아서 냄비에 넣으세요.", "백화점에 가아서 옷을 샀어요.", "생선을 구워서 먹을 거예요.", "물을 끓이어서 차를 마십니다."], c: "생선을 구워서 먹을 거예요.", ex: "Aturan '-아서/어서' (lalu/kemudian - urutan aksi):\nA: 볶다 -> 볶아서 (Bukan 볶아아서).\nB: 가다 -> 가서 (Bukan 가아서).\nC: 굽다 (irregular ㅂ) -> 구워서 (Benar: Saya akan memanggang ikan lalu memakannya).\nD: 끓이다 -> 끓여서 (Bukan 끓이어서).", romaji: "" },
{ id: 'n_r466', ch: 32, q: "우리 나라에서는 식탁 위에서 _________________ 요리를 하지 않아요.", a: ["나중에", "제일", "직접", "너무"], c: "직접", ex: "Sesuai percakapan 2. 'Di negara kami, kami tidak memasak [secara langsung/sendiri] di atas meja makan.' Secara langsung adalah 직접 (jikjeop).", romaji: "" },
{ id: 'n_r467', ch: 32, q: "가: 시험에 합격해서 한국에서 일할 수 있게 됐어요.\n나: 우와, 정말 _________________. 축하해요.", a: ["무섭네요", "잘됐네요", "덥네요", "신기하네요"], c: "잘됐네요", ex: "Sesuai kosakata baru di bab ini. A berkata ia lulus ujian dan bisa kerja di Korea. Respons yang tepat adalah 'Wah, syukurlah / [Baguslah]! Selamat.' Baguslah adalah 잘됐네요 (Jaldwaenneyo).", romaji: "" },
{ id: 'n_r468', ch: 32, q: "가: 이 음식은 어떻게 먹어요?\n나: 불에 _________________ 먹으면 돼요.", a: ["끓여서", "삶아서", "튀겨서", "구워서"], c: "끓여서", ex: "Di buku latihan 2 tertulis: '가: 이 음식은 어떻게 먹어요? 나: 끓여서 먹으면 돼요.' (Direbus kuah/Dididihkan). 끓여서 adalah jawaban resmi buku.", romaji: "" },
{ id: 'n_r469', ch: 32, q: "가: 양파는 어떻게 해요?\n나: 프라이팬에 _________________ 넣으세요.", a: ["튀겨서", "삶아서", "볶아서", "구워서"], c: "볶아서", ex: "Sesuai latihan 2 Bab 32. 'Bawang bombaynya diapakan? / [Tumislah] di wajan lalu masukkan.' Menumis bawang di wajan adalah 볶다 -> 볶아서.", romaji: "" },
{ id: 'n_r470', ch: 32, q: "여름에 뜨거운 삼계탕을 먹으면 몸이 따뜻해집니다. _________________ 여름의 더위를 이길 수 있습니다.", a: ["하지만", "그래서", "그러나", "그런데"], c: "그래서", ex: "Kalimat pertama: 'Jika makan samgyetang panas di musim panas, tubuh jadi hangat.' Kalimat kedua: '[Oleh karena itu] kita bisa mengalahkan hawa panas musim panas.' Kata sambung sebab-akibat adalah 그래서.", romaji: "" },
{ id: 'n_r471', ch: 32, q: "가: 투안 씨는 한국 음식 중에서 뭘 제일 좋아해요?\n나: 저는 _________________을/를 제일 좋아해요. 식탁 위에서 고기를 구워 먹는 것이 재미있어요.", a: ["삼계탕", "비빔밥", "삼겹살", "냉면"], c: "삼겹살", ex: "Sesuai percakapan 2. Tuan berkata ia paling suka [Samgyeopsal / Perut babi panggang]. Alasannya karena seru memanggang daging di atas meja makan (식탁 위에서 고기를 구워 먹는 것).", romaji: "" },
{ id: 'n_r472', ch: 32, q: "가: 왜 이렇게 땀을 많이 흘려요?\n나: 아까 밖에서 운동을 해서 너무 더워요. _________________ 물 한 잔만 주세요.", a: ["뜨거운", "맛없는", "매운", "시원한"], c: "시원한", ex: "'Tadi saya olahraga di luar jadi sangat kepanasan. Tolong beri saya segelas air [yang segar/dingin].' Air segar adalah 시원한 물.", romaji: "" },
{ id: 'n_r473', ch: 32, q: "한국에서는 식탁 위에 불이 있어서 _________________ 고기를 구워 먹을 수 있습니다.", a: ["직접", "먼저", "전혀", "가끔"], c: "직접", ex: "'Di Korea ada api di atas meja makan sehingga kita bisa memanggang daging [secara langsung/sendiri].' Jawabannya adalah 직접.", romaji: "" },
{ id: 'n_r474', ch: 32, q: "냄비에 물을 넣고 _________________ 후에 라면을 넣으세요.", a: ["구운", "볶은", "끓인", "튀긴"], c: "끓인", ex: "'Masukkan air ke dalam panci, lalu setelah [Mendidih / Merebus airnya], masukkan mi instan.' Mendidihkan/merebus air adalah 끓이다. Ditambah -(으)ㄴ 후에 menjadi 끓인 후에.", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r475', ch: 33, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 한복을 입다, 떡국을 먹다, 세배를 하다, 윷놀이를 하다 ]", a: ["설날", "정월대보름", "추석", "한가위"], c: "설날", ex: "Memakai hanbok, makan tteokguk, melakukan sebae, dan bermain yunnori adalah tradisi dan aktivitas utama yang dilakukan pada hari raya 'Seollal' (설날 / Tahun Baru Imlek).", romaji: "" },
{ id: 'n_r476', ch: 33, q: "다음 단어들은 무엇과 관계가 있습니까?\n[ 송편을 만들다, 보름달을 보다, 강강술래를 하다, 햇곡식 ]", a: ["휴가", "추석", "설날", "생일"], c: "추석", ex: "Membuat songpyeon, melihat bulan purnama, bermain ganggangsullae, dan biji-bijian/beras panen baru (햇곡식) adalah ciri khas dari hari raya 'Chuseok' (추석 / Hari Raya Panen).", romaji: "" },
{ id: 'n_r477', ch: 33, q: "가: 어제 제 생일 파티를 했는데 친구들이 많이 왔어요.\n나: 와, 선물도 많이 _________________.", a: ["받았어요", "받았겠어요", "받는", "받을 거예요"], c: "받았겠어요", ex: "A berkata 'Kemarin saya pesta ulang tahun, banyak teman datang.' B menyampaikan perkiraan setelah mendengar kondisi tersebut: 'Wah, [Pasti kamu mendapat] banyak kado ya!'. Tata bahasa untuk menyampaikan perkiraan masa lampau adalah '-았/었겠-'. Menjadi 받았겠어요.", romaji: "" },
{ id: 'n_r478', ch: 33, q: "가: 바루 씨는 무슨 일을 하세요?\n나: 저는 가구를 _________________ 일을 해요.", a: ["만들는", "만들은", "만드는", "만들"], c: "만드는", ex: "Sesuai contoh tata bahasa 2. 'Saya melakukan pekerjaan [yang] membuat mebel.' Tata bahasa 'yang' untuk kata kerja masa kini adalah '-는'. Karena kata dasar '만들다' (membuat) berakhiran konsonan 'ㄹ', konsonan 'ㄹ' dilesapkan sebelum ditambah '-는'. Menjadi 만드는.", romaji: "" },
{ id: 'n_r479', ch: 33, q: "'-겠-'을 바르게 사용한 대답은 무엇입니까?\n가: 요즘 일이 많아서 너무 바빠요.\n나: _________________.", a: ["일이 많아서 힘들겠어요.", "일이 많아서 힘들었어요.", "일이 많아서 힘들는.", "일이 많아서 힘들었겠어요."], c: "일이 많아서 힘들겠어요.", ex: "A berkata sedang sangat sibuk. B merespons dengan perkiraan masa kini: 'Pasti capai karena banyak pekerjaan.' Tata bahasa perkiraan masa kini adalah '-겠어요'. Menjadi 힘들겠어요. (D salah karena -었겠- untuk perkiraan masa lalu).", romaji: "" },
{ id: 'n_r480', ch: 33, q: "'-는'을 바르게 사용한 단어는 무엇입니까?\nA. 알다 → 알는 사람\nB. 듣다 → 듣는 노래\nC. 살다 → 살는 집\nD. 놀다 → 놀는 놀이", a: ["알다 → 알는 사람", "듣다 → 듣는 노래", "살다 → 살는 집", "놀다 → 놀는 놀이"], c: "듣다 → 듣는 노래", ex: "Aturan '-는' (yang - kata kerja masa kini):\nA: 알다 (konsonan ㄹ) -> 아는 사람 (Bukan 알는).\nB: 듣다 -> 듣는 노래 (Benar: Lagu yang sedang didengar. Pengecualian ㄷ tidak berubah jika bertemu konsonan ㄴ/는).\nC: 살다 (konsonan ㄹ) -> 사는 집 (Bukan 살는).\nD: 놀다 (konsonan ㄹ) -> 노는 놀이 (Bukan 놀는).", romaji: "" },
{ id: 'n_r481', ch: 33, q: "가: 지훈 씨, 설날에 고향에 잘 다녀왔어요?\n나: 네, 오랜만에 가족들을 봐서 정말 _________________.", a: ["좋았어요", "좋겠어요", "좋은", "좋아서"], c: "좋았어요", ex: "Sesuai percakapan 1. Jihoon merespons bagaimana liburan Seollalnya: 'Ya, saya [sangat senang] bisa bertemu keluarga setelah sekian lama.' Karena ia membicarakan pengalamannya sendiri di masa lalu, ia menggunakan bentuk past tense biasa '-았/었어요' (좋았어요), bukan perkiraan (-겠어요).", romaji: "" },
{ id: 'n_r482', ch: 33, q: "가: 추석 연휴에 뭐 할 거예요?\n나: 아직 잘 모르겠어요. 투안 씨는요?\n가: 저는 _________________에 가려고 해요. 거기에 가면 전통 놀이도 할 수 있어요.", a: ["은행", "우체국", "경복궁", "병원"], c: "경복궁", ex: "Sesuai percakapan 2. 'Saya berniat pergi ke [Istana Gyeongbokgung]. Jika pergi ke sana, kita bisa bermain permainan tradisional.' Istana Gyeongbokgung (경복궁) sering mengadakan acara kebudayaan saat hari raya.", romaji: "" },
{ id: 'n_r483', ch: 33, q: "지난 설날에 한국 친구 집에 가서 어른들께 세배를 했습니다. 그리고 _________________도 받았습니다.", a: ["보름달", "세뱃돈", "윷놀이", "송편"], c: "세뱃돈", ex: "'Pada Seollal lalu saya pergi ke rumah teman Korea dan melakukan sebae kepada orang tua. Lalu saya juga menerima [Angpao / 세뱃돈].' Benda yang diterima (받다) setelah Sebae adalah Sebaetdon.", romaji: "" },
{ id: 'n_r484', ch: 33, q: "한국 사람들은 명절에 보통 고향에 _________________ 사람이 많아요.", a: ["내려가는", "내려갈", "내려간", "내려가겠"], c: "내려가는", ex: "'Orang Korea pada hari raya biasanya banyak orang [yang pulang] ke kampung halaman.' Kata kerja masa kini (rutinitas) diterangkan dengan '-는'. Menjadi 내려가는.", romaji: "" },
{ id: 'n_r485', ch: 33, q: "수피카 씨는 이번 추석 연휴에 기차표가 없습니다. _________________ 고향에 안 내려갈 것입니다.", a: ["하지만", "그래서", "그런데", "그리고"], c: "그래서", ex: "Kalimat pertama (Sebab): 'Supika tidak punya tiket kereta api pada liburan Chuseok ini.' Kalimat kedua (Akibat): 'Ia tidak akan pulang kampung.' Kata sambung sebab-akibat yang tepat adalah '그래서' (Oleh karena itu).", romaji: "" },
{ id: 'n_r486', ch: 33, q: "가: 한국 사람들은 명절에 가족들이 모여서 같이 _________________을/를 지내요.\n나: 아, 조상들께 감사를 드리는 거군요.", a: ["덕담", "세배", "차례", "성묘"], c: "차례", ex: "A berkata: 'Orang Korea pada hari raya keluarganya berkumpul dan mengadakan [Upacara peringatan leluhur] bersama-sama.' B merespons: 'Ah, untuk berterima kasih kepada leluhur (조상들) rupanya.' Upacara untuk leluhur (조상) adalah 차례 (Charye).", romaji: "" },
{ id: 'n_r487', ch: 33, q: "가: 밖을 보세요. 눈이 정말 많이 오네요.\n나: 와, 밖은 날씨가 아주 _________________.", a: ["춥겠어요", "춥는군요", "따뜻하겠어요", "맑겠어요"], c: "춥겠어요", ex: "Sesuai latihan 1. A menyuruh melihat keluar karena salju turun lebat. B melihat kondisi itu dan memperkirakan: 'Wah, cuaca di luar [Pasti sangat dingin].' Perkiraan 'pasti dingin' adalah 춥다 + 겠어요 = 춥겠어요.", romaji: "" },
{ id: 'n_r488', ch: 33, q: "설날에는 서로에게 '새해 _________________ 많이 받으세요'라고 인사를 합니다.", a: ["소원", "복", "돈", "건강"], c: "복", ex: "Sesuai bacaan budaya. 'Pada hari Seollal saling memberi salam 'Semoga mendapat banyak [Berkah / 복(bok)] tahun baru'.' Kalimat sapaan utuhnya adalah '새해 복 많이 받으세요'.", romaji: "" },
{ id: 'n_r489', ch: 33, q: "한국 사람들은 추석에 갓 수확한 쌀로 밥을 짓고 _________________을/를 만들어서 먹습니다.", a: ["떡국", "윷놀이", "오곡밥", "송편"], c: "송편", ex: "'Orang Korea pada hari Chuseok memasak nasi dari beras yang baru dipanen dan membuat [Songpyeon / 송편] lalu memakannya.' Makanan khas Chuseok yang dibuat/dibentuk adalah Songpyeon.", romaji: "" },// ======================== NORMAL ========================
{ id: 'n_r490', ch: 34, q: "가: 모니카 씨, 언제 밥 먹을 거예요?\n나: 이 일을 _____ 먹으러 갈 거예요.", a: ["끝내고 나서", "끝내는 게 어때요", "끝내서", "끝내면"], c: "끝내고 나서", ex: "Untuk menyatakan melakukan suatu tindakan setelah tindakan lain selesai, digunakan tata bahasa '-고 나서'. Jadi jawaban yang tepat adalah 끝내고 나서 (setelah menyelesaikan)." },
{ id: 'n_r491', ch: 34, q: "가: 친구 집들이에 가는데 무슨 선물이 좋을까요?\n나: 두루마리 휴지를 _____?", a: ["선물하는 게 어때요", "선물하고 나서", "선물하세요", "선물했어요"], c: "선물하는 게 어때요", ex: "Pembicara kedua memberikan saran atau rekomendasi hadiah. Tata bahasa untuk memberi saran/nasihat adalah '-는 게 어때요' (bagaimana kalau...)." },
{ id: 'n_r492', ch: 34, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n아기가 태어난 후 1년이 되면 돌잔치를 합니다. 이때 아기의 미래를 알아보기 위해 여러 가지 물건을 놓고 아기가 잡게 하는 것을 _____ (이)라고 합니다.", a: ["돌잡이", "세배", "폐백", "집들이"], c: "돌잡이", ex: "Tradisi meletakkan berbagai barang agar bayi memilihnya untuk meramal masa depannya saat ulang tahun pertama disebut 돌잡이 (Doljabi)." },
{ id: 'n_r493', ch: 34, q: "가: 소식 들었어요? 현석 씨 아버지가 돌아가셨어요.\n나: 정말이요? 빨리 _____에 가 봐야겠네요.", a: ["장례식장", "결혼식장", "돌잔치", "피로연"], c: "장례식장", ex: "Karena ayah Hyun-seok meninggal dunia (돌아가셨어요), maka tempat yang harus dikunjungi adalah gedung pemakaman atau 장례식장." },
{ id: 'n_r494', ch: 34, q: "가: 진영 씨가 다음 달에 결혼해요.\n나: 네, 저도 어제 _____을/를 받았어요.", a: ["청첩장", "축의금", "선물", "휴지"], c: "청첩장", ex: "Jika ada kenalan yang akan menikah, hal yang biasa kita terima sebagai bentuk undangan adalah kartu undangan pernikahan atau 청첩장." },
{ id: 'n_r495', ch: 34, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n어른이 돌아가시면 매년 돌아가신 날에 가족들이 모여 _____을/를 지냅니다.", a: ["제사", "돌", "결혼", "생일"], c: "제사", ex: "Upacara peringatan kematian leluhur yang diadakan setiap tahun pada hari meninggalnya orang tersebut disebut 제사 (Jesa)." },
{ id: 'n_r496', ch: 34, q: "가: 한국에서는 결혼할 때 한복을 안 입어요?\n나: 결혼식이 _____ 폐백을 드리는데 그때 한복을 입어요.", a: ["끝나고 나서", "끝나는 게 어때요", "끝나기 전에", "끝나려고"], c: "끝나고 나서", ex: "Berdasarkan materi budaya pernikahan Korea, pyebaek (폐백) dilakukan setelah upacara pernikahan selesai. Maka bentuk yang tepat adalah 끝나고 나서." },
{ id: 'n_r497', ch: 34, q: "가: 장례식장에 갈 때는 무슨 옷을 입고 가야 돼요?\n나: _____.", a: ["검은색 옷을 입고 가야 돼요", "하얀색 옷을 입는 게 어때요", "한복을 입고 나서 가요", "웨딩드레스를 입어요"], c: "검은색 옷을 입고 가야 돼요", ex: "Di Korea, saat pergi melayat ke pemakaman (장례식장), aturan sopan santun berbusananya adalah wajib memakai baju berwarna hitam (검은색 옷)." },
{ id: 'n_r498', ch: 34, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 수진 씨 아기 돌인데 무슨 선물을 하면 좋을까요?\n나: 아기 옷을 선물하는 게 어때요?", a: ["돌잔치 선물", "결혼식 날짜", "장례식 복장", "집들이 음식"], c: "돌잔치 선물", ex: "Percakapan ini membahas tentang kebingungan memilih hadiah dan saran untuk memberikan hadiah baju bayi pada perayaan 돌 (ulang tahun ke-1). Topiknya adalah 돌잔치 선물." },
{ id: 'n_r499', ch: 34, q: "가: 모니카 씨, 당근하고 양파는 어떻게 할까요?\n나: 고기를 _____ 볶으세요.", a: ["삶고 나서", "삶는 게 어때요", "삶고", "삶아서"], c: "삶고 나서", ex: "Pembicara kedua menginstruksikan untuk merebus daging terlebih dahulu lalu menumisnya. Tata bahasa '-고 나서' (setelah) dilekatkan pada akar kata 삶다 (merebus)." },// ======================== NORMAL ========================
{ id: 'n_r500', ch: 35, q: "가: 투안 씨, 왜 우산을 가지고 왔어요?\n나: 밖을 보세요. 비가 ____________.", a: ["오잖아요", "오는 것 같아요", "올 거예요", "와서요"], c: "오잖아요", ex: "Pembicara kedua menunjukkan fakta yang sudah jelas terlihat (hujan turun) kepada pembicara pertama. Tata bahasa yang tepat untuk fakta yang sama-sama diketahui adalah '-잖아요'." },
{ id: 'n_r501', ch: 35, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n사람들이 우산을 쓰고 있어요. 밖에 비가 ____________.", a: ["오는 것 같아요", "오잖아요", "오려고 해요", "온 것 같아요"], c: "오는 것 같아요", ex: "Berdasarkan situasi (orang-orang memakai payung), pembicara memperkirakan bahwa di luar sedang hujan. Tata bahasa untuk perkiraan saat ini adalah '-는 것 같아요'." },
{ id: 'n_r502', ch: 35, q: "가: 이 식당에 자주 오네요.\n나: 네, 음식이 ____________.", a: ["맛있잖아요", "맛있는 것 같아요", "맛있을 거예요", "맛없잖아요"], c: "맛있잖아요", ex: "Pembicara kedua memberikan alasan yang sudah diketahui atau sudah pasti sebagai pembenaran mengapa ia sering ke sana, yaitu karena makanannya enak ('맛있잖아요')." },
{ id: 'n_r503', ch: 35, q: "가: 화장품을 사야 하는데 어떤 게 좋아요?\n나: 이거 한번 써 보세요. 싸고 ____________.", a: ["좋은 것 같아요", "좋잖아요", "좋게 해요", "좋은데"], c: "좋은 것 같아요", ex: "Pembicara kedua menyarankan kosmetik dan memberikan penilaian/perkiraan pribadinya bahwa kosmetik tersebut murah dan bagus ('좋은 것 같아요'). Karena '좋다' adalah kata sifat, digunakan '-은 것 같아요'." },
{ id: 'n_r504', ch: 35, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 흐엉 씨 고향에서도 한국 드라마가 인기가 있어요?\n나: 그럼요. 한국 드라마가 재미있잖아요.", a: ["고향의 날씨", "한국 드라마의 인기", "한국의 경제 발전", "수출품과 수입품"], c: "한국 드라마의 인기", ex: "Kedua orang tersebut sedang membicarakan apakah drama Korea populer di kampung halaman Heong, dan Heong membenarkannya karena seru. Topiknya adalah popularitas drama Korea." },
{ id: 'n_r505', ch: 35, q: "가: 방가 씨가 한국어 실력이 많이 늘었어요.\n나: 네, 요즘 한국어를 열심히 ____________.", a: ["공부하는 것 같아요", "공부하잖아요", "공부할 것 같아요", "공부한 것 같아요"], c: "공부하는 것 같아요", ex: "Pembicara kedua memperkirakan penyebab meningkatnya bahasa Korea Bang-ga berdasarkan observasinya saat ini. Bentuk perkiraan/tebakan yang tepat untuk kata kerja (공부하다) saat ini adalah '공부하는 것 같아요'." },
{ id: 'n_r506', ch: 35, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n한국의 경제는 수출 중심입니다. 2000년대부터는 휴대전화나 컴퓨터와 같은 ____________의 수출이 크게 늘었습니다.", a: ["전자제품", "농산물", "의류", "화장품"], c: "전자제품", ex: "Berdasarkan sejarah ekonomi Korea, sejak tahun 2000-an ekspor untuk barang-barang seperti handphone dan komputer meningkat. Barang-barang ini masuk kategori barang elektronik (전자제품)." },
{ id: 'n_r507', ch: 35, q: "가: 한국의 대표적인 수출품은 뭐예요?\n나: ____________.", a: ["휴대전화하고 자동차예요", "수입을 많이 해요", "경제가 많이 발전했어요", "요즘 경제가 안 좋아요"], c: "휴대전화하고 자동차예요", ex: "Pertanyaannya adalah 'Apa produk ekspor representatif Korea?'. Jawaban yang menyebutkan barang ekspor adalah '휴대전화하고 자동차예요' (Handphone dan mobil)." },
{ id: 'n_r508', ch: 35, q: "가: 모니카 씨, 이 사과는 어디에서 샀어요?\n나: 시장에서 샀어요. 시장이 ____________.", a: ["싸잖아요", "비싸잖아요", "싼 것 같아요", "비쌀 거예요"], c: "싸잖아요", ex: "Monika membeli apel di pasar dan memberikan alasan kuat yang umumnya orang tahu, yaitu pasar lebih murah (싸다 + -잖아요 = 싸잖아요)." },
{ id: 'n_r509', ch: 35, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n외국에 물건을 파는 것을 수출이라고 하고, 외국에서 물건을 사서 들어오는 것을 ____________(이)라고 합니다.", a: ["수입", "무역", "발전", "한류"], c: "수입", ex: "Menjual barang ke luar negeri disebut ekspor (수출), sedangkan membeli/mendatangkan barang dari luar negeri disebut impor (수입)." },// ======================== NORMAL ========================
{ id: 'n_r510', ch: 36, q: "가: 지훈 씨가 오늘 ____________.\n나: 네, 어제 야근을 해서 그래요.", a: ["피곤해 보여요", "피곤하게 해요", "피곤할 거예요", "피곤했어요"], c: "피곤해 보여요", ex: "Tata bahasa '-아/어 보이다' digunakan untuk menyatakan dugaan atau penilaian dari apa yang terlihat oleh mata. Kata sifat '피곤하다' diubah menjadi '피곤해 보여요' (kelihatan lelah)." },
{ id: 'n_r511', ch: 36, q: "가: 리한 씨, 단추를 좀 푸는 게 어때요? 너무 ____________.\n나: 그래요? 전 별로 불편하지 않아요.", a: ["답답해 보여요", "답답하게 해요", "답답한 것 같아요", "답답해요"], c: "답답해 보여요", ex: "Pembicara pertama secara langsung melihat Rihan tampak pengap/sesak, sehingga menggunakan tata bahasa visual '답답해 보여요' (terlihat sesak/pengap)." },
{ id: 'n_r512', ch: 36, q: "가: 직장에서는 예의 ____________ 행동해야 해요.\n나: 맞아요. 다른 사람에게 피해를 주면 안 돼요.", a: ["있게", "있고", "있어서", "있으면"], c: "있게", ex: "Untuk mengubah kata sifat menjadi kata keterangan (secara/dengan) yang menerangkan kata kerja 행동하다 (bertindak), digunakan '-게'. '예의 있다' menjadi '예의 있게' (bertindak dengan sopan)." },
{ id: 'n_r513', ch: 36, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n여기는 공공장소니까 그렇게 ____________ 떠들면 안 돼요.", a: ["크게", "크고", "커서", "크면"], c: "크게", ex: "Kata sifat '크다' (besar/keras) harus diubah menjadi kata keterangan yang menerangkan kata kerja '떠들다' (membuat keributan). Menggunakan '-게' menjadi '크게' (dengan keras)." },
{ id: 'n_r514', ch: 36, q: "가: 직장 생활을 할 때는 어떤 옷차림을 해야 합니까?\n나: 항상 단정하고 ____________ 옷을 입어야 합니다.", a: ["깔끔하게", "불쾌하게", "답답하게", "위험하게"], c: "깔끔하게", ex: "Pakaian di tempat kerja memiliki aturan standar, yaitu harus '단정하고 깔끔하게' (dengan rapi dan bersih)." },
{ id: 'n_r515', ch: 36, q: "가: 나이가 같은 사람한테 반말을 하면 안 돼요?\n나: 아직 친하지 않으면 다른 사람을 ____________ 할 수 있어요.", a: ["불쾌하게", "불쾌하고", "존중하게", "존중하고"], c: "불쾌하게", ex: "Berbicara informal kepada orang yang belum akrab bisa membuat mereka merasa tidak nyaman. Kata sifat 불쾌하다 dilekatkan '-게' menjadi '불쾌하게' (membuat menjadi tidak nyaman)." },
{ id: 'n_r516', ch: 36, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n사무실에서 일하는 직원은 보통 양복이나 정장을 입고 ____________을/를 맵니다.", a: ["넥타이", "작업복", "안전모", "지퍼"], c: "넥타이", ex: "Pegawai kantoran (사무직) memiliki aturan berpakaian memakai jas atau setelan resmi (정장) dan harus memakai dasi (넥타이를 매다)." },
{ id: 'n_r517', ch: 36, q: "가: 작업복을 입을 때는 어떻게 해야 합니까?\n나: 일할 때 안전하도록 점퍼의 지퍼를 목까지 ____________ 합니다.", a: ["올려야", "내려야", "풀어야", "묶어야"], c: "올려야", ex: "Saat memakai pakaian kerja lapangan seperti jaket (점퍼), resletingnya harus dinaikkan penuh (지퍼를 올리다) sampai leher demi keamanan dari mesin." },
{ id: 'n_r518', ch: 36, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 직장에서 동료들과 잘 지내려면 어떻게 해야 해요?\n나: 서로 존중하고 배려해야 해요. 그리고 친한 동료에게도 함부로 하면 안 돼요.", a: ["직장 예절", "작업복 입는 법", "출근 시간", "안전 수칙"], c: "직장 예절", ex: "Percakapan ini membahas tentang rasa saling menghormati, kepedulian, dan tidak bersikap sembarangan di kantor. Ini semua adalah pilar dari tata krama di tempat kerja (직장 예절)." },// ======================== NORMAL ========================
{ id: 'n_r520', ch: 37, q: "가: 복도나 계단을 깨끗하게 ____________.\n나: 네, 알겠습니다.", a: ["사용합시다", "사용합니다", "사용한 것 같아요", "사용하세요"], c: "사용합시다", ex: "Untuk mengajak atau menyarankan sesuatu secara formal namun setara, digunakan tata bahasa -(으)ㅂ시다. 'Mari kita gunakan...' menjadi 사용합시다." },
{ id: 'n_r521', ch: 37, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n밤에는 다른 사람들이 자고 있으니까 큰 소리로 ____________.", a: ["떠듭시다", "떠들지 맙시다", "떠드는 동안", "떠들어야 합니다"], c: "떠들지 맙시다", ex: "Untuk ajakan negatif 'mari kita jangan...', kata kerja '떠들다' (berisik/berbicara keras) diubah menjadi '떠들지 맙시다'." },
{ id: 'n_r522', ch: 37, q: "가: 외출할 때는 전기난로를 꼭 끄세요.\n나: 네, ____________ 쓸게요.", a: ["신경", "규칙", "시설", "보고"], c: "신경", ex: "Frasa '신경(을) 쓰다' berarti memikirkan dengan teliti atau menaruh perhatian. Pembicara kedua berjanji akan memperhatikannya (신경 쓸게요)." },
{ id: 'n_r523', ch: 37, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n제가 방을 청소하는 ____________ 리한 씨는 세탁기를 돌려 주세요.", a: ["동안", "시간", "후에", "전에"], c: "동안", ex: "Tata bahasa '-는 동안' digunakan untuk menyatakan 'selama' suatu aktivitas berlangsung. 'Selama saya membersihkan kamar...' menjadi 청소하는 동안." },
{ id: 'n_r524', ch: 37, q: "가: 기숙사 시설물이 파손되면 어떻게 해야 해요?\n나: 즉시 ____________에게 보고해야 해요.", a: ["외부인", "룸메이트", "관리인", "친구"], c: "관리인", ex: "Jika fasilitas asrama rusak (시설물이 파손되면), harus segera dilaporkan kepada pengelola asrama (관리인)." },
{ id: 'n_r525', ch: 37, q: "가: 투안 씨를 기다리는 ____________ 같이 커피를 마실까요?\n나: 네, 그럽시다.", a: ["동안", "후에", "때문에", "전에"], c: "동안", ex: "Untuk menyatakan aktivitas meminum kopi yang dilakukan 'selama' menunggu Tuan, digunakan tata bahasa '-는 동안' pada kata kerja 기다리다." },
{ id: 'n_r526', ch: 37, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 기숙사 방에서 요리를 해도 돼요?\n나: 아니요, 조리 기구는 식당에서만 사용해야 해요.", a: ["기숙사 생활 규칙", "전기난로 사용법", "한국의 주거 형태", "세탁실 이용 시간"], c: "기숙사 생활 규칙", ex: "Percakapan ini membahas tentang boleh tidaknya memasak di kamar asrama, yang merupakan bagian dari tata tertib kehidupan asrama (기숙사 생활 규칙)." },
{ id: 'n_r527', ch: 37, q: "가: 선풍기를 켜고 자면 안 돼요.\n나: 네, 자는 ____________ 사용하지 않을게요.", a: ["동안에는", "후에는", "전에는", "때문에"], c: "동안에는", ex: "Pembicara kedua berjanji tidak akan menggunakannya 'selama' tidur. 자다 + -는 동안 = 자는 동안(에는)." },
{ id: 'n_r528', ch: 37, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n아무도 없을 때 전기난로가 켜 있으면 화재가 날 수 있습니다. 그래서 방에서 나갈 때는 반드시 스위치를 끄고 플러그를 ____________ 합니다.", a: ["꽂아야", "뽑아야", "켜야", "닦아야"], c: "뽑아야", ex: "Untuk mencegah kebakaran saat tidak ada orang, selain mematikan saklar, stop kontaknya juga harus dicabut. 'Mencabut stop kontak' adalah 플러그를 뽑다." },
{ id: 'n_r529', ch: 37, q: "가: 휴게실에서 냄새 나는 음식물을 먹어도 돼요?\n나: 아니요, 냄새 나는 음식물은 ____________에서 드세요.", a: ["방", "식당", "샤워실", "복도"], c: "식당", ex: "Menurut aturan asrama, makanan yang mengeluarkan bau harus dimakan di kantin atau ruang makan (식당), bukan di ruang istirahat (휴게실)." },
{ id: 'n_r519', ch: 36, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n한국의 직장에서는 아랫사람에게도 함부로 대하지 말고 ____________(으)로 대해야 합니다.", a: ["예의", "반말", "불만", "피해"], c: "예의", ex: "Meskipun kepada orang yang lebih muda atau bawahan (아랫사람), kita dilarang bersikap sembarangan dan wajib memperlakukannya dengan sikap sopan santun (예의)." },// ======================== NORMAL ========================
{ id: 'n_r530', ch: 38, q: "가: 투안 씨 회사는 분위기가 어때요?\n나: 동료들끼리 서로 ____________ 편이에요.", a: ["위해 주는", "위해 주려고", "위해 준", "위해 줘서"], c: "위해 주는", ex: "Tata bahasa '-는 편이다' (termasuk/lumayan) dilekatkan pada kata kerja present tense menggunakan '-는'. '위해 주다' (saling menghibur/membantu) menjadi '위해 주는 편이에요'." },
{ id: 'n_r531', ch: 38, q: "가: 리한 씨, 회사 규율이 어때요?\n나: 우리 회사는 규율이 좀 ____________.", a: ["엄격한 편이에요", "엄격하고 싶어요", "엄격하면 돼요", "엄격한 것 같아요"], c: "엄격한 편이에요", ex: "Untuk menyatakan kecenderungan atau 'lumayan ketat', kata sifat '엄격하다' digabung dengan '-(으)ㄴ 편이다' menjadi '엄격한 편이에요' (termasuk ketat)." },
{ id: 'n_r532', ch: 38, q: "가: 지훈 씨하고 수피카 씨가 왜 싸웠어요?\n나: 서로 ____________.", a: ["오해했다고 해요", "오해하는 편이에요", "화해했다고 해요", "화해하는 편이에요"], c: "오해했다고 해요", ex: "Pembicara sedang menyampaikan kejadian lampau yang ia dengar (kalimat tidak langsung). 'Mereka katanya (telah) saling salah paham' menggunakan 'A/V-았/었다고 하다', menjadi '오해했다고 해요'." },
{ id: 'n_r533', ch: 38, q: "가: 어제 두 사람이 화해했어요?\n나: 네, 투안 씨가 먼저 미안하다고 ____________.", a: ["사과했다고 해요", "사과할 거예요", "사과하는 편이에요", "사과하려고 해요"], c: "사과했다고 해요", ex: "Pembicara kedua mengutip tindakan minta maaf yang sudah terjadi di masa lampau. Tata bahasa kutipan tidak langsung untuk lampau adalah '-았/었다고 하다', menjadi '사과했다고 해요' (katanya dia sudah meminta maaf)." },
{ id: 'n_r534', ch: 38, q: "가: 직장에서 나이가 같은 동료를 부를 때 어떻게 해야 해요?\n나: 이름 뒤에 '____________'(을)를 붙여서 부르면 돼요.", a: ["씨", "님", "형", "누나"], c: "씨", ex: "Di tempat kerja Korea, panggilan untuk rekan kerja dengan jabatan setara atau tanpa jabatan adalah menambahkan '-씨' di belakang namanya (contoh: 투안 씨)." },
{ id: 'n_r535', ch: 38, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n회사에서 사장님이나 부장님을 부를 때는 직책 뒤에 '____________'(을)를 붙여야 합니다.", a: ["씨", "님", "형", "동생"], c: "님", ex: "Untuk memanggil atasan atau orang dengan jabatan (직책) yang lebih tinggi di kantor, wajib menambahkan partikel hormat '-님' di belakang jabatannya (사장님, 부장님)." },
{ id: 'n_r536', ch: 38, q: "가: 요즘 일이 많아서 힘들지 않아요?\n나: 괜찮아요. 우리 회사는 윗사람들이 아랫사람을 많이 ____________ 편이라서 일하기 좋아요.", a: ["무시하는", "배려해 주는", "욕을 하는", "화를 내는"], c: "배려해 주는", ex: "Alasan pembicara kedua merasa nyaman bekerja meskipun banyak pekerjaan adalah karena atasannya selalu membantu dan peduli ('배려해 주는 편이라서')." },
{ id: 'n_r537', ch: 38, q: "가: 아까 왜 그렇게 화를 냈어요?\n나: 바루 씨가 제 말을 ____________ 줄 알았어요.", a: ["배려하는", "격려하는", "무시하는", "화해하는"], c: "무시하는", ex: "Dalam dialog 38, alasan timbulnya kemarahan adalah karena ia mengira lawannya mengabaikan atau tidak mengacuhkannya ('무시하는 줄 알았어요')." },
{ id: 'n_r538', ch: 38, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n오해가 생기면 서로 대화를 해서 빨리 오해를 ____________ 합니다.", a: ["풀어야", "해야", "쳐야", "맞아야"], c: "풀어야", ex: "Jika terjadi kesalahpahaman (오해), hal yang harus dilakukan adalah meluruskannya atau menyelesaikannya. Kata kerja yang tepat adalah 오해를 풀다 (풀어야 합니다)." },
{ id: 'n_r539', ch: 38, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 투안 씨 회사는 분위기가 어때요?\n나: 우리 회사는 분위기가 참 좋아요. 윗사람과 아랫사람 사이도 좋고요.", a: ["직장 분위기", "동료와의 갈등", "회식 장소", "직장 호칭"], c: "직장 분위기", ex: "Kedua orang tersebut membicarakan keadaan dan hubungan antar karyawan di kantor. Ini berarti topiknya adalah suasana tempat kerja (직장 분위기)." },// ======================== NORMAL ========================
{ id: 'n_r540', ch: 39, q: "가: 지훈 씨가 뭐라고 해요?\n나: 오늘 퇴근 후에 ____________.", a: ["한잔하자고 해요", "한잔하라고 해요", "한잔하는 것 같아요", "한잔하고 싶어요"], c: "한잔하자고 해요", ex: "Karena Jihun 'mengajak' minum bersama, kita menggunakan kutipan tidak langsung untuk ajakan, yaitu '-자고 하다'. Jadi jawabannya 한잔하자고 해요 (dia mengajak untuk minum)." },
{ id: 'n_r541', ch: 39, q: "가: 공장장님이 뭐라고 하세요?\n나: 오늘 모두 회식에 ____________.", a: ["참석하라고 하세요", "참석하자고 하세요", "참석한 것 같아요", "참석할 거예요"], c: "참석하라고 하세요", ex: "Kepala Pabrik 'menyuruh' semua orang hadir. Kutipan tidak langsung untuk perintah adalah '-(으)라고 하다'. Jadi jawabannya 참석하라고 하세요." },
{ id: 'n_r542', ch: 39, q: "가: 투안 씨가 2차는 어디로 갈까요?\n나: 1차에서 고기를 많이 먹었으니까 노래방에 ____________.", a: ["가자고 해요", "가라고 해요", "갈 것 같아요", "가려고 해요"], c: "가자고 해요", ex: "Tuan 'mengajak' pergi ke karaoke. Tata bahasa ajakan tidak langsung adalah '-자고 하다', sehingga menjadi 가자고 해요." },
{ id: 'n_r543', ch: 39, q: "가: 리한 씨, 오늘 보너스 받았다면서요?\n나: 네, 갑자기 부자가 된 것 같아요. 제가 오늘은 ____________.", a: ["한턱낼게요", "건배할게요", "환영할게요", "빠질게요"], c: "한턱낼게요", ex: "Karena mendapat bonus dan merasa kaya, pembicara kedua menawarkan diri untuk menraktir (한턱내다)." },
{ id: 'n_r544', ch: 39, q: "가: 오늘 저녁에 회식이 있어요?\n나: 네, 새로 온 타타 씨를 ____________ 자리예요.", a: ["환영하는", "환송하는", "축하하는", "무시하는"], c: "환영하는", ex: "Acara makan untuk orang yang baru datang (새로 온 사람) adalah acara penyambutan atau 환영하는 자리." },
{ id: 'n_r545', ch: 39, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n상사에게 술을 받을 때는 반드시 ____________ 받아야 합니다.", a: ["두 손으로", "한 손으로", "고개를 돌리고", "술을 마시고"], c: "두 손으로", ex: "Menurut tata krama minum di Korea, saat menerima minuman (술을 받을 때) dari atasan harus menggunakan kedua tangan (두 손으로)." },
{ id: 'n_r546', ch: 39, q: "가: 사장님께서 아직 안 오셨네요.\n나: 네, 조금 늦으실 것 같아요. 우리 먼저 ____________.", a: ["먹으라고 하세요", "먹자고 하세요", "먹은 것 같아요", "먹을 거예요"], c: "먹으라고 하세요", ex: "Direktur memberikan instruksi/perintah dari jauh agar karyawan makan duluan. Kutipan perintah menggunakan '-(으)라고 하다', menjadi 먹으라고 하세요." },
{ id: 'n_r547', ch: 39, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n직원들이 같이 모여서 등산이나 운동을 하면 동료들과 더 ____________ 수 있습니다.", a: ["친해질", "빠질", "나빠질", "어려워질"], c: "친해질", ex: "Melakukan kegiatan bersama seperti mendaki dan berolahraga bisa membuat kita semakin akrab (친해지다) dengan rekan kerja." },
{ id: 'n_r548', ch: 39, q: "가: 상사 앞에서 술을 마실 때는 어떻게 해야 돼요?\n나: 고개를 상사 ____________ 돌리고 마셔야 돼요.", a: ["반대쪽으로", "앞으로", "위쪽으로", "아래쪽으로"], c: "반대쪽으로", ex: "Saat minum di depan atasan, kita harus memalingkan wajah ke arah yang berlawanan dari atasan (반대쪽으로 돌리다)." },
{ id: 'n_r549', ch: 39, q: "가: 모니카 씨한테 무슨 일이 있어요? 회식에 안 왔어요.\n나: 고향에서 가족들이 ____________.", a: ["왔대요", "오자고 해요", "오라고 해요", "올 거예요"], c: "왔대요", ex: "Bentuk singkatan dari kutipan pernyataan masa lampau (왔다고 해요) adalah 왔대요 (Katanya keluarganya telah datang)." },// ======================== NORMAL ========================
{ id: 'n_r550', ch: 40, q: "가: 수루 씨, 제 옆에 앉으세요.\n나: 민수 씨, 이런 거 ____________ 직장 내 성희롱에 해당하는 거 알지요?", a: ["강요하면", "신고하면", "표현하면", "요구하면"], c: "강요하면", ex: "Suru menegur Minsu yang memaksanya duduk di sebelahnya. Tindakan memaksakan kehendak ('강요하다') dalam konteks seperti ini bisa masuk kategori pelecehan. Jawabannya adalah 강요하면 (jika memaksa)." },
{ id: 'n_r551', ch: 40, q: "가: 어제 지훈 씨가 뭐라고 했어요?\n나: 자기가 내일 휴가를 ____________.", a: ["쓸 거래요", "쓸 거냐고 해요", "쓰자고 해요", "쓰라고 해요"], c: "쓸 거래요", ex: "Pembicara kedua mengutip pernyataan Jihoon di masa depan. Bentuk singkatan (축약형) dari kalimat tidak langsung untuk pernyataan '쓸 것이라고 해요' (dia bilang dia akan menggunakan) adalah '쓸 거래요'." },
{ id: 'n_r552', ch: 40, q: "가: 반장님이 내일 일찍 ____________.\n나: 네, 알겠습니다. 내일은 일찍 출근할게요.", a: ["나오래요", "나오재요", "나온대요", "나오냬요"], c: "나오래요", ex: "Mandor (반장님) memberikan 'perintah' untuk datang awal besok. Bentuk singkatan dari kutipan perintah (나오라고 해요) adalah '나오래요' (katanya disuruh datang)." },
{ id: 'n_r553', ch: 40, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n주말에 시간이 있으면 책을 ____________ 영화를 봅니다.", a: ["읽거나", "읽지만", "읽어서", "읽으면"], c: "읽거나", ex: "Tata bahasa '-거나' digunakan untuk menunjukkan pilihan di antara dua kata kerja (atau). 'Membaca atau menonton film' menjadi '책을 읽거나 영화를 봅니다'." },
{ id: 'n_r554', ch: 40, q: "가: 칸 씨, 아까 지은 씨가 화를 냈는데 무슨 일 있었어요?\n나: 저는 친해서 농담으로 한 말이었는데 지은 씨가 ____________을/를 느낀 것 같아요.", a: ["불쾌감", "안도감", "환영", "친근감"], c: "불쾌감", ex: "Khan berkata ia hanya bercanda, namun Ji-eun marah. Ini berarti candaan tersebut memicu perasaan tidak nyaman atau '불쾌감'." },
{ id: 'n_r555', ch: 40, q: "가: 상담센터에서 아까 뭐라고 물어봤어요?\n나: 저에게 그 일 때문에 거부감이 ____________ 물어봤어요.", a: ["들었냐고", "들었다고", "들자고", "들라고"], c: "들었냐고", ex: "Kutipan tidak langsung untuk sebuah 'pertanyaan' (물어봤어요) menggunakan tata bahasa '-냐고 하다'. Jadi jawabannya adalah '들었냐고' (ditanya apakah [saya] merasakan keberatan)." },
{ id: 'n_r556', ch: 40, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n어제 밤에 집에 도둑이 들어서 경찰서에 바로 ____________.", a: ["신고했어요", "강요했어요", "요구했어요", "표현했어요"], c: "신고했어요", ex: "Tindakan yang paling tepat jika ada pencuri (도둑) yang masuk ke rumah adalah melapor ke polisi. Kosakata untuk melapor adalah '신고하다'." },
{ id: 'n_r557', ch: 40, q: "가: 직장 동료가 저에게 음담패설을 해서 너무 스트레스예요.\n나: 원하지 않는 일에는 분명하게 거부 의사를 ____________ 합니다.", a: ["표현해야", "강요해야", "숨겨야", "요구해야"], c: "표현해야", ex: "Jika menerima perlakuan yang tidak diinginkan seperti omongan kotor, kita harus secara jelas 'mengungkapkan' atau menyatakan penolakan (의사를 표현하다)." },
{ id: 'n_r558', ch: 40, q: "가: 사장님이 이번 주말에 다 같이 등산하러 ____________.\n나: 네, 다른 직원들에게도 모두 참석하라고 전할게요.", a: ["가재요", "가래요", "간대요", "가냬요"], c: "가재요", ex: "Sajangnim 'mengajak' (다 같이) pergi mendaki. Bentuk singkatan dari kutipan ajakan (가자고 해요) adalah '가재요' (katanya mari kita pergi)." },
{ id: 'n_r559', ch: 40, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 성희롱을 당하면 어떻게 해야 해요?\n나: 제일 먼저 싫다는 의사를 분명히 표현하세요. 그리고 증거를 모아서 센터에 신고해야 해요.", a: ["성희롱의 대처 방법", "성희롱의 종류", "성희롱의 처벌", "성희롱 예방 교육"], c: "성희롱의 대처 방법", ex: "Percakapan ini membahas langkah-langkah yang harus diambil (menolak, mengumpulkan bukti, melapor) jika menjadi korban pelecehan seksual. Topiknya adalah cara menghadapi/menangani pelecehan seksual (성희롱의 대처 방법)." },// ======================== NORMAL ========================
{ id: 'n_r560', ch: 41, q: "가: 못을 박아야 하는데 뭘로 박으면 돼요?\n나: ____________ 박으세요.", a: ["망치로", "톱으로", "니퍼로", "스패너로"], c: "망치로", ex: "Paku (못) dipasang/dipalu menggunakan palu (망치). Tata bahasa '-(으)로' menunjukkan alat yang digunakan." },
{ id: 'n_r561', ch: 41, q: "가: 철사는 무엇으로 끊으면 될까요?\n나: ____________ 끊으세요.", a: ["펜치로", "드라이버로", "망치로", "대패로"], c: "펜치로", ex: "Kawat (철사) dipotong/diputus menggunakan tang (펜치) atau nipper." },
{ id: 'n_r562', ch: 41, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n나사못을 박을 때는 망치보다 ____________(으)로 하는 것이 좋습니다.", a: ["드라이버", "톱", "니퍼", "송곳"], c: "드라이버", ex: "Untuk memasang sekrup (나사못), lebih baik menggunakan obeng (드라이버) karena sekrup harus diputar, bukan dipukul dengan palu." },
{ id: 'n_r563', ch: 41, q: "가: 지금 무슨 작업을 하고 있어요?\n나: 핸드카로 물건을 ____________.", a: ["운반하고 있어요", "용접하고 있어요", "자르고 있어요", "뚫고 있어요"], c: "운반하고 있어요", ex: "Hand cart/troli tangan (핸드카) digunakan untuk memindahkan/mengangkut barang (물건을 운반하다). Karena sedang dilakukan, menggunakan '-고 있어요'." },
{ id: 'n_r564', ch: 41, q: "가: 전기 드릴로 벽에 구멍을 ____________?\n나: 네, 거의 다 끝났어요.", a: ["뚫고 있어요", "박고 있어요", "펴고 있어요", "조이고 있어요"], c: "뚫고 있어요", ex: "Membuat lubang (구멍) di dinding dengan bor listrik (전기 드릴) menggunakan kata kerja 뚫다 (melubangi). Sedang berlangsung berarti 뚫고 있어요." },
{ id: 'n_r565', ch: 41, q: "가: 리한 씨, 지금 공구함에 드라이버 있어요?\n나: 아니요, 투안 씨가 드라이버로 나사못을 .", a: ["풀고 있어요", "뚫고 있어요", "자르고 있어요", "구부리고 있어요"], c: "풀고 있어요", ex: "Obeng (드라이버) digunakan untuk melepas/melonggarkan sekrup (나사못을 풀다) atau mengencangkannya." },
{ id: 'n_r566', ch: 41, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n이 책상은 나무 만들었어요.", a: ["로", "가", "를", "에"], c: "로", ex: "Untuk menyatakan bahan atau materi pembuat sesuatu (kayu), digunakan partikel '-(으)로'. Karena 나무 berakhiran vokal, memakai '로'." },
{ id: 'n_r567', ch: 41, q: "가: 포장은 다 끝났어요?\n나: 아니요, 아직 밴딩기로 ____________.", a: ["포장하고 있어요", "운반하고 있어요", "붙이고 있어요", "절단하고 있어요"], c: "포장하고 있어요", ex: "Mesin bending (밴딩기) digunakan untuk membungkus/mengemas (포장하다). Karena belum selesai, ia sedang melakukannya (포장하고 있어요)." },
{ id: 'n_r568', ch: 41, q: "가: 작업장에서 용접을 하고 있지요?\n나: 네, 철판을 ____________.", a: ["붙이고 있어요", "자르고 있어요", "뚫고 있어요", "조이고 있어요"], c: "붙이고 있어요", ex: "Pekerjaan las (용접) adalah pekerjaan menyambung/menempelkan (붙이다) pelat besi atau logam (철판)." },
{ id: 'n_r569', ch: 41, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 이 나무를 뭘로 자를까요?\n나: 톱으로 자르세요.", a: ["필요한 작업 도구", "가구 조립 방법", "작업장 안전 수칙", "전기 드릴 사용법"], c: "필요한 작업 도구", ex: "Dialog membicarakan alat apa (톱/gergaji) yang dibutuhkan untuk memotong kayu. Topiknya adalah alat kerja yang dibutuhkan (필요한 작업 도구)." },// ======================== NORMAL ========================
{ id: 'n_r570', ch: 42, q: "가: 이 기계를 어떻게 ____________ 알아요?\n나: 네, 안전 스위치를 먼저 누르면 돼요.", a: ["작동하는지", "작동해서", "작동하고", "작동하지만"], c: "작동하는지", ex: "Tata bahasa '-는지 알다/모르다' digunakan untuk menyatakan tahu/tidak tahu cara melakukan sesuatu. Jawabannya adalah 작동하는지 (tahu bagaimana cara beroperasi)." },
{ id: 'n_r571', ch: 42, q: "가: 이 전구를 어떻게 ____________ 알아요?\n나: 네, 이쪽을 잡고 돌려서 꽂으세요.", a: ["끼우는지", "자르는지", "오리는지", "접는지"], c: "끼우는지", ex: "Kata kerja untuk memasang lampu (전구) adalah 끼우다. Dengan tata bahasa '-는지 알다', menjadi 끼우는지 (tahu bagaimana cara memasangnya)." },
{ id: 'n_r572', ch: 42, q: "가: 오늘 300개를 다 만들 수 있을까요?\n나: 아니요, 시간이 부족해서 ____________.", a: ["힘들 것 같아요", "힘든 것 같아요", "힘들었어요", "힘들어요"], c: "힘들 것 같아요", ex: "Tata bahasa '-(으)ㄹ 것 같다' digunakan untuk perkiraan di masa depan. 'Sepertinya akan sulit' diterjemahkan menjadi 힘들 것 같아요." },
{ id: 'n_r573', ch: 42, q: "가: 오늘 작업은 언제 끝날까요?\n나: 거의 다 했어요. 6시쯤 ____________.", a: ["끝날 것 같아요", "끝난 것 같아요", "끝나지 않아요", "끝날 거예요"], c: "끝날 것 같아요", ex: "Memperkirakan selesainya pekerjaan di waktu yang akan datang menggunakan '-(으)ㄹ 것 같다'. Jadi 끝날 것 같아요 (sepertinya akan selesai)." },
{ id: 'n_r574', ch: 42, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n기계를 사용할 때 제일 먼저 손잡이에 있는 안전 스위치를 ____________ 합니다.", a: ["눌러야", "오려야", "접어야", "잘라야"], c: "눌러야", ex: "Tombol keamanan (안전 스위치) harus ditekan. Kata kerja menekan adalah 누르다, sehingga menjadi 눌러야 합니다 (harus menekan)." },
{ id: 'n_r575', ch: 42, q: "가: 상자 제작은 다 끝났어요?\n나: 이제 상자를 ____________ 테이프를 붙이면 완성됩니다.", a: ["접고", "자르고", "재고", "달고"], c: "접고", ex: "Setelah dipotong, langkah selanjutnya sebelum ditempel selotip (테이프를 붙이다) adalah melipat kardus tersebut. Melipat adalah 접다 -> 접고." },
{ id: 'n_r576', ch: 42, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n회전하는 기계를 사용할 때는 손이 말려 들어갈 수 있으므로 장갑을 ____________ 맨손으로 작업해야 합니다.", a: ["벗고", "끼고", "신고", "입고"], c: "벗고", ex: "Berdasarkan pedoman keselamatan, saat memakai mesin berputar (회전하는 기계), sarung tangan harus dilepas (장갑을 벗다) dan menggunakan tangan kosong (맨손)." },
{ id: 'n_r577', ch: 42, q: "가: 이 플러그를 어디에 ____________ 알아요?\n나: 저기 벽에 있는 콘센트에 꽂으세요.", a: ["꽂는지", "빼는지", "거는지", "조절하는지"], c: "꽂는지", ex: "Pertanyaan ini menanyakan cara menancapkan colokan (플러그). Kata kerja yang tepat adalah 꽂다 -> 꽂는지 알아요? (apakah Anda tahu di mana menancapkannya?)." },
{ id: 'n_r578', ch: 42, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 먼저 자로 골판지 크기를 잰 후에 칼로 자르세요.\n나: 네, 그다음에는 선을 따라 접고 테이프를 붙일게요.", a: ["포장 작업", "기계 수리", "작업장 청소", "폐기물 처리"], c: "포장 작업", ex: "Dialog ini membicarakan proses mengukur, memotong, melipat, dan mengelem kardus bergelombang (골판지). Topiknya adalah pekerjaan pengemasan/pembuatan kardus (포장 작업)." },
{ id: 'n_r579', ch: 42, q: "가: 바루 씨, 오전에는 무슨 작업을 했어요?\n나: 골판지를 크기에 맞게 ____________ 작업을 다 끝냈어요.", a: ["자르는", "다 달은", "작동하는", "적재하는"], c: "자르는", ex: "Dalam konteks pembuatan kardus (골판지), pekerjaan awal sesuai ukurannya adalah memotong. Maka jawabannya adalah 자르는 (memotong)." },// ======================== NORMAL ========================
{ id: 'n_r580', ch: 43, q: "가: 1층에 있는 철근을 3층으로 ____________?\n나: 네, 어제 다 옮겼어요.", a: ["옮겨 놓았지요", "옮겨 줄게요", "옮길 거예요", "옮기고 있어요"], c: "옮겨 놓았지요", ex: "Pembicara pertama memastikan tindakan yang diduga sudah selesai (memindahkan besi). Tata bahasa '-아/어 놓다' (melakukan dan membiarkan hasilnya) digabung dengan '-지요' (kan?) menjadi 옮겨 놓았지요? (sudah dipindahkan, kan?)." },
{ id: 'n_r581', ch: 43, q: "가: 반장님, 굴착기로 땅을 ____________?\n나: 네, 1미터 정도 깊게 파 주세요.", a: ["파 놓을까요", "파 놓았어요", "파면 돼요", "파고 있어요"], c: "파 놓을까요", ex: "Pekerja menawarkan diri untuk menggali tanah dengan ekskavator. Penggunaan '-아/어 놓다' digabung dengan tawaran '-(으)ㄹ까요' menjadi 파 놓을까요? (apakah sebaiknya saya gali?)." },
{ id: 'n_r582', ch: 43, q: "가: 이 벽돌은 어떻게 할까요?\n나: 저쪽 구석에 잘 ____________.", a: ["쌓아 놓으세요", "쌓았지요", "쌓고 있어요", "쌓으려고 해요"], c: "쌓아 놓으세요", ex: "Mandor menyuruh pekerja untuk menumpuk batu bata dan membiarkan tumpukan itu di sana. Perintah yang tepat menggunakan '-아/어 놓으세요' menjadi 쌓아 놓으세요 (tolong tumpuk/susun di sana)." },
{ id: 'n_r583', ch: 43, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n흙을 밀어 내어 땅을 다지거나 평평하게 하는 기계를 ____________(이)라고 합니다.", a: ["불도저", "레미콘", "화물차", "지게차"], c: "불도저", ex: "Alat berat yang memiliki bilah besar di depan untuk meratakan tanah dengan mendorong tanah atau puing-puing adalah buldoser (불도저)." },
{ id: 'n_r584', ch: 43, q: "가: 레미콘은 언제 사용해요?\n나: 콘크리트가 굳지 않게 섞으면서 ____________ 때 사용해요.", a: ["운반할", "파낼", "조립할", "설치할"], c: "운반할", ex: "Fungsi truk pengecor beton (레미콘) adalah untuk mencampur beton agar tidak mengeras sambil mengangkut atau memindahkannya (운반하다) ke lokasi proyek." },
{ id: 'n_r585', ch: 43, q: "가: 반장님, 제품을 몇 개씩 포장할까요?\n나: 제품을 열 개씩 모아서 상자에 ____________ 됩니다.", a: ["담으면", "자르면", "타설하면", "만들면"], c: "담으면", ex: "Produk yang sudah dikumpulkan sebanyak 10 buah harus 'dimasukkan' ke dalam kotak kardus. Kosakata yang tepat untuk memasukkan barang ke wadah adalah 담다, menjadi 담으면 됩니다 (cukup dimasukkan)." },
{ id: 'n_r586', ch: 43, q: "가: 바루 씨, 상품은 크기별로 다 ____________?\n나: 네, 대, 중, 소로 다 나누었어요.", a: ["분류해 놓았지요", "포장해 놓았지요", "조립해 놓았지요", "설치해 놓았지요"], c: "분류해 놓았지요", ex: "Proses membagi produk berdasarkan ukurannya (besar, sedang, kecil) disebut menyortir (분류하다). Dengan tata bahasa kepastian lampau, menjadi 분류해 놓았지요? (sudah disortir, kan?)." },
{ id: 'n_r587', ch: 43, q: "가: 작업이 끝나면 어떻게 할까요?\n나: 작업이 끝나는 대로 반장님에게 바로 ____________.", a: ["보고해 주세요", "조립해 주세요", "타설해 주세요", "판매해 주세요"], c: "보고해 주세요", ex: "Dalam lingkungan kerja, jika suatu tugas telah selesai, hal yang paling wajib dan lazim dilakukan adalah melapor (보고하다) kepada atasan atau mandor." },
{ id: 'n_r588', ch: 43, q: "가: 저기 무거운 철근을 위로 들어 올려야 하는데 어떻게 하지요?\n나: ____________을/를 부르는 게 좋겠어요.", a: ["크레인", "트랙터", "그레이더", "레미콘"], c: "크레인", ex: "Alat berat yang spesifik digunakan untuk mengangkat benda sangat berat (seperti balok besi) ke atas atau memindahkannya secara horizontal adalah mesin derek atau 크레인 (crane)." },
{ id: 'n_r589', ch: 43, q: "다음 대화의 주제로 알맞은 것을 고르십시오.\n\n가: 오늘은 거푸집을 설치하고 철근을 조립합시다.\n나: 네, 철근을 먼저 3층으로 옮겨 놓겠습니다.", a: ["오늘의 작업 지시", "안전모 착용 방법", "포장 상자 분류", "중장비 운전 방법"], c: "오늘의 작업 지시", ex: "Kedua orang tersebut sedang menyinkronkan apa saja tugas yang akan dikerjakan pada hari itu (memasang bekisting, merakit, memindah rebar). Topiknya adalah instruksi/pekerjaan hari ini (오늘의 작업 지시)." },// ======================== NORMAL ========================
{ id: 'n_r590', ch: 44, q: "가: 작업장이 왜 이렇게 엉망이에요?\n나: 어제 늦게까지 페인트 작업을 ____________.", a: ["했거든요", "할 거예요", "하면 돼요", "하고 싶어요"], c: "했거든요", ex: "Pembicara kedua memberikan alasan mengapa tempat kerjanya berantakan. Tata bahasa untuk memberikan alasan adalah '-거든요', sehingga menjadi 했거든요 (karena kemarin bekerja...)." },
{ id: 'n_r591', ch: 44, q: "가: 날씨가 점점 ____________.\n나: 네, 이제 여름이 다 된 것 같아요.", a: ["더워지고 있어요", "덥고 있어요", "더운 것 같아요", "더웠거든요"], c: "더워지고 있어요", ex: "Untuk menyatakan perubahan kondisi (semakin panas), kata sifat 덥다 digabungkan dengan '-어지다' menjadi 더워지다. Karena sedang berlangsung, menjadi 더워지고 있어요." },
{ id: 'n_r592', ch: 44, q: "가: 작업장이 참 쾌적하네요.\n나: 네, 아침에 창문을 열고 ____________.", a: ["환기했거든요", "환기할 거예요", "환기해지거든요", "환기하고 있어요"], c: "환기했거든요", ex: "Alasan mengapa tempat kerjanya nyaman (쾌적하다) adalah karena sudah diberi ventilasi pagi ini. Tata bahasa '-거든요' digabungkan dengan bentuk lampau menjadi 환기했거든요." },
{ id: 'n_r593', ch: 44, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n공구를 다 쓴 후에는 아무 데나 두지 말고 반드시 ____________에 넣어서 보관해야 합니다.", a: ["공구함", "휴지통", "마대", "손수레"], c: "공구함", ex: "Setelah menggunakan perkakas (공구), alat tersebut harus disimpan ke dalam kotak perkakas (공구함) untuk menjaga kerapian dan mencegah kecelakaan." },
{ id: 'n_r594', ch: 44, q: "가: 매일 청소를 하니까 작업 환경이 많이 ____________.\n나: 맞아요. 훨씬 깨끗해서 일하기 좋아요.", a: ["좋아졌어요", "나빠졌어요", "좋았거든요", "나쁘거든요"], c: "좋아졌어요", ex: "Membersihkan setiap hari menyebabkan perubahan kondisi lingkungan menjadi lebih baik. Kata 좋다 + -아/어지다 = 좋아지다. Bentuk lampaunya adalah 좋아졌어요." },
{ id: 'n_r595', ch: 44, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n바닥에 페인트나 기름이 있으면 미끄러워서 ____________ 수 있습니다. 빨리 닦아야 합니다.", a: ["넘어질", "다칠", "환기할", "정리할"], c: "넘어질", ex: "Jika ada tumpahan cat atau minyak di lantai, orang bisa terpeleset dan jatuh (넘어지다). Jadi jawaban yang tepat adalah 넘어질 수 있습니다." },
{ id: 'n_r596', ch: 44, q: "가: 밖이 왜 이렇게 시끄러워요?\n나: 지금 도로 공사를 ____________.", a: ["하고 있거든요", "할 거거든요", "하고 싶거든요", "해서 그렇거든요"], c: "하고 있거든요", ex: "Pembicara kedua menjelaskan alasan mengapa di luar berisik. Karena perbaikan jalannya sedang berlangsung saat ini, menggunakan bentuk sedang berlangsung ditambah alasan: 하고 있거든요." },
{ id: 'n_r597', ch: 44, q: "가: 분뇨 버리는 곳에 다른 쓰레기도 버려도 돼요?\n나: 안 돼요. 쓰레기는 종류별로 ____________ 버려야 해요.", a: ["분리해서", "처리해서", "오려서", "접어서"], c: "분리해서", ex: "Sesuai aturan pembuangan limbah, sampah yang berbeda tidak boleh dicampur and harus dipilah/dipisahkan (분리하다) sebelum dibuang ke tempatnya." },
{ id: 'n_r598', ch: 44, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n페인트 냄새가 너무 심할 때는 냄새를 맡지 않도록 ____________을/를 꼭 써야 합니다.", a: ["마스크", "안전모", "귀마개", "안전대"], c: "마스크", ex: "Saat bau cat sangat menyengat, alat pelindung diri yang paling tepat digunakan untuk menghindari gas atau bau berbahaya adalah masker (마스크)." },
{ id: 'n_r599', ch: 44, q: "가: 어제보다 일이 많이 ____________.\n나: 네, 요즘 주문이 줄어서 그래요.", a: ["적어졌어요", "많아졌어요", "적거든요", "많거든요"], c: "적어졌어요", ex: "Karena pesanan berkurang (주문이 줄어서), maka pekerjaannya pun berubah menjadi semakin sedikit (적다 + -어지다 = 적어지다 -> 적어졌어요)." },// ======================== NORMAL ========================
{ id: 'n_r600', ch: 45, q: "가: 밭에 물을 줘야 ____________.\n나: 그래요? 제가 창고에서 호스를 찾아 줄게요.", a: ["하는데요", "하기 전에", "해서요", "하지만"], c: "하는데요", ex: "Tata bahasa '-는데요' dilekatkan di akhir kalimat untuk memberikan latar belakang situasi (harus menyiram air) dan menunggu respons lawan bicara." },
{ id: 'n_r601', ch: 45, q: "가: 토마토를 딸까요?\n나: 아니요, 토마토를 ____________ 농약을 먼저 치세요.", a: ["따기 전에", "딴 후에", "따면서", "따지만"], c: "따기 전에", ex: "Tata bahasa '-기 전에' berarti 'sebelum'. Sebelum memetik tomat, mandor menyuruh untuk menyemprotkan pestisida dahulu." },
{ id: 'n_r602', ch: 45, q: "가: 괭이로 고구마를 캘까요?\n나: 괭이로 캐면 고구마에 상처가 나기 쉬우니까 ____________(으)로 캐는 게 좋아요.", a: ["호미", "삽", "낫", "쇠스랑"], c: "호미", ex: "Dalam materi EPS-TOPIK, untuk menggali ubi (고구마) agar tidak terluka atau lecet (상처가 나다), disarankan menggunakan beliung kecil atau 호미." },
{ id: 'n_r603', ch: 45, q: "가: 내일 고구마 밭에 거름을 줄까요?\n나: 며칠 전에 ____________ 안 줘도 돼요.", a: ["줬는데요", "주기 전에", "줄 건데요", "주려고요"], c: "줬는데요", ex: "Pembicara kedua menyatakan bahwa pupuk sudah diberikan beberapa hari lalu. Kata kerja lampau '줬다' ditambah akhiran informasi '-는데요' menjadi 줬는데요." },
{ id: 'n_r604', ch: 45, q: "빈칸에 들어갈 알맞은 말을 고르십시오.\n\n모종을 ____________ 밭에 비료를 먼저 뿌려야 합니다.", a: ["심기 전에", "심은 후에", "심으면서", "심으려고"], c: "심기 전에", ex: "Secara agrikultural, pupuk harus ditabur 'sebelum menanam' benih. 'Menanam benih' = 심다, jadi bentuk yang tepat adalah 심기 전에." },
{ id: 'n_r605', ch: 45, q: "가: 밖에 비가 많이 ____________. 창문을 닫을까요?\n나: 네, 닫아 주세요.", a: ["오는데요", "오기 전에", "온 후에", "오려고"], c: "오는데요", ex: "Pembicara pertama menyampaikan latar belakang informasi bahwa 'di luar sedang hujan deras' menggunakan '-는데요' sebelum menawarkan saran menutup jendela." },
{ id: 'n_r606', ch: 45, q: "가: 이 파종 상자를 어디에 둘까요?\n나: 밭으로 가져갈 거니까 ____________에 실어 놓으세요.", a: ["경운기", "낫", "물뿌리개", "호미"], c: "경운기", ex: "Kotak benih (파종 상자) harus diangkut ke ladang. Dari pilihan yang ada, alat angkut atau kendaraan pertanian yang tepat adalah traktor tangan atau 경운기." },
{ id: 'n_r607', ch: 45, q: "가: 반장님, 사과 상자들을 트럭에 다 ____________. 좀 봐 주세요.\n나: 그래요? 잠깐만 기다리세요.", a: ["실었는데요", "싣기 전에", "실으려고요", "실을 건데요"], c: "실었는데요", ex: "Pekerja sudah selesai memuat (실었다) keranjang apel dan memanggil mandor untuk mengeceknya, sehingga menggunakan bentuk lampau + 는데요 (실었는데요)." },
{ id: 'n_r608', ch: 45, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n가: 한국에 ____________ 인도네시아에서 무슨 일을 했어요?\n나: 무역 회사에 다녔어요.", a: ["오기 전에", "온 후에", "오면서", "오려고"], c: "오기 전에", ex: "Pertanyaan ini menanyakan pekerjaan seseorang di Indonesia 'sebelum datang' ke Korea. Tata bahasa yang tepat adalah 오다 + -기 전에 = 오기 전에." },
{ id: 'n_r609', ch: 45, q: "가: 모종은 다음 주에 심을 건데 벌써 비료를 뿌려요?\n나: 네, 비료를 먼저 뿌리고 일주일쯤 지난 후에 심어야 모종이 잘 ____________.", a: ["자라거든요", "자라기 전에", "자라는데요", "자랐거든요"], c: "자라거든요", ex: "Pembicara menjelaskan alasan mengapa pupuk ditabur lebih awal (karena akan tumbuh dengan baik) menggunakan tata bahasa penanda alasan absolut '-거든요'." },// ======================== NORMAL ========================
{ id: 'n_r610', ch: 46, q: "가: 소들이 배가 고픈 것 같아요.\n나: 그럼 축사에 가서 소 먹이를 ____________.", a: ["주도록 하세요", "주게 되었어요", "주지 마세요", "주기 전에"], c: "주도록 하세요", ex: "Tata bahasa '-도록 하다' digunakan untuk memberi instruksi atau menyuruh dengan halus. '주도록 하세요' berarti 'tolong berikan'." },
{ id: 'n_r611', ch: 46, q: "가: 한국 음식을 잘 먹네요.\n나: 처음에는 매워서 못 먹었는데 이제는 잘 ____________.", a: ["먹게 되었어요", "먹도록 하세요", "먹은 적이 있어요", "먹을 거예요"], c: "먹게 되었어요", ex: "Tata bahasa '-게 되다' menunjukkan perubahan keadaan. Awalnya tidak bisa makan, tapi karena terbiasa ia 'menjadi bisa makan' (잘 먹게 되었어요)." },
{ id: 'n_r612', ch: 46, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n바다에 그물을 던져서 물고기를 잡는 기계를 ____________(이)라고 합니다.", a: ["양망기", "집어등", "통발", "도르래"], c: "양망기", ex: "Mesin yang dioperasikan di kapal untuk menarik atau menggulung jaring ikan dari laut disebut 양망기 (mesin penarik jaring)." },
{ id: 'n_r613', ch: 46, q: "가: 내일 몇 시에 출발할까요?\n나: 6시에 배가 출발하니까 늦지 ____________.", a: ["않도록 하세요", "않게 되었어요", "않을 것 같아요", "않으려고요"], c: "않도록 하세요", ex: "Pembicara menginstruksikan agar tidak terlambat. Bentuk negatif '-지 않다' digabung dengan '-도록 하다' menjadi '않도록 하세요' (pastikan/usahakan agar tidak...)." },
{ id: 'n_r614', ch: 46, q: "가: 사료를 왜 바꿨어요?\n나: 농협에서 좋은 사료가 새로 나와서 ____________.", a: ["바꾸게 되었어요", "바꾸도록 하세요", "바꾸기 전에", "바꾸면서"], c: "바꾸게 되었어요", ex: "Terjadinya suatu hal (mengganti pakan) karena faktor eksternal (ada rekomendasi/produk baru) diekspresikan dengan '-게 되다', menjadi '바꾸게 되었어요' (jadi saya menggantinya)." },
{ id: 'n_r615', ch: 46, q: "빈칸에 들어gal al맞은 말을 고르십시오.\n\n갯벌에서 조개를 캘 때 흙을 파기 위해 ____________을/를 사용합니다.", a: ["갈퀴", "부표", "집어등", "닻"], c: "갈퀴", ex: "Alat yang memiliki ujung menyerupai garpu untuk menggali atau menggaruk tanah/lumpur saat mencari kerang (조개) di dataran lumpur adalah penggaruk atau 갈퀴." },
{ id: 'n_r616', ch: 46, q: "가: 투안 씨, 감기는 좀 어때요?\n나: 많이 나았어요. ____________ 줘서 고마워요.", a: ["신경 써", "신고해", "화해해", "조립해"], c: "신경 써", ex: "Ungkapan '신경(을) 쓰다' berarti menaruh perhatian atau memedulikan. '신경 써 줘서 고마워요' adalah frasa umum yang berarti 'terima kasih sudah memperhatikan/mempedulikan saya'." },
{ id: 'n_r617', ch: 46, q: "가: 작업장이 좀 지저분하네요.\n나: 죄송합니다. 이 일만 끝내고 바로 ____________.", a: ["청소하도록 할게요", "청소하게 되었어요", "청소하기 전에", "청소하지 마세요"], c: "청소하도록 할게요", ex: "Saat berjanji atau menyanggupi untuk melakukan sesuatu yang diinstruksikan, pembicara menggunakan bentuk '-도록 할게yo' (saya akan memastikan untuk membersihkannya)." },
{ id: 'n_r618', ch: 46, q: "가: 소의 배가 너무 불룩한데 어떻게 할까요?\n나: 우선 아무것도 먹이지 말고 빨리 ____________을/를 부르도록 하세요.", a: ["수의사", "어부", "농부", "경찰"], c: "수의사", ex: "Jika sapi tiba-tiba perutnya bengkak (불룩해지다) atau kembung gas, itu pertanda sakit. Orang yang harus segera dipanggil adalah dokter hewan (수의사)." },
{ id: 'n_r619', ch: 46, q: "다음 대화의 주제로 al맞은 것을 고르십시오.\n\n가: 그물이 모두 엉켜 있으니까 어서 풀도록 하세요.\n나: 네, 알겠습니다. 지금 바로 풀게요.", a: ["작업 지시", "사료 교체", "날씨 확인", "건강 상태"], c: "작업 지시", ex: "Percakapan ini berisi instruksi atasan/mandor untuk mengurai jaring yang kusut (엉킨 그물을 풀다) dan pekerjanya menyanggupi. Topik utamanya adalah instruksi kerja (작업 지시)." },// ======================== NORMAL ========================
{ id: 'n_r620', ch: 47, q: "가: 창고 관리는 어떻게 해야 해요?\n나: 창고 관리는 재고를 잘 ____________ 중요해요.", a: ["파악하는 것이", "파악해서", "파악할 텐데", "파악할 거예요"], c: "파악하는 것이", ex: "Tata bahasa '-는 것이 중요하다' (penting untuk melakukan) digunakan untuk menekankan hal yang esensial. 'Penting untuk mengecek stok' diterjemahkan menjadi 재고를 파악하는 것이 중요해요." },
{ id: 'n_r621', ch: 47, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n냉동 창고에 식품을 보관할 때는 적절한 온도를 ____________ 중요합니다.", a: ["유지하는 것이", "유지할 텐데", "유지해서", "유지할 거예요"], c: "유지하는 것이", ex: "Menjaga suhu (온도를 유지하다) digabungkan dengan '-는 것이 중요하다' menjadi 유지하는 것이 중요합니다." },
{ id: 'n_r622', ch: 47, q: "가: 밖에 비가 오는데 어떻게 할까요?\n나: 물건이 젖지 않게 미리 덮개를 ____________ 중요해요.", a: ["덮는 것이", "덮을 텐데", "덮고", "덮지만"], c: "덮는 것이", ex: "Penting untuk memasang penutup (덮개를 덮다) agar barang tidak basah. Tata bahasa yang digunakan adalah 덮는 것이 중요하다." },
{ id: 'n_r623', ch: 47, q: "가: 오늘 도장 작업을 다 끝낼 수 있을까요?\n나: 네, 3시까지는 다 ____________.", a: ["끝날 거예요", "끝나는 것이 중요해요", "끝났어요", "끝날 텐데"], c: "끝날 거예요", ex: "Untuk mengekspresikan perkiraan atau kepastian di masa depan (akan selesai), digunakan '-(으)ㄹ 거예요'. Jadi 끝날 거예요 (akan selesai)." },
{ id: 'n_r624', ch: 47, q: "가: 오전에 원목 재단 작업이 다 될까요?\n나: 네, 문제없이 다 ____________.", a: ["될 거예요", "되는 것이 중요해요", "됐어요", "될 텐데"], c: "될 거예요", ex: "Pertanyaan menanyakan prediksi ('다 될까요?'). Jawaban yang menyatakan perkiraan kepastian adalah '-(으)ㄹ 거예요' -> 될 거예요 (pasti akan selesai/bisa)." },
{ id: 'n_r625', ch: 47, q: "가: 직각자 못 봤어요?\n나: 아마 저쪽 공구함에 ____________.", a: ["있을 거예요", "있는 것이 중요해요", "있었어요", "있거든요"], c: "있을 거예요", ex: "Pembicara menebak/memperkirakan letak penggaris siku (아마 = mungkin/barangkali). Prediksi keadaan menggunakan '-(으)ㄹ 거예요', menjadi 있을 거예요 (sepertinya ada di sana)." },
{ id: 'n_r626', ch: 47, q: "가: 이 원목은 구멍을 반대쪽에 뚫어서 못 쓰게 ____________.\n나: 너무 속상해하지 마세요.", a: ["됐어요", "될 거예요", "되는 것이 중요해요", "될 텐데"], c: "됐어요", ex: "Karena kesalahan sudah terjadi, kayu tersebut 'sudah menjadi' tidak bisa dipakai. Bentuk lampau dari 못 쓰게 되다 adalah 못 쓰게 됐어요." },
{ id: 'n_r627', ch: 47, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n가: 노트북이 어때요?\n나: 가벼워서 좋아요. 기능도 ____________.", a: ["많고요", "많을 거예요", "많을 텐데", "많은 것이 중요해요"], c: "많고요", ex: "Untuk menambahkan informasi lain pada kalimat sebelumnya tanpa mengulang akhir kalimat panjang, digunakan tata bahasa '-고요'. 'Fungsinya juga banyak' menjadi 기능도 많고요." },
{ id: 'n_r628', ch: 47, q: "가: 지금 밥을 먹지 않으면 이따가 배가 ____________.\n나: 괜찮아요. 일이 끝나고 먹을게요.", a: ["고플 텐데", "고픈 것이 중요해요", "고팠어요", "고파서요"], c: "고플 텐데", ex: "Pembicara pertama memberikan prediksi (nanti akan lapar) yang menjadi latar belakang kekhawatirannya. Tata bahasa prediksi + latar belakang adalah '-(으)ㄹ 텐데', menjadi 고플 텐데 (nanti kamu bakal lapar...)." },
{ id: 'n_r629', ch: 47, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n안전하게 작업하려면 규칙을 잘 ____________ 중요합니다.", a: ["지키는 것이", "지킬 텐데", "지키고요", "지킬 거예요"], c: "지키는 것이", ex: "Menaati aturan (규칙을 지키다) adalah suatu keharusan yang penting. 'Penting untuk menaati aturan' menggunakan '-는 것이 중요하다' menjadi 지키는 것이 중요합니다." },// ======================== NORMAL ========================
{ id: 'n_r630', ch: 48, q: "가: 투안 씨는 이 작업복 처음 입어 보지요?\n나: 아니요, 전에 ____________.", a: ["입은 적이 있어요", "입은 적이 없어요", "입지 않도록 하세요", "입을 거예요"], c: "입은 적이 있어요", ex: "Untuk menyatakan bahwa seseorang sudah 'pernah' memakai baju kerja tersebut sebelumnya, digunakan tata bahasa '-(으)ㄴ 적이 있다' (입다 -> 입은 적이 있어요)." },
{ id: 'n_r631', ch: 48, q: "가: 리한 씨, 이 선반 기계를 사용할 수 있어요?\n나: 네, 전에 ____________.", a: ["사용한 적이 있어요", "사용한 적이 없어요", "사용하지 마세요", "사용할 거예요"], c: "사용한 적이 있어요", ex: "Karena menjawab '네' (Ya), berarti ia sudah pernah menggunakan mesin bubut tersebut. Tata bahasanya adalah 사용한 적이 있어요." },
{ id: 'n_r632', ch: 48, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n작업을 하다가 가스에 ____________ 것을 막기 위해서는 환기를 자주 해야 합니다.", a: ["중독되는", "잘리는", "박히는", "베이는"], c: "중독되는", ex: "Kecelakaan kerja yang berhubungan dengan gas (가스) adalah keracunan (중독되다). Untuk mencegah keracunan gas, ventilasi harus sering dibuka." },
{ id: 'n_r633', ch: 48, q: "가: 자, 그럼 작업을 시작해 볼까요?\n나: 뜨거우니까 화상을 ____________ 조심하세요.", a: ["입지 않도록", "입게 되도록", "입을 텐데", "입었기 때문에"], c: "입지 않도록", ex: "Tata bahasa '-지 않도록 조심하다' berarti 'berhati-hati agar tidak...'. 'Berhati-hati agar tidak mengalami luka bakar' menjadi 화상을 입지 않도록 조심하세요." },
{ id: 'n_r634', ch: 48, q: "가: 어, 여기 유리 조각 있네.\n나: ____________ 조심해. 얼른 치워야겠다.", a: ["밟지 않도록", "밟게 되도록", "밟은 적이 있어서", "밟을 텐데"], c: "밟지 않도록", ex: "Karena ada pecahan kaca (유리 조각), ia memperingatkan untuk berhati-hati 'agar tidak menginjaknya' (밟지 않도록 조심해)." },
{ id: 'n_r635', ch: 48, q: "가: 앗, 뜨거워! 어, 팔에 불꽃이 튀었어요.\n나: 움직이지 말고 가만히 있어요. 우선 ____________(으)로 진정시키고 병원부터 가야겠어요.", a: ["얼음", "소화기", "뜨거운 물", "가스"], c: "얼음", ex: "Ketika terkena percikan api (불꽃이 튀다), pertolongan pertama untuk mendinginkan area yang panas adalah menggunakan es (얼음)." },
{ id: 'n_r636', ch: 48, q: "빈칸에 들어gal al맞은 말을 고르십시오.\n\n프레스 기계로 철판을 구부리거나 같은 모양을 여러 개 ____________ 수 있습니다.", a: ["찍어 낼", "갈아 낼", "파낼", "도려낼"], c: "찍어 낼", ex: "Fungsi utama mesin press adalah untuk mencetak/memacak logam dengan bentuk yang sama secara massal. Kata yang tepat adalah 찍어 내다 (mencetak/memacak)." },
{ id: 'n_r637', ch: 48, q: "가: 밀링 작업을 해 본 ____________?\n나: 아니요. 오늘 처음 해 봐요.", a: ["적이 있어요", "적이 없어요", "수 있어요", "거예요"], c: "적이 있어요", ex: "Pertanyaan ini menanyakan pengalaman: 'Apakah Anda pernah melakukan pekerjaan milling?' menggunakan tata bahasa '-(으)ㄴ 적이 있다', menjadi 해 본 적이 있어요?" },
{ id: 'n_r638', ch: 48, q: "빈칸에 들어gal al맞은 말을 고르십시오.\n\n젖은 손으로 전기 기계나 전선을 만지면 안 됩니다. ____________ 사고가 생길 수 있습니다.", a: ["감전", "추락", "붕괴", "낙하"], c: "감전", ex: "Menyentuh mesin listrik atau kabel dengan tangan basah (젖은 손) dapat menyebabkan kecelakaan tersengat listrik atau kesetrum (감전 사고)." },
{ id: 'n_r639', ch: 48, q: "가: 바루 씨, 제주도에 간 적이 있어요?\n나: 아니요, 한 번도 ____________.", a: ["가 본 적이 없어요", "가 본 적이 있어요", "가 보지 마세요", "가 보고 싶어요"], c: "가 본 적이 없어요", ex: "Karena menjawab '아니요' (Tidak) dan '한 번도' (belum pernah sekalipun), maka kelanjutannya adalah bentuk negatif dari pengalaman: 가 본 적이 없어요." },// ======================== NORMAL ========================
{ id: 'n_r640', ch: 49, q: "가: 귀마개를 꼭 해야 돼요?\n나: 네, 귀마개를 안 하면 귀를 ____________.", a: ["다칠 수 있어요", "다치기 때문에", "다치지 마세요", "다칠 거예요"], c: "다칠 수 있어요", ex: "Tata bahasa '-(으)ㄹ 수 있다' menunjukkan kemungkinan bahaya. Jika tidak pakai penutup telinga, telinga 'bisa' terluka (다칠 수 있어요)." },
{ id: 'n_r641', ch: 49, q: "가: 높은 곳에서 작업할 때는 조심해야 합니다.\n나: 자칫하면 아래로 ____________.", a: ["떨어질 수 있거든요", "떨어지기 때문에", "떨어진 적이 있어요", "떨어지도록 하세요"], c: "떨어질 수 있거든요", ex: "Pembicara menyetujui peringatan tersebut karena di tempat tinggi orang 'bisa jatuh'. 떨어지다 + -(으)ㄹ 수 있다 + -거든요 = 떨어질 수 있거든요." },
{ id: 'n_r642', ch: 49, q: "가: 밀링 작업을 할 때는 왜 맨손으로 해야 해요?\n나: 장갑이 기계에 ____________.", a: ["감길 수 있기 때문이에요", "감길 수 있어서요", "감기기 전에요", "감기는 동안에요"], c: "감길 수 있기 때문이에요", ex: "Untuk memberikan alasan menggunakan pola kalimat formal, digunakan '-기 때문에' (karena). 'Karena bisa terlilit/tersangkut' menjadi 감길 수 있기 때문이에요." },
{ id: 'n_r643', ch: 49, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n바닥에 물이나 기름이 있으면 ____________ 넘어질 수 있습니다.", a: ["미끄러워서", "미끄러우면", "미끄럽지만", "미끄럽고"], c: "미끄러워서", ex: "Alasan mengapa seseorang bisa terjatuh di lantai yang berair/berminyak adalah karena licin. Kata hubung sebab-akibat '-(아/어)서' digabung dengan 미끄럽다 menjadi 미끄러워서." },
{ id: 'n_r644', ch: 49, q: "가: 보안경을 안 쓰면 어떻게 돼요?\n나: 파편이 튀어서 눈을 ____________.", a: ["다칠 수 있어요", "다치기 때문에", "다쳐야 해요", "다치려고 해요"], c: "다칠 수 있어요", ex: "Bongkahan/serpihan (파편) yang terpental dapat menyebabkan mata terluka. Kemungkinan buruk ini diekspresikan dengan 다칠 수 있어요." },
{ id: 'n_r645', ch: 49, q: "가: 오늘 왜 이렇게 도로에 차가 막혀요?\n나: 아까 비가 많이 ____________ 길이 미끄러워서 차가 막히는 것 같아요.", a: ["왔기 때문에", "올 수 있어서", "오기 전에", "온 후에"], c: "왔기 때문에", ex: "Penyebab kemacetan adalah karena tadi hujan deras. Bentuk lampau (왔다) + alasan (-기 때문에) = 왔기 때문에." },
{ id: 'n_r646', ch: 49, q: "겨울에는 날씨가 ____________ 따뜻한 작업복을 입어야 합니다.", a: ["춥기 때문에", "추울 수 있어서", "춥지만", "춥거나"], c: "춥기 때문에", ex: "Alasan harus memakai baju hangat adalah 'karena cuaca dingin'. 춥다 + -기 때문에 = 춥기 때문에." },
{ id: 'n_r647', ch: 49, q: "가: 용접면을 꼭 써야 돼요?\n나: 그럼요. 불꽃이 튀면 얼굴에 화상을 ____________.", a: ["입을 수 있어요", "입기 때문에", "입은 적이 있어요", "입지 마세요"], c: "입을 수 있어요", ex: "Peringatan akan bahaya terkena luka bakar (화상을 입다) akibat percikan api menggunakan pola kemungkinan '-(으)ㄹ 수 있다' -> 입을 수 있어요." },
{ id: 'n_r648', ch: 49, q: "가: 작업장에 왜 지금 못 들어가요?\n나: 안에 유해 가스가 ____________ 환기를 먼저 해야 돼요.", a: ["새기 때문에", "샐 수 있어서", "새기 전에", "샌 후에"], c: "새기 때문에", ex: "Alasan tidak boleh masuk adalah 'karena gas bocor' (가스가 새다). Digabungkan dengan tata bahasa alasan menjadi 새기 때문에." },
{ id: 'n_r649', ch: 49, q: "빈칸에 들어gal al맞은 말을 고르십시오.\n\n높은 곳에서 일할 때는 생명과 직결되므로 반드시 ____________을/를 매야 합니다.", a: ["안전대", "목장갑", "귀마개", "보안경"], c: "안전대", ex: "Alat keselamatan yang harus diikat/dipasang (매다) saat bekerja di ketinggian (높은 곳) untuk mencegah jatuh adalah sabuk keselamatan (안전대)." },// ======================== NORMAL ========================
{ id: 'n_r650', ch: 50, q: "가: 일이 빨리 끝났네요.\n나: 투안 씨가 많이 도와주신 ____________ 빨리 끝낼 수 있었어요.", a: ["덕분에", "때문에", "후에", "동안에"], c: "덕분에", ex: "Tata bahasa '-(으)ㄴ 덕분에' digunakan untuk menyatakan 'berkat' sesuatu yang menghasilkan akibat positif. 'Berkat bantuan Tuan...' menjadi 도와주신 덕분에." },
{ id: 'n_r651', ch: 50, q: "가: 이번 주말에 뭐 할 거예요?\n나: 친구들하고 같이 등산을 ____________.", a: ["가기로 했어요", "간 덕분에", "가기 전에", "가는 동안"], c: "가기로 했어요", ex: "Tata bahasa '-기로 하다' digunakan untuk menyatakan keputusan atau janji. 'Saya sudah memutuskan/berjanji untuk pergi mendaki' menjadi 가기로 했어요." },
{ id: 'n_r652', ch: 50, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n기계를 오래 사용하려면 문제가 없는지 정기적으로 ____________ 합니다.", a: ["점검해야", "어겨야", "취해야", "섭취해야"], c: "점검해야", ex: "Agar mesin dapat digunakan lama, mesin tersebut harus dicek atau diperiksa secara rutin. Kosakata yang tepat adalah 점검하다 (점검해야 합니다)." },
{ id: 'n_r653', ch: 50, q: "빈칸에 들어gal al맞은 말을 고르십시오.\n\n이런 도구는 위험하니까 사용할 때 다치지 않도록 ____________ 합니다.", a: ["주의해야", "준수해야", "개선해야", "해쳐야"], c: "주의해야", ex: "Saat menggunakan alat yang berbahaya, kita harus memperhatikan atau berhati-hati (주의하다) agar tidak terluka." },
{ id: 'n_r654', ch: 50, q: "가: 용접기가 또 고장 났어요?\n나: 아니요, 공장장님이 어제 ____________ 내일은 쓸 수 있을 거예요.", a: ["보수한 덕분에", "보수하기로 해서", "어긴 덕분에", "어기기로 해서"], c: "보수한 덕분에", ex: "Karena kemarin sudah diperbaiki (보수하다) dan memberikan hasil positif (besok bisa dipakai), tata bahasa yang tepat adalah '-(으)ㄴ 덕분에', menjadi 보수한 덕분에." },
{ id: 'n_r655', ch: 50, q: "가: 불량품이 계속 나오고 있어요.\n나: 문제를 ____________ 수 있는 방법을 찾아야 합니다.", a: ["개선할", "어길", "주의할", "준수할"], c: "개선할", ex: "Jika produk gagal (불량품) terus muncul, kita harus mencari cara untuk 'memperbaiki kualitas/menyelesaikan' masalah tersebut. Kosakatanya adalah 개선하다 (개선할 수 있는)." },
{ id: 'n_r656', ch: 50, q: "가: 작업장이 참 깨끗하네요.\n나: 네, 작업장 환경이 별로 깨끗하지 않아서 늘 ____________ 위해 애쓰는 편입니다.", a: ["청결을 유지하기", "휴식을 취하기", "스트레칭을 하기", "골고루 섭취하기"], c: "청결을 유지하기", ex: "Untuk membuat tempat kerja menjadi bersih (깨끗하다), kita harus berusaha untuk 'menjaga kebersihan' atau 청결을 유지하다." },
{ id: 'n_r657', ch: 50, q: "가: 모니카 씨가 우수 사원으로 뽑힌 이유는 뭐예요?\n나: 일도 잘하고 작업장 점검도 아주 ____________ 하기 때문이에요.", a: ["꼼꼼히", "틈틈이", "조심히", "급히"], c: "꼼꼼히", ex: "Sesuai dialog di Bab 50, Monika terpilih sebagai karyawan teladan karena ia bekerja dengan baik dan melakukan pengecekan dengan sangat teliti (꼼꼼히)." },
{ id: 'n_r658', ch: 50, q: "가: 일이 바빠도 ____________ 쉬면서 하세요. 그러다가 건강 해쳐요.\n나: 네, 알겠습니다.", a: ["틈틈이", "꼼꼼히", "벌써", "아직"], c: "틈틈이", ex: "Kosakata 틈틈이 berarti 'di setiap ada waktu luang/sela-sela kesibukan'. Jadi 틈틈이 쉬면서 하세요 berarti beristirahatlah setiap ada waktu kosong." },
{ id: 'n_r659', ch: 50, q: "가: 요즘 몸이 안 좋다면서요?\n나: 네, 그래서 내일 병원에 가서 ____________.", a: ["건강 검진을 받기로 했어요", "건강을 해치기로 했어요", "기분 전환을 하기로 했어요", "유산소 운동을 하기로 했어요"], c: "건강 검진을 받기로 했어요", ex: "Karena merasa tidak enak badan, keputusan yang diambil adalah pergi ke rumah sakit untuk melakukan tes kesehatan (건강 검진을 받기로 했어요)." },// ======================== NORMAL ========================
{ id: 'n_r660', ch: 51, q: "가: 고용허가제로 한국에 가면 어떤 일을 하고 싶어요?\n나: 공장에서 물건을 만드는 ____________ 쪽 일을 하고 싶어요.", a: ["농업", "건설업", "제조업", "서비스업"], c: "제조업", ex: "Pekerjaan membuat barang di pabrik termasuk ke dalam industri manufaktur atau 제조업." },
{ id: 'n_r661', ch: 51, q: "가: 한국어능력시험 ____________?\n나: 네, 어제 인터넷으로 다 했어요.", a: ["합격했어요", "신청했어요", "문의했어요", "봤어요"], c: "신청했어요", ex: "Konteksnya adalah melakukan proses untuk ujian melalui internet, yaitu mendaftar (신청했어요 / 접수했어요)." },
{ id: 'n_r662', ch: 51, q: "가: 무슨 일로 오셨어요?\n나: 고용허가제에 대해서 ____________ 싶은데요.", a: ["문의하고", "합격하고", "수험하고", "재계약하고"], c: "문의하고", ex: "Ungkapan 'ingin bertanya tentang EPS' menggunakan kata 문의하다 -> 문의하고 싶은데요." },
{ id: 'n_r663', ch: 51, q: "가: 한국어능력시험을 잘 봤어요?\n나: 어렵지 않았어요. ____________ 좋겠어요.", a: ["접수하면", "문의하면", "합격하면", "신청하면"], c: "합격하면", ex: "Karena ujiannya dirasa tidak sulit, pembicara berharap dirinya bisa 'lulus' atau 합격하면 좋겠어요." },
{ id: 'n_r664', ch: 51, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n성명, 생년월일, 성별, 응시 분야 등을 적는 종이를 ____________(이)라고 합니다.", a: ["신청서", "성적표", "접수증", "수험표"], c: "신청서", ex: "Kertas/formulir yang diisi dengan nama, tanggal lahir, dan bidang pekerjaan saat mendaftar disebut formulir pendaftaran atau 신청서." },
{ id: 'n_r665', ch: 51, q: "가: 한국어능력시험은 어떻게 신청해요?\n나: 한국어능력시험은 ____________을/를 통해 접수할 수 있습니다.", a: ["인터넷", "우체국", "은행", "공장"], c: "인터넷", ex: "Pendaftaran ujian TOPIK (EPS-TOPIK) dapat dilakukan secara online melalui internet (인터넷을 통해 접수할 수 있습니다)." },
{ id: 'n_r666', ch: 51, q: "가: 고용허가제로 한국에 가면 처음에는 몇 년 정도 일할 수 있어요?\n나: 기본 취업 기간은 ____________입니다.", a: ["1년 10개월", "2년", "3년", "5년"], c: "3년", ex: "Masa kerja awal menurut sistem izin kerja (EPS) adalah 3 tahun (3년)." },
{ id: 'n_r667', ch: 51, q: "가: 한국에 가려면 시험에서 몇 점을 받아야 해요?\n나: 200점 만점 기준으로 ____________이 넘어야 해요.", a: ["50점", "60점", "80점", "100점"], c: "80점", ex: "Standar minimal kelulusan EPS-TOPIK adalah 80 poin (80점) dari total 200 poin." },
{ id: 'n_r668', ch: 51, q: "가: 시험에는 어떤 문제가 나와요?\n나: 시험에는 ____________하고 읽기만 25문제씩 나와요.", a: ["쓰기", "듣기", "말하기", "문법"], c: "듣기", ex: "Ujian EPS-TOPIK hanya menguji kemampuan Menyimak (듣기) dan Membaca (읽기)." },
{ id: 'n_r669', ch: 51, q: "가: 시험공부를 어떻게 해야 할지 모르겠어요.\n나: ____________을/를 많이 풀어 보세요.", a: ["신청서", "수험표", "기출문제", "성적표"], c: "기출문제", ex: "Guru menyarankan Ivan untuk banyak mengerjakan soal-soal ujian sebelumnya/soal tahun lalu yang disebut 기출문제." },// ======================== NORMAL ========================
{ id: 'n_r670', ch: 52, q: "가: 월급을 언제 받는지 모르겠어요.\n나: 계약서에서 ____________을/를 확인해 보세요.", a: ["지급일", "수습 기간", "업무 내용", "근무지"], c: "지급일", ex: "Untuk mengetahui 'kapan' (언제) gaji diterima, kita harus mengecek tanggal pembayaran atau 지급일." },
{ id: 'n_r671', ch: 52, q: "가: 계약서에 있는 것보다 월급이 적게 들어온 것 같아요.\n나: 지금은 일을 배우는 ____________(이)라서 그럴 거예요.", a: ["수습 기간", "근무 시간", "휴게 시간", "계약 기간"], c: "수습 기간", ex: "Gaji yang diterima lebih sedikit karena masih dalam masa pelatihan/magang atau 수습 기간 (biasanya menerima 90% dari gaji pokok)." },
{ id: 'n_r672', ch: 52, q: "가: 식사는 회사에서 ____________ 주는 거예요?\n나: 계약서에 누가 부담하는 거라고 쓰여 있어요?", a: ["제공해", "서명해", "해고해", "퇴직해"], c: "제공해", ex: "Apakah perusahaan 'menyediakan' (제공하다) makan? Oleh karena itu jawabannya 제공해 주는 거예요?." },
{ id: 'n_r673', ch: 52, q: "가: 계약서를 잘 확인해 봤어요?\n나: 네, 업무 내용이랑 임금 모두 마음에 들어요. ____________이/가 좋은 것 같아요.", a: ["근로 조건", "면접 시간", "회사 이름", "근로자"], c: "근로 조건", ex: "Deskripsi pekerjaan dan gaji adalah bagian dari syarat kerja. Jadi ia merasa syarat kerjanya (근로 조건) bagus." },
{ id: 'n_r674', ch: 52, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n가: 어디에서 일하게 됐어요?\n나: 잠시만요. 계약서에서 ____________을/를 확인해 볼게요.", a: ["근무지", "근무 시간", "업무 내용", "지급 방법"], c: "근무지", ex: "Karena ditanya 'di mana' (어디에서), hal yang harus dicek di kontrak adalah tempat kerja (근무지)." },
{ id: 'n_r675', ch: 52, q: "가: 취업자 칸에는 누구의 이름을 써야 해요?\n나: 이반 씨가 ____________ 사람이니까 이반 씨 이름을 쓰세요.", a: ["취직을 하는", "고용을 하는", "해고를 하는", "면접을 보는"], c: "취직을 하는", ex: "Kolom 취업자 (pekerja) diisi oleh nama orang yang 'mendapat pekerjaan/dipekerjakan' (취직을 하는 사람)." },
{ id: 'n_r676', ch: 52, q: "가: 한국 음식을 잘 먹네요.\n나: 처음에는 매워서 못 먹었는데 이제는 잘 ____________.", a: ["먹게 되었어요", "먹도록 하세요", "먹기 전에", "먹은 적이 있어요"], c: "먹게 되었어요", ex: "Tata bahasa '-게 되다' menunjukkan perubahan keadaan. Dari tidak bisa makan menjadi bisa makan (잘 먹게 되었어요)." },
{ id: 'n_r677', ch: 52, q: "가: 소들이 배가 고픈 것 같아요.\n나: 그럼 축사에 가서 소 먹이를 ____________.", a: ["주도록 하세요", "주게 되었어요", "줄 텐데", "주기 때문에"], c: "주도록 하세요", ex: "Tata bahasa '-도록 하다' digunakan untuk memberikan instruksi halus. 'Tolong berikan' menjadi 주도록 하세요." },
{ id: 'n_r678', ch: 52, q: "가: 같이 일하게 돼서 기쁩니다. 이 계약서에 ____________.\n나: 네, 알겠습니다.", a: ["사인하세요", "면접을 보세요", "고용하세요", "해고하세요"], c: "사인하세요", ex: "Setelah sepakat untuk bekerja sama, langkah selanjutnya adalah menandatangani surat kontrak (계약서에 사인하세요)." },
{ id: 'n_r679', ch: 52, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n고용허가제로 한국에 들어올 때는 ____________을/를 체결합니다. 여기에는 근무 시간, 임금 등에 관한 사항이 담겨 있습니다.", a: ["근로계약", "건강검진", "한국어능력시험", "여권"], c: "근로계약", ex: "Dokumen yang memuat jam kerja, gaji, dan ditandatangani saat masuk ke Korea adalah kontrak kerja (근로계약)." },// ======================== NORMAL ========================
{ id: 'n_r680', ch: 53, q: "가: 한국에 가면 바로 회사에서 일해요?\n나: 아니요. 2박 3일 동안 ____________을/를 받아요.", a: ["입국 심사", "취업 교육", "외국인 등록", "재계약"], c: "취업 교육", ex: "Sesuai percakapan dan prosedur EPS, sebelum mulai bekerja, pekerja asing wajib menerima pelatihan kerja (취업 교육) selama 3 hari 2 malam." },
{ id: 'n_r681', ch: 53, q: "가: ____________ 할 때 보통 뭘 물어봐요?\n나: 한국에 온 목적이랑 체류 기간 같은 것을 물어봐요.", a: ["입국 심사", "작업장 배치", "비자 연장", "건강 검진"], c: "입국 심사", ex: "Pemeriksaan tentang tujuan kedatangan (목적) dan masa tinggal (체류 기간) saat baru tiba di bandara dilakukan pada saat pemeriksaan imigrasi atau 입국 심사." },
{ id: 'n_r682', ch: 53, q: "가: 입국 심사에서 실수를 할까 봐 걱정이에요.\n나: 혹시 한국어를 이해할 수 없으면 ____________을/를 신청할 수 있어요.", a: ["통역", "교육", "비자", "신분증"], c: "통역", ex: "Jika pekerja tidak mengerti bahasa Korea saat melewati pemeriksaan imigrasi, mereka memiliki hak untuk meminta bantuan penerjemah atau 통역." },
{ id: 'n_r683', ch: 53, q: "가: 여권 유효 기간이 얼마 안 남았네요.\n나: 네, 그래서 다음 주에 다시 ____________을/를 받으러 가려고 해요.", a: ["발급", "취업", "배치", "출국"], c: "발급", ex: "Jika masa berlaku paspor hampir habis, tindakan yang harus dilakukan adalah pergi untuk mendapatkan 'penerbitan ulang' atau memperpanjangnya. Kata yang tepat adalah 발급 (penerbitan)." },
{ id: 'n_r684', ch: 53, q: "빈칸에 들어갈 가장 al맞은 것을 고르십시오.\n\n해외로 여행을 갈 때는 여권을 ____________ 않게 조심해야 합니다.", a: ["분실하지", "교환하지", "사용하지", "연기하지"], c: "분실하지", ex: "Paspor adalah dokumen yang sangat penting, jadi kita harus berhati-hati agar tidak menghilangkannya (분실하다). Bentuk negatifnya adalah 분실하지 않게 조심해야 합니다." },
{ id: 'n_r685', ch: 53, q: "가: 리한 씨, 혹시 제 외국인 등록증 못 봤어요?\n나: 계속 찾아보고 없으면 빨리 출입국관리소에서 ____________을/를 받는 게 좋겠어요.", a: ["재발급", "신청서", "수수료", "번호표"], c: "재발급", ex: "Jika kartu identitas hilang (분실) dan tidak dapat ditemukan, pekerja harus segera ke kantor imigrasi untuk mendapatkan 'penerbitan ulang' (재발급)." },
{ id: 'n_r686', ch: 53, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n등록증을 만들 때 본인이 맞는지 정확히 확인하기 위해서 기계에 ____________을/를 등록합니다.", a: ["지문", "도장", "사인", "서명"], c: "지문", ex: "Untuk memverifikasi identitas asli (본인이 맞는지 확인하기 위해서) secara biometrik saat membuat kartu identitas, pendaftar harus mendaftarkan sidik jari (지문)." },
{ id: 'n_r687', ch: 53, q: "가: 외국인 등록을 하려면 뭐가 필요해요?\n나: 여권과 사진 2장, 그리고 일하는 곳의 ____________이/가 필요해요.", a: ["사업자 등록증 사본", "성적표", "근로계약서", "월급명세서"], c: "사업자 등록증 사본", ex: "Berdasarkan materi Bab 53, syarat mendaftar kartu identitas orang asing bagi pekerja E-9 adalah paspor, pas foto 2 lembar, dan fotokopi surat izin usaha perusahaan (사업자 등록증 사본)." },
{ id: 'n_r688', ch: 53, q: "가: 외국인 등록은 한국에 온 후에 언제까지 해야 해요?\n나: 한국에 들어오신 후 ____________ 이내에 하시면 됩니다.", a: ["90일", "30일", "1년", "3년"], c: "90일", ex: "Pendaftaran status warga asing (외국인 등록) secara hukum wajib dilakukan dalam kurun waktu maksimal 90 hari (90일 이내) setelah tanggal kedatangan ke Korea." },
{ id: 'n_r689', ch: 53, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n공공기관에서는 먼저 온 순서대로 업무를 볼 수 있도록 기계에서 ____________ 합니다.", a: ["지문을 등록해야", "번호표를 뽑아야", "신청서를 제출해야", "등록증을 발급 받아야"], c: "번호표를 뽑아야", ex: "Agar proses pelayanan di instansi berjalan adil dan sesuai urutan kedatangan (먼저 온 순서대로), setiap orang harus mengambil nomor antrean (번호표를 뽑아야 합니다)." },// ======================== NORMAL ========================
{ id: 'n_r690', ch: 54, q: "가: 지난번에 많이 아파서 일도 못 했다면서요?\n나: 네, 혹시 보험 회사에서 ____________ 있을까요?", a: ["보상을 받을 수", "보험료를 낼 수", "만기가 될 수", "가입할 수"], c: "보상을 받을 수", ex: "Karena ia sakit dan tidak bisa bekerja, ia bertanya apakah ia 'bisa mendapat kompensasi' (보상을 받을 수) dari perusahaan asuransi." },
{ id: 'n_r691', ch: 54, q: "가: 이 보험료는 좀 비싼 것 같아요.\n나: 네, 이 보험은 만기가 되면 그동안 낸 돈을 ____________ 보험이라서 그래요.", a: ["소멸되는", "환급 받는", "납입하는", "청구하는"], c: "환급 받는", ex: "Premi asuransinya mahal karena jika sudah jatuh tempo (만기가 되면), uang yang disetor akan 'dikembalikan/dicairkan' (환급 받는)." },
{ id: 'n_r692', ch: 54, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n보험금을 ____________ 먼저 보험 회사에 보험금을 청구해야 합니다.", a: ["내려면", "지급하려면", "타려면", "신청하려면"], c: "타려면", ex: "Untuk 'menerima/mendapatkan' uang asuransi (보험금을 타다), kita harus terlebih dahulu mengajukan klaim (청구하다). Tata bahasa '-(으)려면' berarti 'jika ingin'." },
{ id: 'n_r693', ch: 54, q: "가: 다쳐서 일도 못하고 생활이 어려워서 어떡해요.\n나: 그래도 보험금으로 평균 임금의 70%에 해당하는 ____________을/를 받을 수 있으니까 다행이에요.", a: ["병원비", "치료비", "휴업 급여", "장해 보상금"], c: "휴업 급여", ex: "Uang yang setara dengan 70% rata-rata gaji untuk menggantikan upah yang hilang karena tidak bisa bekerja disebut 휴업 급여 (upah saat cuti)." },
{ id: 'n_r694', ch: 54, q: "빈칸에 들어gal al맞은 말을 고르십시오.\n\n외국인 근로자가 귀국할 때 필요한 비행기 표 값을 준비하기 위해 가입하는 것은 ____________입니다.", a: ["귀국 비용 보험", "출국 만기 보험", "상해 보험", "산재 보험"], c: "귀국 비용 보험", ex: "Asuransi wajib bagi pekerja asing untuk membiayai tiket pesawat pulang (항공비 충당) disebut asuransi biaya kepulangan (귀국 비용 보험)." },
{ id: 'n_r695', ch: 54, q: "가: 바루 씨, 손이 왜 그래요?\n나: 연마 작업을 하다가 기계 안으로 손이 ____________.", a: ["빨려 들어갔어요", "만기가 되었어요", "잘렸어요", "환급 받았어요"], c: "빨려 들어갔어요", ex: "Berdasarkan dialog di buku, kecelakaan saat menggerinda sering kali berupa tangan 'tersedot masuk' ke dalam mesin (빨려 들어가다)." },
{ id: 'n_r696', ch: 54, q: "가: 보험금을 청구하려고요. 어떤 서류가 필요해요?\n나: 산재를 신청하려면 재해 발생 당시의 의사 소견이 적힌 ____________이/가 중요합니다.", a: ["진단서", "내역서", "영수증", "청구서"], c: "진단서", ex: "Untuk mengklaim asuransi kecelakaan kerja, dokumen paling penting dari rumah sakit adalah surat rekam medis/diagnosis (진단서)." },
{ id: 'n_r697', ch: 54, q: "가: 상해 보험에도 꼭 가입해야 해요?\n나: 그럼요. 고용허가제를 통해 온 외국인 근로자는 ____________ 가입해야 해요.", a: ["반드시", "가끔", "미리", "아직"], c: "반드시", ex: "Pekerja EPS diwajibkan oleh undang-undang untuk mendaftar asuransi kecelakaan dan asuransi kepulangan, sehingga menggunakan kata '반드시' (pasti/wajib)." },
{ id: 'n_r698', ch: 54, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n사업주가 외국인 근로자에게 퇴직금을 쉽게 줄 수 있도록 매월 적립하여 가입하는 것은 ____________입니다.", a: ["출국 만기 보험", "귀국 비용 보험", "상해 보험", "임금 체불 보증 보험"], c: "출국 만기 보험", ex: "Asuransi yang dibayar oleh pengusaha (사업주) untuk mengurangi beban pembayaran uang pesangon (퇴직금) disebut asuransi jaminan keberangkatan (출국 만기 보험)." },
{ id: 'n_r699', ch: 54, q: "가: 병원비는 어떻게 해요?\n나: 건강 보험이 ____________ 병원비 걱정은 하지 마세요.", a: ["있기 전에", "있을 텐데", "있으니까", "있지만"], c: "있으니까", ex: "Alasan mengapa ia tidak perlu khawatir soal biaya rumah sakit adalah 'karena ada' asuransi kesehatan (건강 보험이 있으니까)." },// ======================== NORMAL ========================
{ id: 'n_r700', ch: 55, q: "가: 월급을 미리 받을 수 있어요?\n나: 급하시면 반장님께 ____________ 보세요.", a: ["가불을 신청해", "공제를 신청해", "상여금을 신청해", "야근을 신청해"], c: "가불을 신청해", ex: "Jika butuh uang sebelum hari gajian (미리 받을 수 있어요?), maka yang harus diajukan adalah 'kas bon' atau 가불을 신청하다." },
{ id: 'n_r701', ch: 55, q: "가: 오늘 일이 아주 많네요.\n나: 곧 명절이____________ 일이 몰리네요.", a: ["라서 그런지", "기 때문에", "니까", "라서요"], c: "라서 그런지", ex: "Tata bahasa '-(이)라서 그런지 / -아/어서 그런지' digunakan untuk menyatakan dugaan alasan yang kurang pasti. 'Entah karena sebentar lagi hari raya, pekerjaannya menumpuk' menjadi 명절이라서 그런지 일이 몰리네요." },
{ id: 'n_r702', ch: 55, q: "가: 급여 명세서에서 제가 실제로 받는 돈을 확인하려면 뭘 봐야 해요?\n나: ____________(이)라고 쓰여 있는 부분을 보세요.", a: ["실수령액", "공제 총액", "세금 총액", "기본급"], c: "실수령액", ex: "Jumlah uang yang 'sebenarnya diterima' (실제로 받는 돈) tertera di bagian 실수령액 (Gaji Bersih / Take-home pay)." },
{ id: 'n_r703', ch: 55, q: "가: 수당이나 보너스는 어떻게 계산해요?\n나: 보통은 ____________을/를 기준으로 100%, 200% 이렇게 계산해요.", a: ["기본급", "퇴직금", "실수령액", "공제액"], c: "기본급", ex: "Bonus dan tunjangan pada umumnya dihitung berdasarkan persentase dari gaji pokok (기본급을 기준으로 계산해요)." },
{ id: 'n_r704', ch: 55, q: "가: 밤 10시부터 새벽 6시 사이에 일하면 무슨 수당을 받아요?\n나: ____________을/를 받아요.", a: ["야간 근로 수당", "연장 근로 수당", "휴일 근로 수당", "명절 수당"], c: "야간 근로 수당", ex: "Bekerja di malam hari antara pukul 10 malam dan 6 pagi dikategorikan sebagai lembur kerja malam hari (야근 근로/야간 근로 수당)." },
{ id: 'n_r705', ch: 55, q: "가: 법으로 정해진 8시간보다 초과해서 더 많이 일하면 무슨 수당을 받아요?\n나: ____________을/를 받아요.", a: ["연장 근로 수당", "야간 근로 수당", "휴일 근로 수당", "퇴직 수당"], c: "연장 근로 수당", ex: "Jika bekerja lebih dari 8 jam sehari (1일 8시간 초과), maka tambahan waktu tersebut dibayar sebagai lembur atau 연장 근로 수당." },
{ id: 'n_r706', ch: 55, q: "가: 휴일에 나와서 일하면 무슨 수당을 받아요?\n나: ____________을/를 받아요.", a: ["휴일 근로 수당", "야간 근로 수당", "연장 근로 수당", "출국 만기 수당"], c: "휴일 근로 수당", ex: "Bekerja pada hari libur (휴일에 일할 경우) dibayar sebagai lembur hari libur atau 휴일 근로 수당." },
{ id: 'n_r707', ch: 55, q: "가: 계약서에서 본 금액보다 월급이 적은 것 같아요.\n나: 그건 총액에서 세금하고 보험료를 ____________ 만큼 받기 때문이에요.", a: ["뺀", "더한", "곱한", "포함한"], c: "뺀", ex: "Gaji yang diterima lebih sedikit dari kontrak karena dipotong/dikurangi asuransi dan pajak. Kata 'dikurangi' adalah 뺀 (dari kata 빼다)." },
{ id: 'n_r708', ch: 55, q: "가: 급여 명세서에 있는 주민세하고 소득세는 뭐예요?\n나: 그건 월급에 대한 기본적인 ____________이에요.", a: ["세금", "보험료", "보너스", "식대"], c: "세금", ex: "Pajak penduduk (주민세) dan pajak pendapatan (소득세) adalah jenis-jenis pajak (세금) dasar yang dipotong dari gaji bulanan." },
{ id: 'n_r709', ch: 55, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n가: 수당은 언제 받을 수 있어요?\n나: 보통 수당은 월급에 ____________ 나오니까 월급하고 같이 지급돼요.", a: ["포함돼", "가불돼", "공제돼", "계산해"], c: "포함돼", ex: "Tunjangan/bonus (수당) biasanya 'termasuk' atau digabungkan ke dalam gaji bulanan, jadi dibayarkan bersamaan. Kata yang tepat adalah 포함되다 (포함돼)." },// ======================== NORMAL ========================
{ id: 'n_r710', ch: 56, q: "가: 내일은 달력에 빨간 날도 아닌데 쉬네요.\n나: 네, ____________ 휴일이라서 우리 회사는 쉬어요.", a: ["약정", "법정", "무급", "출산"], c: "약정", ex: "Libur yang bukan tanggal merah resmi (bukan UU) tetapi ditentukan sendiri oleh kesepakatan perusahaan disebut libur kontrak atau 약정 휴일." },
{ id: 'n_r711', ch: 56, q: "가: 연차를 사용하는 기간 동안은 임금이 나오지 않는 거예요?\n나: 아니요, ____________ 휴가니까 임금이 지불돼요.", a: ["유급", "무급", "병가", "생리"], c: "유급", ex: "Cuti tahunan (연차) dihitung sebagai cuti berbayar, jadi tetap dibayar gajinya. Kata yang tepat adalah 유급 휴가 (cuti berbayar)." },
{ id: 'n_r712', ch: 56, q: "가: 우리 회사는 출산 휴가를 얼마나 줘요?\n나: 아기를 낳기 전후로 ____________을/를 준대요.", a: ["3개월", "1개월", "15일", "1년"], c: "3개월", ex: "Di Korea, secara standar Undang-Undang Ketenagakerjaan (근로기준법), cuti melahirkan (출산 휴가) diberikan selama 3 bulan." },
{ id: 'n_r713', ch: 56, q: "가: 이반 씨, 이번 여름 휴가 계획은 세웠어?\n나: 아직 아무도 휴가 얘기를 안 해서 휴가를 써도 될지 ____________.", a: ["눈치를 보는 중이야", "연차를 낸 중이야", "진단서를 떼는 중이야", "조퇴를 하는 중이야"], c: "눈치를 보는 중이야", ex: "Ungkapan '눈치를 보다' berarti melihat situasi/membaca keadaan orang lain karena segan/takut untuk bertindak pertama kali." },
{ id: 'n_r714', ch: 56, q: "가: 안색이 안 좋아요. 일찍 들어가서 쉬는 게 어때요?\n나: 네, ____________ 먼저 들어가 보겠습니다.", a: ["조퇴하고", "결근하고", "휴직하고", "입원하고"], c: "조퇴하고", ex: "Karena ia disarankan untuk pulang lebih awal untuk istirahat (일찍 들어가서 쉬다), maka tindakan yang ia lakukan adalah 조퇴하다 (pulang cepat)." },
{ id: 'n_r715', ch: 56, q: "가: 저 직원은 오늘 안 나왔어요?\n나: 네, 회사에 연락도 없이 ____________을/를 한 것 같아요.", a: ["무단결근", "연차 휴가", "병가 신청", "통원 치료"], c: "무단결근", ex: "Tidak datang bekerja 'tanpa menghubungi perusahaan' (회사에 연락도 없이) disebut absen tanpa izin atau 무단결근." },
{ id: 'n_r716', ch: 56, q: "가: 허리가 좀 아파서 병원에 갔는데 수술을 받는 게 좋겠다고 하네요.\n나: 그래요? 그럼 한 일주일 정도 ____________을/를 쓰면 될 것 같아요.", a: ["병가", "출산 휴가", "약정 휴가", "조퇴"], c: "병가", ex: "Cuti yang digunakan untuk melakukan operasi (수술을 받다) dan pemulihan medis adalah cuti sakit (병가)." },
{ id: 'n_r717', ch: 56, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n연차 휴가는 유급 휴가이기 때문에 쉬지 않고 일한 사람한테는 ____________을/를 줍니다.", a: ["수당", "벌금", "세금", "수수료"], c: "수당", ex: "Karena cuti tahunan dibayar (유급), jika seseorang tidak mengambil jatah cutinya dan tetap bekerja, ia akan mendapat kompensasi berupa tunjangan cuti atau 수당 (tunjangan/uang tambahan)." },
{ id: 'n_r718', ch: 56, q: "가: 1주일 이상 병가를 신청하고 싶은데요. 내야 할 서류가 있어요?\n나: 병가 신청서를 쓰시고 아파서 쉰다는 것을 증명할 ____________도/도 같이 제출해 주세요.", a: ["진단서", "여권", "사업자 등록증", "신분증"], c: "진단서", ex: "Dokumen dari rumah sakit yang membuktikan bahwa pekerja tersebut benar-benar sakit dan butuh istirahat adalah surat keterangan dokter atau 진단서." },
{ id: 'n_r719', ch: 56, q: "가: 보통 휴가는 1년에 얼마나 쓸 수 있어?\n나: 1년에 ____________ 15일까지 쓸 수 있어. 여름 휴가로는 보통 3~4일 정도 써.", a: ["연차", "월차", "반차", "조퇴"], c: "연차", ex: "Jatah libur 15 hari dalam setahun (1년에 15일) disebut cuti tahunan atau 연차 휴가." },// ======================== NORMAL ========================
{ id: 'n_r720', ch: 57, q: "가: 근로계약이 만료되면 어떻게 할 거예요?\n나: 계약을 ____________. 지금 다니는 회사가 좋은 것 같아서요.", a: ["갱신하려고요", "해지하려고요", "체불하려고요", "면제하려고요"], c: "갱신하려고요", ex: "Karena ia merasa perusahaannya yang sekarang bagus, ia berencana untuk 'memperpanjang' kontrak kerja (계약을 갱신하다)." },
{ id: 'n_r721', ch: 57, q: "가: 이렇게 빨리 고향에 돌아가는 거예요?\n나: 네. 어머니가 편찮으셔서 ____________하게 됐어요.", a: ["조기 귀국", "재입국", "계약 갱신", "사업장 변경"], c: "조기 귀국", ex: "Ibu yang sakit parah menyebabkan ia harus 'pulang lebih awal dari masa kontrak' dan tidak kembali lagi. Istilahnya adalah 조기 귀국." },
{ id: 'n_r722', ch: 57, q: "가: 신청서를 제출하고 일시 출국했다가 입국하면 다시 허가를 받아야 해요?\n나: 아니요. 이 경우에는 재입국 허가가 ____________.", a: ["면제돼요", "가능해요", "신고해요", "제출돼요"], c: "면제돼요", ex: "Jika sudah melapor dan menyerahkan formulir sebelum pulang, izin masuk kembalinya (재입국 허가) akan 'dibebaskan/dikecualikan' (면제돼요)." },
{ id: 'n_r723', ch: 57, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n사업주와 근로계약 종료 후 한 달 안에 ____________을/를 신청해야 합니다.", a: ["사업장 변경", "계약 갱신", "계약 만료", "근로계약"], c: "사업장 변경", ex: "Setelah kontrak berakhir, jika ingin pindah, pendaftaran 'pindah tempat kerja' (사업장 변경) harus diajukan dalam waktu satu bulan." },
{ id: 'n_r724', ch: 57, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n개인 사정으로 일시 출국을 할 때 재입국 허가 신청서에 사업자의 ____________을/를 첨부하여 제출해야 합니다.", a: ["동의서", "여권", "신분증", "명함"], c: "동의서", ex: "Saat akan pulang sementara, pekerja harus melampirkan 'surat persetujuan' (동의서) dari pengusaha (majikan)." },
{ id: 'n_r725', ch: 57, q: "가: 더 이상 공장은 운영 안 하는 거예요?\n나: 아니요. 사정이 있어서 지금은 잠시 ____________ 중이에요.", a: ["휴업", "폐업", "변경", "체불"], c: "휴업", ex: "Karena pabrik hanya tidak beroperasi 'untuk sementara waktu' (잠시), istilah yang tepat adalah 휴업 (berhenti produksi sementara)." },
{ id: 'n_r726', ch: 57, q: "가: 근무지를 바꾸고 싶은 이유가 있어요?\n나: 몇 달째 임금을 못 받았어요. ____________도 변경 사유가 되지요?", a: ["임금 체불", "해고", "폐업", "휴업"], c: "임금 체불", ex: "Alasan pindah kerja karena 'tidak menerima gaji selama berbulan-bulan' disebut 임금 체불 (menunggak gaji)." },
{ id: 'n_r727', ch: 57, q: "가: 회사 옮길 거라며? 무슨 일 있어?\n나: 우리 회사가 사정이 안 좋아서 곧 ____________ 것 같아.", a: ["문을 닫을", "입국할", "귀국할", "체불할"], c: "문을 닫을", ex: "Karena kondisi perusahaannya buruk, perusahaannya sepertinya akan segera 'tutup/bangkrut' (문을 닫다 / 폐업하다)." },
{ id: 'n_r728', ch: 57, q: "가: 아버지가 큰 수술을 받으셨어. 고향에 다녀와야 할 것 같은데.\n나: 고향에 ____________ 지금 일은 어떻게 하고?", a: ["가게 되면", "가기 전에", "가는 동안", "갔기 때문에"], c: "가게 되면", ex: "Ivan bertanya tentang rencana Adit, 'Jika kamu jadi pulang ke kampung, pekerjaan yang sekarang bagaimana?' Tata bahasa yang tepat adalah 가다 + -게 되다 + -(으)면 = 가게 되면." },
{ id: 'n_r729', ch: 57, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n사업장 변경 ____________에는 근로계약의 만료나 해지, 일하던 사업장의 휴업이나 폐업 등이 있습니다.", a: ["사유", "기간", "신고", "신청"], c: "사유", ex: "Hal-hal yang disebutkan (kontrak habis, pabrik tutup, dsb) adalah 'alasan' (사유) yang memperbolehkan pindah tempat kerja." },// ======================== NORMAL ========================
{ id: 'n_r730', ch: 58, q: "가: 체류 가능 기간은 어디에 나와 있어요?\n나: 외국인 등록증 ____________에 날짜가 적혀 있어요.", a: ["뒷면", "앞면", "옆면", "위쪽"], c: "뒷면", ex: "Tanggal masa berlaku izin tinggal (체류 가능 기간) tertulis di bagian belakang (뒷면) dari Kartu Identitas Orang Asing (외국인 등록증)." },
{ id: 'n_r731', ch: 58, q: "가: 재계약을 하면 체류 기간은 ____________ 연장되는 거예요?\n나: 아니요, 따로 연장 허가를 받아야 해요.", a: ["자동으로", "스스로", "무조건", "절대"], c: "자동으로", ex: "Rihan bertanya apakah perpanjangan kontrak otomatis (자동으로) memperpanjang masa tinggal. Jawabannya tidak, harus diurus terpisah (따로)." },
{ id: 'n_r732', ch: 58, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n외국인 근로자는 체류 자격 외 ____________을/를 하기 전에 반드시 신고를 해야 합니다.", a: ["고용", "신청", "연장", "활동"], c: "활동", ex: "Melakukan pekerjaan di luar kontrak kerja yang diizinkan disebut aktivitas di luar kualifikasi izin tinggal (체류 자격 외 활동). Ini harus dilaporkan terlebih dahulu." },
{ id: 'n_r733', ch: 58, q: "가: 체류 기간 연장 허가는 언제까지 받아야 해요?\n나: 체류 기간 ____________ 전까지만 받으면 돼요.", a: ["만료", "부여", "연장", "변경"], c: "만료", ex: "Izin perpanjangan harus diajukan dan diterima sebelum masa tinggal saat ini berakhir (만료 전까지)." },
{ id: 'n_r734', ch: 58, q: "가: 신청 ____________이/가 지나서 연장 신고를 하면 어떻게 돼요?\n나: 불법 체류가 되고 벌금을 내야 해요.", a: ["기간", "서류", "대상", "자격"], c: "기간", ex: "Jika melapor setelah 'masa/batas waktu' (기간) pendaftarannya lewat, akan dikenakan denda." },
{ id: 'n_r735', ch: 58, q: "가: 스스로 신고한 거예요?\n나: 네, ____________ 출국을 하면 나중에 재입국할 때 도움이 된다고 해서요.", a: ["강제", "자진", "불법", "합법"], c: "자진", ex: "Pulang atas kemauan sendiri disebut 자진 출국 (pulang sukarela), yang mana akan membantu mempermudah proses masuk kembali (재입국) ke Korea nantinya." },
{ id: 'n_r736', ch: 58, q: "가: 체류지 입증 서류에는 어떤 것들이 있어요?\n나: 거주하고 있음을 증빙하는 ____________ 등이 필요해요.", a: ["임대차 계약서", "자진 출국 각서", "신원 보증서", "여권"], c: "임대차 계약서", ex: "Dokumen yang membuktikan (입증) tempat tinggal (체류지) atau domisili (거주) adalah surat kontrak sewa rumah/kamar (임대차 계약서)." },
{ id: 'n_r737', ch: 58, q: "가: 흐엉 씨는 어떻게 하다가 불법 체류자가 되었어요?\n나: 계약 갱신은 했는데, 체류 연장 신청을 ____________ 안 해서 그렇게 됐대요.", a: ["자동으로", "따로", "같이", "미리"], c: "따로", ex: "Heong memperpanjang kontrak kerja, tetapi tidak mengurus perpanjangan izin tinggal 'secara terpisah' (따로 안 해서) ke imigrasi." },
{ id: 'n_r738', ch: 58, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n체류 기간 연장 허가를 안 받고 일을 계속하면 ____________이/가 돼서 강제 출국을 당하게 됩니다.", a: ["합법 체류", "불법 체류", "사업장 변경", "자진 출국"], c: "불법 체류", ex: "Bekerja tanpa izin perpanjangan tinggal akan membuat status pekerja menjadi imigran ilegal (불법 체류), yang berakibat deportasi paksa (강제 출국)." },
{ id: 'n_r739', ch: 58, q: "가: 체류 기간 연장 신청을 할 때 무엇을 내야 합니까?\n나: 신청서, 여권, 외국인 등록증, 그리고 6만 원의 ____________을/를 내야 합니다.", a: ["수수료", "벌금", "세금", "수당"], c: "수수료", ex: "Biaya yang harus dibayarkan saat mengurus dokumen resmi di kantor pemerintahan disebut biaya administrasi atau 수수료." },// ======================== NORMAL ========================
{ id: 'n_r740', ch: 59, q: "다음 표지의 뜻으로 al맞은 것을 고르십시오.\n\n[화기금지]", a: ["불을 사용하면 안 됩니다.", "담배를 피우면 안 됩니다.", "걸어 다니면 안 됩니다.", "안으로 들어가면 안 됩니다."], c: "불을 사용하면 안 됩니다.", ex: "화기금지 (No open fire) berarti dilarang menyalakan api atau menggunakan barang yang menghasilkan api." },
{ id: 'n_r741', ch: 59, q: "불이 쉽게 붙을 수 있는 위험한 물질이 있을 때 붙이는 경고 표지는 무엇입니까?", a: ["인화성 물질 경고", "방사선 물질 경고", "산화성 물질 경고", "급성독 물질 경고"], c: "인화성 물질 경고", ex: "인화성 물질 경고 (Warning: flammable material) adalah peringatan untuk bahan yang mudah terbakar." },
{ id: 'n_r742', ch: 59, q: "작업자가 이동하다가 지게차나 다른 차량과 충돌하는 사고는 어떤 재해에 해당합니까?", a: ["부딪힘 재해", "넘어짐 재해", "끼임 재해", "맞음 재해"], c: "부딪힘 재해", ex: "차량 등과의 부딪힘 (Tertabrak kendaraan) termasuk dalam kategori 부딪힘 재해 (Kecelakaan tabrakan/benturan)." },
{ id: 'n_r743', ch: 59, q: "크레인으로 무거운 물건을 옮기던 중 물건이 떨어져 작업자가 다쳤습니다. 이는 어떤 재해입니까?", a: ["맞음 재해", "끼임 재해", "넘어짐 재해", "부딪힘 재해"], c: "맞음 재해", ex: "중량물 운반 시 맞음 (Kejatuhan/terpukul benda berat yang sedang dipindahkan) termasuk dalam 맞음 재해." },
{ id: 'n_r744', ch: 59, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n바닥에 기름이 있어서 미끄러지거나 돌출물에 걸려 쓰러지는 것을 ____________(이)라고 합니다.", a: ["넘어짐", "끼임", "부딪힘", "맞음"], c: "넘어짐", ex: "Terpeleset di permukaan licin atau tersandung (바닥에서 미끄러짐, 돌출물에 걸려 쓰러짐) disebut 넘어짐 (terjatuh/terpeleset)." },
{ id: 'n_r745', ch: 59, q: "공중에 매달려 있는 물건이 있어서 위험할 때 사용하는 표지는 무엇입니까?", a: ["매달린 물체 경고", "낙하물 경고", "위험 장소 경고", "몸균형 상실 경고"], c: "매달린 물체 경고", ex: "매달린 물체 경고 (Warning: hanging objects) adalah peringatan bahaya benda yang menggantung." },
{ id: 'n_r746', ch: 59, q: "지붕을 수리하다가 아래로 떨어지는 사고는 어디에 해당합니까?", a: ["떨어짐 (기타 재해)", "끼임 재해", "부딪힘 재해", "맞음 재해"], c: "떨어짐 (기타 재해)", ex: "지붕수리 중 떨어짐 (Terjatuh dari ketinggian saat membetulkan atap) merupakan salah satu contoh 기타 재해 (kecelakaan lain-lain)." },
{ id: 'n_r747', ch: 59, q: "먹거나 마시면 생명에 치명적인 위험을 줄 수 있는 독이 있는 물질을 경고하는 표지는 무엇입니까?", a: ["급성독 물질 경고", "방사선 물질 경고", "산화성 물질 경고", "폭발성 물질 경고"], c: "급성독 물질 경고", ex: "급성독 물질 경고 (Warning: acute toxic) adalah peringatan untuk bahan beracun yang sangat mematikan." },
{ id: 'n_r748', ch: 59, q: "다음 중 교류아크용접 작업을 할 때 발생할 수 있는 위험한 사고는 무엇입니까?", a: ["감전", "넘어짐", "끼임", "추락"], c: "감전", ex: "교류아크용접 작업 중 감전 (Tersengat listrik saat pengoperasian las AC arc) adalah salah satu bahaya keselamatan (기타 재해)." },
{ id: 'n_r749', ch: 59, q: "빈칸에 들어갈 al맞은 말을 고르십시오.\n\n미끄러운 곳이나 경사진 곳에서 몸의 균형을 잃고 넘어질 위험이 있을 때 ____________ 표지를 붙입니다.", a: ["몸균형 상실 경고", "고온 경고", "저온 경고", "위험 장소 경고"], c: "몸균형 상실 경고", ex: "몸균형 상실 경고 (Warning: loss of body balance) digunakan untuk mengingatkan pekerja agar berhati-hati kehilangan keseimbangan." },// ======================== NORMAL ========================
{ id: 'n_r650', ch: 60, q: "가: 콘크리트 펌프카가 쓰러질까 봐 위험해 보여요.\n나: 넘어지지 않게 반드시 ____________을/를 설치해야 해요.", a: ["아웃리거", "구명줄", "달기로프", "수직 보호망"], c: "아웃리거", ex: "Untuk mencegah truk pompa beton terjungkir/rubuh (넘어짐 위험), wajib menggunakan penyangga samping atau katir yang disebut 아웃리거 (outrigger)." },
{ id: 'n_r651', ch: 60, q: "가: 철근 조립 작업을 할 때 조심해야 할 점이 뭐예요?\n나: 뾰족한 철근에 ____________ 위험이 있으니까 주변을 잘 정리하세요.", a: ["찔릴", "감길", "데일", "베일"], c: "찔릴", ex: "Bahaya utama saat bekerja dengan baja tulangan/rebar yang menonjol adalah risiko tertusuk (철근에 찔릴 위험)." },
{ id: 'n_r652', ch: 60, q: "벽돌이나 블록을 쌓는 조적 작업을 할 때는 벽체가 무너지지 않도록 ____________(1.2~1.5m/일)을/를 반드시 지켜야 합니다.", a: ["일일 작업량", "안전율", "수습 기간", "작업 발판"], c: "일일 작업량", ex: "Untuk mencegah rubuhnya tembok yang sedang dibangun (조적 벽체 무너짐 방지), volume pengerjaan per hari (일일 작업량) dibatasi 1.2 hingga 1.5 meter." },
{ id: 'n_r653', ch: 60, q: "가: 외부에서 도장 작업을 하려고 합니다.\n나: 떨어지면 위험하니까 안전대를 ____________에 확실히 걸고 작업하세요.", a: ["구명줄", "철근", "아웃리거", "전선"], c: "구명줄", ex: "Pekerja cat (도장 작업) harus mengaitkan sabuk pengamannya pada tali penyelamat vertikal (구명줄) untuk mencegah jatuh." },
{ id: 'n_r654', ch: 60, q: "가: 위층에서 거푸집을 조립하고 있는데 아래층에서 다른 작업을 해도 돼요?\n나: 아니요, 물건이 떨어질 수 있어서 ____________(은)는 아주 위험합니다.", a: ["상하부 동시 작업", "철근 가공 작업", "콘크리트 타설", "안전대 부착"], c: "상하부 동시 작업", ex: "Bekerja di bagian atas dan bawah secara bersamaan (상하부 동시에 작업 진행) sangat dilarang karena berisiko kejatuhan benda dari atas." },
{ id: 'n_r655', ch: 60, q: "무거운 철골을 양중기(크레인)로 들어 올릴 때는 철골을 묶은 ____________의 상태가 양호한지 확인해야 합니다.", a: ["와이어로프", "구명줄", "달기로프", "전선"], c: "와이어로프", ex: "Saat mengangkat kerangka baja (철골 부재 인양), kondisi tali kawat baja atau 와이어로프 harus dipastikan dalam keadaan baik (양호한가)." },
{ id: 'n_r656', ch: 60, q: "화학 물질을 취급하는 곳에서는 공기 중에 있는 유해 가스 양을 최소화하기 위해 ____________을/를 가동한 상태에서 일해야 합니다.", a: ["환기 장치", "양중기", "절단기", "펌프카"], c: "환기 장치", ex: "Pekerjaan harus dilakukan dengan alat ventilasi (환기 장치) yang menyala untuk mengeluarkan udara berbahaya." },
{ id: 'n_r657', ch: 60, q: "가: 철근을 원하는 길이로 자르거나 구부릴 때는 어떤 기계를 써요?\n나: 철근 ____________기(이)나 절곡기를 사용해서 가공해요.", a: ["절단", "포장", "연마", "용접"], c: "절단", ex: "Mesin untuk memotong baja tulangan disebut pemotong baja tulangan (철근 절단기) dan untuk melengkungkan disebut mesin pelengkung baja (절곡기)." },
{ id: 'n_r658', ch: 60, q: "가: 갱폼에서 작업할 때 옆으로 떨어지지 않게 뭘 설치해야 합니까?\n나: 갱폼 외부에 ____________을/를 설치해야 합니다.", a: ["수직 보호망", "안전대", "환기 장치", "아웃리거"], c: "수직 보호망", ex: "Tindakan pengamanan pada Gang Form meliputi pemasangan rel pengaman dan jaring pelindung vertikal (수직 보호망) untuk mencegah benda atau orang jatuh." },
{ id: 'n_r659', ch: 60, q: "가: 일하다가 화학 물질 때문에 피부에 병이 생긴 것 같아요.\n나: 그럼 빨리 병원에 가거나 외국인 근로자 지원 센터에 가서 ____________을/를 받아 보세요.", a: ["상담", "수수료", "벌금", "명세서"], c: "상담", ex: "Jika muncul gejala penyakit akibat kerja, pekerja disarankan segera ke rumah sakit atau pusat bantuan untuk berkonsultasi (상담)." },


      // SOAL GAMBAR BANK/ATM (NORMAL)
      { id: 'n_img_atm_1', image: 'img/mengirim_uang.png', q: "Orang ini sedang mengirim uang ke keluarganya. Bahasa Koreanya adalah?", a: ["가족에게 돈을 송금해요", "가족에게 돈을 빌려요", "가족에게 돈을 찾아요", "가족에게 돈을 바꿔요"], c: "가족에게 돈을 송금해요", ex: "송금해요 = mengirim uang.", romaji: "gajogege doneul songgeumhaeyo" },
      { id: 'n_img_atm_2', image: 'img/memasukan_uang.png', q: "통장에 돈을 넣고 싶습니다. 무엇을 해야 합니까? (Saya ingin memasukkan uang ke rekening. Apa yang harus dilakukan?)", a: ["입금해야 합니다", "출금해야 합니다", "대출해야 합니다", "환전해야 합니다"], c: "입금해야 합니다", ex: "입금 = setor tunai / memasukkan uang.", romaji: "ipgeumhaeya hamnida" },
      { id: 'n_img_atm_3', image: 'img/mesin_atm.png', q: "은행에 가지 않고 돈을 찾을 수 있는 기계는 무엇입니까? (Mesin yang bisa mengambil uang tanpa pergi ke bank disebut apa?)", a: ["현금인출기", "컴퓨터", "복사기", "선풍기"], c: "현금인출기", ex: "현금인출기 = Mesin tarik tunai (ATM).", romaji: "hyeongeuminchulgi" },
      { id: 'n_img_atm_4', image: 'img/mengambil_uang.png', q: "현금이 필요해서 돈을 찾으려고 합니다. 무슨 버튼을 눌러야 합니까? (Saya butuh uang tunai dan ingin mengambilnya. Tombol apa yang harus ditekan?)", a: ["입금", "출금", "송금", "환전"], c: "출금", ex: "출금 = tarik tunai / mengambil uang.", romaji: "chulgeum" },
      { id: 'n_img_atm_5', image: 'img/transfer_antar_rekening.png', q: "내 통장에서 다른 사람의 통장으로 돈을 보내는 것을 무엇이라고 합니까? (Mengirim uang dari rekening saya ke rekening orang lain disebut apa?)", a: ["계좌 이체", "현금 출금", "통장 정리", "잔액 조회"], c: "계좌 이체", ex: "계좌 이체 = transfer antar rekening.", romaji: "gyejwa iche" },
      { id: 'n_img_atm_6', image: 'img/mengecek_saldo.png', q: "통장에 돈이 얼마나 남았는지 확인하고 싶습니다. (Saya ingin mengecek sisa uang di rekening.)", a: ["잔액 조회를 합니다", "송금을 합니다", "환전을 합니다", "입금을 합니다"], c: "잔액 조회를 합니다", ex: "잔액 조회 = cek saldo.", romaji: "janaek johoereul hamnida" },
      { id: 'n_img_atm_7', image: 'img/mutasi_rekening.png', q: "그동안의 입출금 내역을 통장에 인쇄하고 싶습니다. 무엇을 합니까? (Saya ingin mencetak riwayat transaksi di buku tabungan.)", a: ["통장 정리를 합니다", "잔액 조회를 합니다", "현금을 출금합니다", "돈을 송금합니다"], c: "통장 정리를 합니다", ex: "통장 정리 = mutasi rekening (print riwayat).", romaji: "tongjang jeongrireul hamnida" },
      { id: 'n_img_atm_8', image: 'img/meminjam_uang.png', q: "집이나 차를 사기 위해 은행에서 돈을 빌리는 것을 무엇이라고 합니까? (Meminjam uang dari bank untuk beli rumah/mobil disebut apa?)", a: ["대출하다", "환전하다", "입금하다", "출금하다"], c: "대출하다", ex: "대출하다 = meminjam uang.", romaji: "daechulhada" },
      { id: 'n_img_atm_9', image: 'img/menukar_uang.png', q: "고향에 갈 때 한국 돈을 인도네시아 돈으로 바꾸고 싶습니다. 무엇을 해야 합니까? (Saya ingin menukar uang Korea ke Rupiah saat pulang. Apa yang harus dilakukan?)", a: ["환전해야 합니다", "대출해야 합니다", "통장 정리를 해야 합니다", "계좌 이체를 해야 합니다"], c: "환전해야 합니다", ex: "환전하다 = menukar mata uang.", romaji: "hwanjeonhaeya hamnida" }
